  onLogout: () => void; // Function to handle logout
}

const MobileApp: React.FC<MobileAppProps> = ({ loggedInUser, onLogout }) => {
  const [cameraPermissionGranted, setCameraPermissionGranted] = useState<boolean | null>(null);
  const [locationPermissionGranted, setLocationPermissionGranted] = useState<boolean | null>(null);
  // const [showToast, setShowToast] = useState(false);
  // const [toastMessage, setToastMessage] = useState('');
  // const [toastType, setToastType] = useState<'info' | 'success' | 'error'>('info');

  const navigate = useNavigate();
  const location = useLocation();

  // const showAppToast = useCallback((message: string, type: 'info' | 'success' | 'error' = 'info') => {
  //   setToastMessage(message);
  //   setToastType(type);
  //   setShowToast(true);
  //   // Auto-hide toast after a duration
  //   setTimeout(() => setShowToast(false), 5000);
  // }, []);

  const requestPermissions = useCallback(async () => {
    try {
      // Request Camera Permission
      const cameraStatus = await navigator.permissions.query({ name: 'camera' as PermissionName });
      if (cameraStatus.state === 'granted') {
        setCameraPermissionGranted(true);
      } else {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
        stream.getTracks().forEach(track => track.stop()); // Stop immediate stream after permission
        setCameraPermissionGranted(true);
      }
    } catch (error) {
      console.error('Camera permission denied:', error);
      setCameraPermissionGranted(false);
      // showAppToast('Camera access denied. Please enable it in your browser settings.', 'error');
    }

    try {
      // Request Geolocation Permission
      const geoStatus = await navigator.permissions.query({ name: 'geolocation' as PermissionName });
      if (geoStatus.state === 'granted') {
        setLocationPermissionGranted(true);
      } else {
        const position = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject);
        });
        if (position) {
          setLocationPermissionGranted(true);
        }
