                <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 12H6.75a.75.75 0 0 0-.75.75v6.75a.75.75 0 0 0 .75.75h6.75a.75.75 0 0 0 .75-.75V12.75a.75.75 0 0 0-.75-.75H12" />
                <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 12h-3.75a.75.75 0 0 0-.75.75v6.75a.75.75 0 0 0 .75.75h3.75a.75.75 0 0 0 .75-.75V12.75a.75.75 0 0 0-.75-.75z" />
