export default DashboardApp;

import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import { Case, CaseStatus, AuditLog, User, UserRole } from '../types';
import { VIOLATION_TYPE_COLORS } from '../constants';
import { fetchCaseById, updateCaseStatus, fetchAuditLogsForCase, assignCase, fetchUsersByRole, analyzeContentWithGemini } from '../services/api';
import LoadingSpinner from './LoadingSpinner';
import MapComponent from './MapComponent';
import Button from './Button';
import Modal from './Modal';
import Dropdown from './Dropdown';

interface CaseDetailProps {
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseDetail: React.FC<CaseDetailProps> = ({ onNotify }) => {
  const { id } = useParams<{ id: string }>();
  const [caseDetail, setCaseDetail] = useState<Case | null>(null);
  const [loading, setLoading] = useState(true);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  // const [message, setMessage] = useState<{ text: string; type: 'success' | 'error' | '' }>({ text: '', type: '' });

  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [generatingSummary, setGeneratingSummary] = useState(false);
  const [summaryError, setSummaryError] = useState<string | null>(null);

  const fetchCaseAndLogs = useCallback(async () => {
    setLoading(true);
    // setMessage({ text: '', type: '' });
    if (!id) return;
    try {
      const fetchedCase = await fetchCaseById(id);
      if (fetchedCase) {
        setCaseDetail(fetchedCase);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
      } else {
        // setMessage({ text: 'Case not found.', type: 'error' });
        console.error('Case not found.');
      }
    } catch (error) {
      console.error('Failed to fetch case details:', error);
      // setMessage({ text: 'Failed to load case details. Please try again.', type: 'error' });
    } finally {
      setLoading(false);
    }
  }, [id]);

  const generateCaseSummary = useCallback(async () => {
    if (!caseDetail || auditLogs.length === 0) {
      setAiSummary(null); // Clear summary if data is incomplete
      return;
    }

    setGeneratingSummary(true);
    setSummaryError(null);
    setAiSummary(null);

    const caseInfo = `
      Case ID: ${caseDetail.id}
      Status: ${caseDetail.status.replace(/_/g, ' ')}
      Violation Types: ${caseDetail.violationTypes.map(type => type.replace(/_/g, ' ')).join(', ')}
      Confidence: ${(caseDetail.confidence * 100).toFixed(0)}%
      Plate Text: ${caseDetail.plateText}
      Plate Confidence: ${(caseDetail.plateConfidence * 100).toFixed(0)}%
      Location: ${caseDetail.location.placeName} (Lat: ${caseDetail.location.latitude.toFixed(4)}, Lon: ${caseDetail.location.longitude.toFixed(4)})
      Created At: ${new Date(caseDetail.createdAt).toLocaleString()}
      Recorded By: ${caseDetail.recorderId}
      Device ID: ${caseDetail.deviceId}
    `;

    const logInfo = auditLogs.map(log =>
      ` - Action: ${log.action}, Actor: ${log.actorId}, Notes: ${log.notes || 'N/A'}, Time: ${new Date(log.ts).toLocaleString()}`
    ).join('\n');

    const prompt = `
      Summarize the following traffic violation case details and its audit log concisely. 
      Focus on the key events, current status, and violation specifics.
      Provide a summary in 3-4 sentences.

      Case Details:
      ${caseInfo}

      Audit Log:
      ${logInfo}
    `;

    try {
      const summary = await analyzeContentWithGemini(prompt);
      setAiSummary(summary);
    } catch (error) {
      console.error('Error generating AI summary:', error);
      setSummaryError('Failed to generate AI summary.');
    } finally {
      setGeneratingSummary(false);
    }
  }, [caseDetail, auditLogs]);

  useEffect(() => {
    fetchCaseAndLogs();
  }, [fetchCaseAndLogs]);

  useEffect(() => {
      // Trigger summary generation when case details or audit logs are loaded/updated
      if (caseDetail && auditLogs.length > 0 && !generatingSummary) {
          generateCaseSummary();
      } else if (!caseDetail || auditLogs.length === 0) {
        setAiSummary(null); // Clear summary if data is missing or becomes invalid
        setSummaryError(null);
      }
  }, [caseDetail, auditLogs, generateCaseSummary, generatingSummary]);

  const handleStatusUpdate = async (status: CaseStatus) => {
    if (!id) return;
    setLoading(true);
    // setMessage({ text: '', type: '' });
    try {
      const updatedCase = await updateCaseStatus(id, status);
      if (updatedCase) {
        setCaseDetail(updatedCase);
        const logs = await fetchAuditLogsForCase(id); // Re-fetch logs
        setAuditLogs(logs);
        onNotify?.(`Case status updated to ${status.replace(/_/g, ' ')}.`, 'success');
      }
    } catch (error) {
      console.error('Failed to update case status:', error);
      onNotify?.('Failed to update case status.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const openAssignModal = useCallback(async () => {
    if (!id) return;
    // setMessage({ text: '', type: '' });
    try {
      const reviewers = await fetchUsersByRole(UserRole.REVIEWER);
      setAssignees(reviewers);
      if (reviewers.length > 0) {
        setSelectedAssigneeId(reviewers[0].id);
      }
      setIsAssignModalOpen(true);
    } catch (error) {
      console.error('Failed to fetch assignees:', error);
      onNotify?.('Failed to load assignees.', 'error');
    }
  }, [id, onNotify]);

  const closeAssignModal = () => {
    setIsAssignModalOpen(false);
    setSelectedAssigneeId(assignees.length > 0 ? assignees[0].id : '');
  };

  const handleAssignCase = async () => {
    if (!id || !selectedAssigneeId) return;
    setLoading(true);
    try {
      const result = await assignCase(id, selectedAssigneeId);
      if (result.success) {
        if (result.case) setCaseDetail(result.case);
        const logs = await fetchAuditLogsForCase(id); // Re-fetch logs
        setAuditLogs(logs);
        onNotify?.(result.message, 'success');
      } else {
        onNotify?.(result.message, 'error');
      }
    } catch (error) {
      console.error('Failed to assign case:', error);
      onNotify?.('Failed to assign case.', 'error');
    } finally {
      setLoading(false);
      closeAssignModal();
    }
  };

  const statusColor = (status: CaseStatus): string => {
    switch (status) {
      case CaseStatus.ACCEPTED: return 'bg-green-700 text-white';
      case CaseStatus.REJECTED: return 'bg-red-700 text-white';
      case CaseStatus.PENDING_REVIEW: return 'bg-yellow-700 text-white';
      case CaseStatus.ASSIGNED: return 'bg-blue-700 text-white';
      case CaseStatus.DRAFT: return 'bg-gray-700 text-white';
      default: return 'bg-gray-700 text-white';
    }
  };

  if (loading) {
    return <LoadingSpinner />;
  }

  if (!caseDetail) {
    return (
      <div className="flex-1 p-6 text-center text-red-600">
        <p>Error: {'Case details could not be loaded.'}</p>
      </div>
    );
  }

  return (
    <div className="flex-1 p-6 bg-gray-900 text-white"> {/* Set root background and text color */}
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-white">Case ID: {caseDetail.id}</h2>
        <div className="flex space-x-2">
          {caseDetail.status === CaseStatus.PENDING_REVIEW && (
            <>
              <Button variant="primary" onClick={() => handleStatusUpdate(CaseStatus.ACCEPTED)}>
                Accept
              </Button>
              <Button variant="danger" onClick={() => handleStatusUpdate(CaseStatus.REJECTED)}>
                Reject
              </Button>
            </>
          )}
          {(caseDetail.status === CaseStatus.ACCEPTED || caseDetail.status === CaseStatus.PENDING_REVIEW) && (
            <Button variant="secondary" onClick={openAssignModal}>
              Assign
            </Button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Case Info */}
        <div className="lg:col-span-2 bg-gray-800 rounded-lg shadow-xl p-6">
          <h3 className="text-xl font-semibold text-white mb-4">Case Information</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-gray-300">
            <div>
              <p><strong className="font-medium">Status:</strong> <span className={`px-2 py-1 rounded-full text-sm font-medium ${statusColor(caseDetail.status)}`}>{caseDetail.status.replace(/_/g, ' ')}</span></p>
              <p className="mt-2"><strong className="font-medium">Created At:</strong> {new Date(caseDetail.createdAt).toLocaleString()}</p>
              <p className="mt-2"><strong className="font-medium">Confidence:</strong> {(caseDetail.confidence * 100).toFixed(0)}%</p>
              <p className="mt-2"><strong className="font-medium">Device ID:</strong> {caseDetail.deviceId}</p>
            </div>
            <div>
              <p><strong className="font-medium">Plate Text:</strong> {caseDetail.plateText}</p>
              <p className="mt-2"><strong className="font-medium">Plate Confidence:</strong> {(caseDetail.plateConfidence * 100).toFixed(0)}%</p>
              <p className="mt-2"><strong className="font-medium">Recorder ID:</strong> {caseDetail.recorderId}</p>
              <p className="mt-2"><strong className="font-medium">Duplicate Of:</strong> {caseDetail.duplicateOf || 'N/A'}</p>
            </div>
          </div>
          <div className="mt-4">
            <p><strong className="font-medium">Violation Types:</strong></p>
            <div className="flex flex-wrap gap-2 mt-2">
              {caseDetail.violationTypes.map(type => (
                <span key={type} className={`text-sm font-medium px-3 py-1 rounded-full ${VIOLATION_TYPE_COLORS[type]} text-white`}>
                  {type.replace(/_/g, ' ')}
                </span>
              ))}
            </div>
          </div>
          <div className="mt-4">
            <p><strong className="font-medium">Rules Matched:</strong> {caseDetail.rulesMatched.join(', ') || 'N/A'}</p>
          </div>
        </div>

        {/* Media & Map */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-gray-800 rounded-lg shadow-xl p-6">
            <h3 className="text-xl font-semibold text-white mb-4">Evidence Media</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {caseDetail.mediaUrls.map((url, index) => (
                <img key={index} src={url} alt={`Evidence ${index + 1}`} className="w-full h-40 object-cover rounded-md shadow-sm" />
              ))}
            </div>
          </div>
          <div className="bg-gray-800 rounded-lg shadow-xl p-6">
            <h3 className="text-xl font-semibold text-white mb-4">Location</h3>
            {caseDetail.location ? (
              <MapComponent location={caseDetail.location} placeName={caseDetail.location.placeName} />
            ) : (
              <p className="text-gray-400">Location data not available.</p>
            )}
          </div>
        </div>

        {/* Audit Log */}
        <div className="lg:col-span-3 bg-gray-800 rounded-lg shadow-xl p-6">
          <h3 className="text-xl font-semibold text-white mb-4">Audit Log</h3>
          {auditLogs.length > 0 ? (
            <div className="space-y-4">
              {auditLogs.map(log => (
                <div key={log.id} className="border-l-4 border-indigo-500 pl-4 py-2 bg-gray-700 rounded-md">
                  <p className="text-sm text-white"><strong className="font-medium">{log.action}</strong> by {log.actorId} at {new Date(log.ts).toLocaleString()}</p>
                  {log.notes && <p className="text-xs text-gray-400 italic mt-1">{log.notes}</p>}
                </div>
              ))}
            </div>
          ) : (
            <p className="text-gray-400">No audit logs for this case.</p>
          )}
        </div>

        {/* AI Summary Section */}
        <div className="lg:col-span-3 bg-gray-800 rounded-lg shadow-xl p-6">
            <h3 className="text-xl font-semibold text-white mb-4">AI Summary</h3>
            {generatingSummary ? (
                <LoadingSpinner />
            ) : summaryError ? (
                <p className="text-red-600">{summaryError}</p>
            ) : aiSummary ? (
                <p className="text-gray-300 whitespace-pre-line">{aiSummary}</p>
            ) : (
                <p className="text-gray-400">No AI summary available yet.</p>
            )}
        </div>
      </div>

      <Modal
        isOpen={isAssignModalOpen}
        onClose={closeAssignModal}
        title="Assign Case"
        footer={
          <div className="flex justify-end space-x-2">
            <Button variant="secondary" onClick={closeAssignModal}>Cancel</Button>
            <Button variant="primary" onClick={handleAssignCase} disabled={!selectedAssigneeId}>
              Assign
            </Button>
          </div>
        }
      >
        <p className="mb-4 text-gray-300">Select a reviewer or traffic unit to assign this case to:</p>
        <div>
          <label htmlFor="assignee-select" className="block text-sm font-medium text-gray-300 mb-1">Assign to:</label>
          <Dropdown
            options={assignees.map(u => ({ label: `[${u.unit}] ${u.email}`, value: u.id }))}
            selectedValue={selectedAssigneeId}
            onSelect={setSelectedAssigneeId}
            placeholder="Select Assignee"
            buttonClassName="w-full !bg-gray-700 !border-gray-600 !text-white hover:!bg-gray-600"
            menuClassName="!bg-gray-800"
          />
        </div>
      </Modal>
    </div>
  );
};

export default CaseDetail;

import React, { useState, useEffect, useCallback } from 'react';
import { Case, CaseStatus, FilterOptions, PaginationInfo, User, ViolationType } from '../types';
import { fetchCases, fetchUsersByRole, PaginatedCases, updateCaseStatus, assignCase, acceptAllPendingCases } from '../services/api';
import CaseListItem from './CaseListItem';
import LoadingSpinner from '../components/LoadingSpinner';
import Pagination from './Pagination';
import Dropdown from './Dropdown';
import Button from './Button';
import Modal from './Modal';
import { UserRole } from '../types';
import { MOCK_USERS } from '../constants'; // For mock assignee options

interface CaseListProps {
  currentFilters: FilterOptions;
  triggerFetch: boolean;
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseList: React.FC<CaseListProps> = ({ currentFilters, triggerFetch, onNotify }) => {
  const [cases, setCases] = useState<Case[]>([]);
  const [loading, setLoading] = useState(true);
  const [pagination, setPagination] = useState<PaginationInfo>({ page: 1, pageSize: 10, totalItems: 0, totalPages: 0 });
  const [selectedCaseIds, setSelectedCaseIds] = useState<Set<string>>(new Set());
  const [isBulkActionModalOpen, setIsBulkActionModalOpen] = useState(false);
  const [bulkActionType, setBulkActionType] = useState<'accept' | 'reject' | 'assign' | null>(null);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const [isAcceptAllLoading, setIsAcceptAllLoading] = useState(false);
  const [pendingReviewCasesExist, setPendingReviewCasesExist] = useState(false);

  const fetchCasesData = useCallback(async () => {
    setLoading(true);
    setSelectedCaseIds(new Set()); // Clear selection on new fetch
    try {
      const data: PaginatedCases = await fetchCases(currentFilters, { page: pagination.page, pageSize: pagination.pageSize });
      setCases(data.cases);
      setPagination(data.pagination);
      setPendingReviewCasesExist(data.cases.some(c => c.status === CaseStatus.PENDING_REVIEW));
    } catch (error) {
      console.error('Failed to fetch cases:', error);
    } finally {
      setLoading(false);
    }
  }, [currentFilters, pagination.page, pagination.pageSize]);

  const fetchAssignees = useCallback(async () => {
    try {
      const reviewers = await fetchUsersByRole(UserRole.REVIEWER);
      setAssignees(reviewers);
      if (reviewers.length > 0) {
        setSelectedAssigneeId(reviewers[0].id);
      }
    } catch (error) {
      console.error('Failed to fetch assignees:', error);
    }
  }, []);

  useEffect(() => {
    setPagination(prev => ({ ...prev, page: 1 })); // Reset to first page on new filters
    fetchCasesData();
  }, [triggerFetch]); // Only re-fetch when triggerFetch changes from parent

  useEffect(() => {
    fetchCasesData();
  }, [pagination.page]); // Re-fetch when page changes

  useEffect(() => {
    fetchAssignees();
  }, [fetchAssignees]);

  const handlePageChange = (newPage: number) => {
    setPagination(prev => ({ ...prev, page: newPage }));
  };

  const handleSelectCase = (id: string, isSelected: boolean) => {
    setSelectedCaseIds(prev => {
      const newSet = new Set(prev);
      if (isSelected) {
        newSet.add(id);
      } else {
        newSet.delete(id);
      }
      return newSet;
    });
  };

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      const allIds = new Set(cases.map(c => c.id));
      setSelectedCaseIds(allIds);
    } else {
      setSelectedCaseIds(new Set());
    }
  };

  const openBulkActionModal = (action: 'accept' | 'reject' | 'assign') => {
    if (selectedCaseIds.size === 0) {
      onNotify?.('Please select at least one case for bulk action.', 'info');
      return;
    }
    setBulkActionType(action);
    setIsBulkActionModalOpen(true);
  };

  const closeBulkActionModal = () => {
    setIsBulkActionModalOpen(false);
    setBulkActionType(null);
    setSelectedAssigneeId(assignees.length > 0 ? assignees[0].id : '');
  };

  const performBulkAction = async () => {
    setLoading(true);
    const actions: Promise<any>[] = [];
    const failedCases: string[] = [];

    for (const caseId of selectedCaseIds) {
      try {
        if (bulkActionType === 'accept') {
          actions.push(updateCaseStatus(caseId, CaseStatus.ACCEPTED));
        } else if (bulkActionType === 'reject') {
          actions.push(updateCaseStatus(caseId, CaseStatus.REJECTED));
        } else if (bulkActionType === 'assign' && selectedAssigneeId) {
          actions.push(assignCase(caseId, selectedAssigneeId));
        }
      } catch (error) {
        console.error(`Failed to perform action on case ${caseId}:`, error);
        failedCases.push(caseId);
      }
    }

    const results = await Promise.allSettled(actions); 

    const successfulCount = results.filter(r => r.status === 'fulfilled').length;

    if (failedCases.length > 0 || successfulCount < selectedCaseIds.size) {
      onNotify?.(`Bulk action completed with ${failedCases.length} failures.`, 'error');
    } else {
      onNotify?.(`Bulk action successful for ${selectedCaseIds.size} cases.`, 'success');
    }

    closeBulkActionModal();
    fetchCasesData(); // Re-fetch cases to reflect changes
  };

  const handleAcceptAllPending = async () => {
    setIsAcceptAllLoading(true);
    try {
      const result = await acceptAllPendingCases();
      if (result.success > 0) {
        onNotify?.(`Accepted ${result.success} pending cases.`, 'success');
      }
      if (result.failed > 0) {
        onNotify?.(`Failed to accept ${result.failed} cases.`, 'error');
      }
    } catch (error) {
      console.error('Failed to accept all pending cases:', error);
      onNotify?.('Bulk accept action failed.', 'error');
    } finally {
      setIsAcceptAllLoading(false);
      fetchCasesData(); // Re-fetch cases to reflect changes
      setSelectedCaseIds(new Set()); // Clear selection after bulk action
    }
  };

  const isAllSelected = selectedCaseIds.size === cases.length && cases.length > 0;

  // Add a placeholder value for the dropdown to correctly type selectedValue
  const BULK_ACTION_PLACEHOLDER_VALUE = 'BULK_ACTION_PLACEHOLDER';

  return (
    <div className="flex-1 p-6 bg-gray-900 text-white"> {/* Set background and text color */}
      <h2 className="text-2xl font-bold mb-6 text-white">All Cases</h2> {/* Set heading color */}

      <div className="bg-gray-800 rounded-lg shadow-xl overflow-hidden"> {/* Updated background and shadow */}
        <div className="flex items-center justify-between p-4 border-b border-gray-700"> {/* Updated border color */}
          <div className="flex items-center">
            <input
              type="checkbox"
              className="form-checkbox h-5 w-5 text-indigo-600 rounded mr-2 bg-gray-700 border-gray-600"
              onChange={handleSelectAll}
              checked={isAllSelected}
              disabled={cases.length === 0 || loading}
            />
            <label className="text-sm text-gray-300">Select All ({selectedCaseIds.size} selected)</label> {/* Updated text color */}
          </div>
          <div className="flex space-x-2">
            <Button
              variant="primary"
              onClick={handleAcceptAllPending}
              disabled={isAcceptAllLoading || loading || !pendingReviewCasesExist}
              className="px-4 py-2 text-sm"
            >
              {isAcceptAllLoading ? 'Accepting...' : 'Accept All Pending'}
            </Button>
            <Dropdown
              options={[
                { label: 'Bulk Actions', value: BULK_ACTION_PLACEHOLDER_VALUE },
                { label: 'Accept', value: 'accept' },
                { label: 'Reject', value: 'reject' },
                { label: 'Assign', value: 'assign' },
              ]}
              selectedValue={BULK_ACTION_PLACEHOLDER_VALUE}
              onSelect={(value) => {
                if (value !== BULK_ACTION_PLACEHOLDER_VALUE) {
                  openBulkActionModal(value as 'accept' | 'reject' | 'assign');
                }
              }}
              placeholder="Bulk Actions"
              buttonClassName="!bg-indigo-500 hover:!bg-indigo-600 !text-white"
              menuClassName="!bg-gray-800"
            />
          </div>
        </div>

        {loading ? (
          <LoadingSpinner />
        ) : cases.length === 0 ? (
          <div className="p-4 text-center text-gray-400">No cases found matching your criteria.</div> /* Updated text color */
        ) : (
          <div>
            {cases.map(caseItem => (
              <CaseListItem
                key={caseItem.id}
                caseItem={caseItem}
                isSelected={selectedCaseIds.has(caseItem.id)}
                onSelect={handleSelectCase}
              />
            ))}
          </div>
        )}
      </div>

      <Pagination pagination={pagination} onPageChange={handlePageChange} />

      <Modal
        isOpen={isBulkActionModalOpen}
        onClose={closeBulkActionModal}
        title={`Confirm Bulk ${bulkActionType ? bulkActionType.charAt(0).toUpperCase() + bulkActionType.slice(1) : ''} (${selectedCaseIds.size} Cases)`}
        footer={
          <div className="flex justify-end space-x-2">
            <Button 
              onClick={closeBulkActionModal}
              className="bg-transparent text-white hover:bg-gray-700 px-4 py-2 focus:ring-offset-gray-800 focus:ring-2 focus:ring-indigo-500"
            >
                Cancel
            </Button>
            <Button variant="primary" onClick={performBulkAction} disabled={bulkActionType === 'assign' && !selectedAssigneeId}>
              Confirm
            </Button>
          </div>
        }
      >
        <p className="mb-4 text-gray-300">Are you sure you want to perform this action on the selected cases?</p> {/* Updated text color */}
        {bulkActionType === 'assign' && (
          <div>
            <label htmlFor="assignee-select" className="block text-sm font-medium text-gray-300 mb-1">Assign to:</label> {/* Updated text color */}
            <Dropdown
              options={assignees.map(u => ({ label: `[${u.unit}] ${u.email}`, value: u.id }))}
              selectedValue={selectedAssigneeId}
              onSelect={setSelectedAssigneeId}
              placeholder="Select Assignee"
