import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import { Case, CaseStatus, AuditLog, User, UserRole } from '../types';
import { VIOLATION_TYPE_COLORS } from '../constants';
import { fetchCaseById, updateCaseStatus, fetchAuditLogsForCase, assignCase, fetchUsersByRole, analyzeContentWithGemini } from '../services/api';
import LoadingSpinner from './LoadingSpinner';
import MapComponent from './MapComponent';
import Button from './Button';
import Modal from './Modal';
import Dropdown from './Dropdown';

interface CaseDetailProps {
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseDetail: React.FC<CaseDetailProps> = ({ onNotify }) => {
  const { id } = useParams<{ id: string }>();
  const [caseDetail, setCaseDetail] = useState<Case | null>(null);
  const [loading, setLoading] = useState(true);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);

  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [summaryTimestamp, setSummaryTimestamp] = useState<string | null>(null);
  const [generatingSummary, setGeneratingSummary] = useState(false);
  const [summaryError, setSummaryError] = useState<string | null>(null);

  const fetchCaseAndLogs = useCallback(async () => {
    setLoading(true);
    if (!id) return;
    try {
      const fetchedCase = await fetchCaseById(id);
      if (fetchedCase) {
        setCaseDetail(fetchedCase);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
      } else {
        console.error('Case not found.');
      }
    } catch (error) {
      console.error('Failed to fetch case details:', error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  const generateCaseSummary = useCallback(async (force = false) => {
    if (!caseDetail || auditLogs.length === 0) return;
    if (aiSummary && !force) return; // Don't regenerate automatically if already exists

    setGeneratingSummary(true);
    setSummaryError(null);

    const caseInfo = `
      Case ID: ${caseDetail.id}
      Status: ${caseDetail.status.replace(/_/g, ' ')}
      Violation Types: ${caseDetail.violationTypes.map(type => type.replace(/_/g, ' ')).join(', ')}
      Confidence: ${(caseDetail.confidence * 100).toFixed(0)}%
      Plate Text: ${caseDetail.plateText}
      Location: ${caseDetail.location.placeName}
      Created At: ${new Date(caseDetail.createdAt).toLocaleString()}
    `;

    const logInfo = auditLogs.map(log =>
      ` - ${log.action} by ${log.actorId} (${new Date(log.ts).toLocaleString()}): ${log.notes || 'No notes'}`
    ).join('\n');

    const prompt = `
      As a traffic safety analyst, provide a concise summary of this violation case.
      Analyze the provided data and the evidence image (if provided).
      Summarize the incident, the current administrative status, and any notable patterns in 3-4 professional sentences.

      Case Context:
      ${caseInfo}

      Administrative History:
      ${logInfo}
    `;

    try {
      // Use primary evidence image for multimodal analysis
      const primaryImage = caseDetail.mediaUrls[0];
      const summary = await analyzeContentWithGemini(prompt, primaryImage);
      setAiSummary(summary);
      setSummaryTimestamp(new Date().toLocaleTimeString());
    } catch (error) {
      console.error('Error generating AI summary:', error);
      setSummaryError('Failed to generate AI summary.');
    } finally {
      setGeneratingSummary(false);
    }
  }, [caseDetail, auditLogs, aiSummary]);

  useEffect(() => {
    fetchCaseAndLogs();
  }, [fetchCaseAndLogs]);

  useEffect(() => {
      // Auto-generate summary once on initial load
      if (caseDetail && auditLogs.length > 0 && !aiSummary && !generatingSummary && !summaryError) {
          generateCaseSummary();
      }
  }, [caseDetail, auditLogs, generateCaseSummary, aiSummary, generatingSummary, summaryError]);

  const handleStatusUpdate = async (status: CaseStatus) => {
    if (!id) return;
    setLoading(true);
    try {
      const updatedCase = await updateCaseStatus(id, status);
      if (updatedCase) {
        setCaseDetail(updatedCase);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(`Case status updated to ${status.replace(/_/g, ' ')}.`, 'success');
      }
    } catch (error) {
      console.error('Failed to update case status:', error);
      onNotify?.('Failed to update case status.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const openAssignModal = useCallback(async () => {
    if (!id) return;
    try {
      const reviewers = await fetchUsersByRole(UserRole.REVIEWER);
      setAssignees(reviewers);
      if (reviewers.length > 0) {
        setSelectedAssigneeId(reviewers[0].id);
      }
      setIsAssignModalOpen(true);
    } catch (error) {
      console.error('Failed to fetch assignees:', error);
      onNotify?.('Failed to load assignees.', 'error');
    }
  }, [id, onNotify]);

  const closeAssignModal = () => {
    setIsAssignModalOpen(false);
  };

  const handleAssignCase = async () => {
    if (!id || !selectedAssigneeId) return;
    setLoading(true);
    try {
      const result = await assignCase(id, selectedAssigneeId);
      if (result.success) {
        if (result.case) setCaseDetail(result.case);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(result.message, 'success');
      } else {
        onNotify?.(result.message, 'error');
      }
    } catch (error) {
      console.error('Failed to assign case:', error);
      onNotify?.('Failed to assign case.', 'error');
    } finally {
      setLoading(false);
      closeAssignModal();
    }
  };

  const statusColor = (status: CaseStatus): string => {
    switch (status) {
      case CaseStatus.ACCEPTED: return 'bg-green-700 text-white';
      case CaseStatus.REJECTED: return 'bg-red-700 text-white';
      case CaseStatus.PENDING_REVIEW: return 'bg-yellow-700 text-white';
      case CaseStatus.ASSIGNED: return 'bg-blue-700 text-white';
      case CaseStatus.DRAFT: return 'bg-gray-700 text-white';
      default: return 'bg-gray-700 text-white';
    }
  };

  if (loading) {
    return <LoadingSpinner />;
  }

  if (!caseDetail) {
    return (
      <div className="flex-1 p-6 text-center text-red-600">
        <p>Error: Case details could not be loaded.</p>
      </div>
    );
  }

  return (
    <div className="flex-1 p-6 bg-gray-900 text-white pb-24">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-white">Case ID: {caseDetail.id}</h2>
        <div className="flex space-x-2">
          {caseDetail.status === CaseStatus.PENDING_REVIEW && (
            <>
              <Button variant="primary" onClick={() => handleStatusUpdate(CaseStatus.ACCEPTED)}>
                Accept
              </Button>
              <Button variant="danger" onClick={() => handleStatusUpdate(CaseStatus.REJECTED)}>
                Reject
              </Button>
            </>
          )}
          {(caseDetail.status === CaseStatus.ACCEPTED || caseDetail.status === CaseStatus.PENDING_REVIEW) && (
            <Button variant="secondary" onClick={openAssignModal}>
              Assign
            </Button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Case Info */}
        <div className="lg:col-span-2 bg-gray-800 rounded-lg shadow-xl p-6">
          <h3 className="text-xl font-semibold text-white mb-4">Case Information</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-gray-300">
            <div>
              <p><strong className="font-medium">Status:</strong> <span className={`px-2 py-1 rounded-full text-sm font-medium ${statusColor(caseDetail.status)}`}>{caseDetail.status.replace(/_/g, ' ')}</span></p>
              <p className="mt-2"><strong className="font-medium">Created At:</strong> {new Date(caseDetail.createdAt).toLocaleString()}</p>
              <p className="mt-2"><strong className="font-medium">Confidence:</strong> {(caseDetail.confidence * 100).toFixed(0)}%</p>
              <p className="mt-2"><strong className="font-medium">Device ID:</strong> {caseDetail.deviceId}</p>
            </div>
            <div>
              <p><strong className="font-medium">Plate Text:</strong> {caseDetail.plateText}</p>
              <p className="mt-2"><strong className="font-medium">Plate Confidence:</strong> {(caseDetail.plateConfidence * 100).toFixed(0)}%</p>
              <p className="mt-2"><strong className="font-medium">Recorder ID:</strong> {caseDetail.recorderId}</p>
              <p className="mt-2"><strong className="font-medium">Duplicate Of:</strong> {caseDetail.duplicateOf || 'N/A'}</p>
            </div>
          </div>
          <div className="mt-4">
            <p><strong className="font-medium">Violation Types:</strong></p>
            <div className="flex flex-wrap gap-2 mt-2">
              {caseDetail.violationTypes.map(type => (
                <span key={type} className={`text-sm font-medium px-3 py-1 rounded-full ${VIOLATION_TYPE_COLORS[type]} text-white`}>
                  {type.replace(/_/g, ' ')}
                </span>
              ))}
            </div>
          </div>
        </div>

        {/* Media & Map */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-gray-800 rounded-lg shadow-xl p-6">
            <h3 className="text-xl font-semibold text-white mb-4">Evidence Media</h3>
            <div className="grid grid-cols-1 gap-4">
              {caseDetail.mediaUrls.length > 0 ? (
                <img src={caseDetail.mediaUrls[0]} alt="Primary Evidence" className="w-full h-48 object-cover rounded-md shadow-sm border border-gray-700" />
              ) : (
                <div className="w-full h-48 bg-gray-700 flex items-center justify-center rounded-md italic text-gray-400 text-sm">No media available</div>
              )}
            </div>
          </div>
          <div className="bg-gray-800 rounded-lg shadow-xl p-6">
            <h3 className="text-xl font-semibold text-white mb-4">Location</h3>
            <MapComponent location={caseDetail.location} placeName={caseDetail.location.placeName} />
          </div>
        </div>

        {/* AI Summary Section - Enhanced */}
        <div className="lg:col-span-3">
          <div className="relative p-[1px] rounded-xl bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 shadow-2xl overflow-hidden">
            <div className="bg-gray-900 rounded-xl p-6 h-full">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-2">
                  <svg className="w-6 h-6 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z"></path>
                  </svg>
                  <h3 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">
                    AI Case Analyst
                  </h3>
                </div>
                <div className="flex items-center space-x-4">
                  {summaryTimestamp && (
                    <span className="text-xs text-gray-500 hidden sm:inline">Last updated: {summaryTimestamp}</span>
                  )}
                  <Button 
                    variant="ghost" 
                    size="sm" 
                    onClick={() => generateCaseSummary(true)} 
                    disabled={generatingSummary}
                    className="flex items-center space-x-2 !text-indigo-400 hover:!bg-indigo-900/30"
                  >
                    <svg className={`w-4 h-4 ${generatingSummary ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path>
                    </svg>
                    <span>{generatingSummary ? 'Analyzing...' : 'Refresh'}</span>
                  </Button>
                </div>
              </div>

              {generatingSummary ? (
                <div className="py-8 flex flex-col items-center justify-center space-y-4">
                  <LoadingSpinner />
                  <p className="text-sm text-indigo-300 animate-pulse font-medium">Processing logs and visual evidence...</p>
                </div>
              ) : summaryError ? (
                <div className="bg-red-900/20 border border-red-700 p-4 rounded-lg text-red-400 text-sm">
                  {summaryError}
                </div>
              ) : aiSummary ? (
                <div className="prose prose-invert max-w-none">
                  <p className="text-gray-200 text-lg leading-relaxed italic border-l-4 border-indigo-500 pl-4 py-1">
                    "{aiSummary}"
                  </p>
                </div>
              ) : (
                <p className="text-gray-500 italic text-center py-4">Analysis available upon request.</p>
              )}
            </div>
          </div>
        </div>

        {/* Audit Log */}
        <div className="lg:col-span-3 bg-gray-800 rounded-lg shadow-xl p-6">
          <h3 className="text-xl font-semibold text-white mb-4">Detailed Audit Log</h3>
          {auditLogs.length > 0 ? (
            <div className="space-y-4">
              {auditLogs.map(log => (
                <div key={log.id} className="border-l-4 border-indigo-500 pl-4 py-2 bg-gray-700/50 rounded-md">
                  <p className="text-sm text-white font-semibold">{log.action}</p>
                  <p className="text-xs text-gray-400 mt-1">By: {log.actorId} | {new Date(log.ts).toLocaleString()}</p>
                  {log.notes && <p className="text-sm text-gray-300 mt-2 italic">"{log.notes}"</p>}
                </div>
              ))}
            </div>
          ) : (
            <p className="text-gray-400">No logs recorded.</p>
          )}
        </div>
      </div>

      <Modal
        isOpen={isAssignModalOpen}
        onClose={closeAssignModal}
        title="Assign Case to Traffic Unit"
        footer={
          <div className="flex justify-end space-x-2">
            <Button variant="secondary" onClick={closeAssignModal}>Cancel</Button>
            <Button variant="primary" onClick={handleAssignCase} disabled={!selectedAssigneeId}>
              Confirm Assignment
