        }
      >
        <p className="mb-4 text-gray-300">Select an officer or specialized traffic unit for secondary review and enforcement:</p>
        <div>
          <Dropdown
            options={assignees.map(u => ({ label: `[${u.unit}] ${u.email}`, value: u.id }))}
