const SubmittedCasesView: React.FC<SubmittedCasesViewProps> = ({ /*showAppToast*/ }) => {
  const [allCases, setAllCases] = useState<Case[]>([]); 
  const [loading, setLoading] = useState(true);

  const [searchTerm, setSearchTerm] = useState('');
  const debouncedSearchTerm = useDebounce(searchTerm, 300);

  const [searchResultsCases, setSearchResultsCases] = useState<Case[]>([]);
  const [searchResultsUsers, setSearchResultsUsers] = useState<User[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchExecuted, setSearchExecuted] = useState(false);

  const fetchAllCasesData = useCallback(async () => {
    setLoading(true);
    try {
      const data: PaginatedCases = await fetchCases({}, { page: 1, pageSize: 1000 });
      setAllCases(data.cases);
    } catch (err) {
      console.error('Failed to fetch submitted cases:', err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (!debouncedSearchTerm && !searchExecuted) {
      fetchAllCasesData();
    }
  }, [debouncedSearchTerm, searchExecuted, fetchAllCasesData]);


  useEffect(() => {
    const performSearch = async () => {
      if (debouncedSearchTerm) {
        setIsSearching(true);
        setSearchExecuted(true);
        try {
          const casesData = await fetchCases({ searchTerm: debouncedSearchTerm }, { page: 1, pageSize: 100 });
          setSearchResultsCases(casesData.cases);

          const usersData = await searchUsers(debouncedSearchTerm);
          setSearchResultsUsers(usersData);
        } catch (err) {
          console.error('Failed to perform search:', err);
          setSearchResultsCases([]);
          setSearchResultsUsers([]);
        } finally {
          setIsSearching(false);
        }
      } else {
        setSearchResultsCases([]);
        setSearchResultsUsers([]);
        setIsSearching(false);
        setSearchExecuted(false);
        fetchAllCasesData();
      }
    };

    performSearch();
  }, [debouncedSearchTerm, fetchAllCasesData]);


  return (
    <div className="p-4 bg-gray-900 min-h-full text-white pb-24">
      <h2 className="text-2xl font-bold mb-6 text-center">Submitted Cases</h2>

      <div className="mb-6">
        <label htmlFor="search-input" className="sr-only">Search Cases and People</label>
        <div className="relative">
          <input
            type="search"
            id="search-input"
            className="w-full p-3 rounded-lg bg-gray-800 border border-gray-700 text-white placeholder-gray-400 focus:ring-indigo-500 focus:border-indigo-500 pr-10"
            placeholder="Search cases or people..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          {searchTerm && (
            <button
              type="button"
              onClick={() => setSearchTerm('')}
              className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-white"
              aria-label="Clear search"
            >
              <svg className="h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {loading && !searchExecuted && <LoadingSpinner />}
      {isSearching && <LoadingSpinner />}

      {!isSearching && searchExecuted && searchTerm && (
        (searchResultsCases.length === 0 && searchResultsUsers.length === 0) ? (
          <div className="text-center text-gray-400 mt-8">No results found for "{searchTerm}".</div>
        ) : (
          <div className="space-y-6">
            {searchResultsCases.length > 0 && (
              <div>
                <h3 className="text-lg font-bold mb-4 flex items-center">
                  <span className="w-2 h-2 bg-indigo-500 rounded-full mr-2"></span>
                  Cases ({searchResultsCases.length})
                </h3>
                <div className="space-y-4">
                  {searchResultsCases.map(caseItem => (
                    <CaseDisplayCard key={caseItem.id} caseItem={caseItem} />
                  ))}
                </div>
              </div>
            )}
            {searchResultsUsers.length > 0 && (
              <div>
                <h3 className="text-lg font-bold mt-8 mb-4 flex items-center">
                  <span className="w-2 h-2 bg-green-500 rounded-full mr-2"></span>
                  People ({searchResultsUsers.length})
                </h3>
                <div className="space-y-4">
                  {searchResultsUsers.map(user => (
                    <UserDisplayCard key={user.id} user={user} />
                  ))}
                </div>
              </div>
            )}
          </div>
        )
      )}

      {!isSearching && !searchExecuted && !loading && (
        allCases.length === 0 ? (
          <div className="text-center text-gray-400 mt-8">No cases found.</div>
        ) : (
          <div className="space-y-4">
            {allCases.map(caseItem => (
              <CaseDisplayCard key={caseItem.id} caseItem={caseItem} />
            ))}
          </div>
        )
      )}
    </div>
  );
};

