export const analyzeContentWithGemini = async (prompt: string, imageBase64?: string): Promise<string> => {
  if (!API_KEY || API_KEY === 'YOUR_GEMINI_API_KEY_HERE') {
    return "Gemini API key is not configured. Cannot perform AI analysis.";
  }
  try {
    const contents: any[] = [{ text: prompt }];
    if (imageBase64) {
      try {
        const cleanBase64 = await ensureBase64(imageBase64);
        contents.push({
          inlineData: {
            mimeType: 'image/jpeg', 
            data: cleanBase64,
          },
        });
      } catch (e) {
        console.warn("Skipping image in analysis due to fetch error (likely CORS):", e);
        // If image fails (CORS on mock URLs), proceed with text only
      }
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
    });
    return response.text;
  } catch (error) {
    console.error('Error calling Gemini API:', error);
    return `Error from Gemini API: ${(error as Error).message}`;
  }
};

