export const acceptAllPendingCases = async (): Promise<{ success: number; failed: number }> => {
  await delay(1000); 

  let successCount = 0;
  let failedCount = 0;

  for (let i = 0; i < MOCK_CASES.length; i++) {
    if (MOCK_CASES[i].status === CaseStatus.PENDING_REVIEW) {
      try {
        MOCK_CASES[i].status = CaseStatus.ACCEPTED;
        const newLog: AuditLog = {
          id: `audit-${MOCK_CASES[i].id}-${MOCK_AUDIT_LOGS.length + 1}`,
          caseId: MOCK_CASES[i].id,
          action: `Status Updated to ${CaseStatus.ACCEPTED}`,
          actorId: MOCK_USERS[0].id, 
          notes: 'Accepted all pending cases via bulk action',
          ts: new Date().toISOString(),
        };
        MOCK_AUDIT_LOGS.push(newLog);
        successCount++;
      } catch (error) {
        console.error(`Failed to accept case ${MOCK_CASES[i].id}:`, error);
        failedCount++;
      }
    }
  }

  return { success: successCount, failed: failedCount };
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import Button from '../components/Button';
import LoadingSpinner from '../components/LoadingSpinner';
import { API_KEY } from '../constants'; // Import API_KEY

interface Message {
  text: string;
  sender: 'user' | 'gemini';
}

const ChatbotPage: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<Chat | null>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Initialize chat session
  useEffect(() => {
    const initializeChat = async () => {
      try {
        const ai = new GoogleGenAI({ apiKey: API_KEY });
        chatRef.current = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction: 'You are a helpful assistant specializing in traffic rules and M-Traffic Cop app support. Provide concise and informative answers.',
          },
        });
        // Add an initial welcome message
        setMessages([{ text: "Hello! How can I assist you with traffic violations today?", sender: 'gemini' }]);
      } catch (error) {
        console.error('Failed to initialize Gemini chat:', error);
        setMessages(prev => [...prev, { text: "Error: Failed to initialize chat. Please check your API key and try again.", sender: 'gemini' }]);
      }
    };
    initializeChat();
  }, []);

  // Scroll to bottom on new message or loading state change
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const sendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault(); // Prevent default form submission if triggered by form

    if (!input.trim() || isLoading || !chatRef.current) return;

    const userMessage = { text: input, sender: 'user' as const };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const responseStream = await chatRef.current.sendMessageStream({ message: userMessage.text });
      let geminiResponseText = '';

      // Add a placeholder message for Gemini's response
      setMessages(prev => [...prev, { text: '', sender: 'gemini' as const }]);

      for await (const chunk of responseStream) {
        const currentChunkText = chunk.text;
        if (currentChunkText) {
          geminiResponseText += currentChunkText;
          setMessages(prev => {
            const newMessages = [...prev];
            // Update the last message (which is Gemini's placeholder)
            if (newMessages.length > 0 && newMessages[newMessages.length - 1].sender === 'gemini') {
              newMessages[newMessages.length - 1].text = geminiResponseText;
            }
            return newMessages;
          });
        }
      }
    } catch (error) {
      console.error('Error sending message to Gemini:', error);
      setMessages(prev => [...prev, { text: `Error: Could not get a response. ${(error as Error).message}`, sender: 'gemini' as const }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-900 text-white">
      <div className="flex-1 overflow-y-auto p-4 space-y-4 hide-scrollbar" ref={chatContainerRef}>
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[70%] p-3 rounded-lg shadow-md ${
                msg.sender === 'user' ? 'bg-indigo-600 text-white' : 'bg-gray-700 text-white'
              }`}
            >
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="max-w-[70%] p-3 rounded-lg shadow-md bg-gray-700 text-white">
              <LoadingSpinner />
            </div>
          </div>
        )}
      </div>

      <form onSubmit={sendMessage} className="flex p-4 bg-gray-800 border-t border-gray-700">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type your message..."
          className="flex-1 p-3 rounded-l-lg bg-gray-700 border border-gray-600 text-white placeholder-gray-400 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500"
          disabled={isLoading}
        />
        <Button
          type="submit"
          variant="primary"
          className="rounded-l-none px-6 py-3"
          disabled={!input.trim() || isLoading}
        >
          {isLoading ? 'Sending...' : 'Send'}
        </Button>
      </form>
    </div>
  );
};

export default ChatbotPage;

