import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Case, CaseStatus, LatLng, ViolationType } from '../types';
import { ingestCase, detectViolationWithGemini } from '../services/api';
import { SPEED_LIMIT_KMH } from '../constants';
import CaseReviewOverlay from './CaseReviewOverlay';
import LoadingSpinner from '../components/LoadingSpinner';

interface CameraViewProps {
  recorderId: string;
}

const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const videoTrackRef = useRef<MediaStreamTrack | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [detectedCase, setDetectedCase] = useState<(Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 5000; // Run AI analysis every 5 seconds

  // Speed related state
  const [currentSpeed, setCurrentSpeed] = useState<number>(0);
  const [isSpeeding, setIsSpeeding] = useState(false);
  const hasTriggeredSpeedingRef = useRef(false);

  const [zoomLevel, setZoomLevel] = useState<number | null>(null);
  const [zoomCapabilities, setZoomCapabilities] = useState<{ min: number; max: number; step: number } | null>(null);

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d', { willReadFrequently: true });
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight || video.paused || video.ended) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (detectedCase && detectedCase.detectionArea) {
          const { x, y, width, height } = detectedCase.detectionArea;

          // Map percentages (0-100) from Gemini to pixel values
          const rectX = (x / 100) * canvas.width;
          const rectY = (y / 100) * canvas.height;
          const rectW = (width / 100) * canvas.width;
          const rectH = (height / 100) * canvas.height;

          context.strokeStyle = '#ef4444'; // Red-500
          context.lineWidth = 4;
          context.strokeRect(rectX, rectY, rectW, rectH);

          context.fillStyle = '#ef4444';
          context.font = 'bold 24px sans-serif';
          context.fillText(`${detectedCase.violationTypes[0].replace(/_/g, ' ')} (${(detectedCase.confidence * 100).toFixed(0)}%)`, rectX + 5, rectY - 10);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [detectedCase]);

  const stopCamera = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (animationFrameId.current) {
      cancelAnimationFrame(animationFrameId.current);
      animationFrameId.current = null;
    }
    if (videoRef.current) {
      videoRef.current.pause();
      videoRef.current.srcObject = null;
    }
    videoTrackRef.current = null;
    setZoomCapabilities(null);
    setZoomLevel(null);
    setIsCameraActive(false);
    setIsMediaReady(false);
    setIsAnalyzing(false);
  }, []);

  // Initialize Camera
  useEffect(() => {
    let isActiveComponent = true;
    const video = videoRef.current;

    const setupCameraStream = async () => {
      if (!video) return;

      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: {
            facingMode: 'environment',
            width: { ideal: 1280 },
            height: { ideal: 720 },
          },
        });

        if (!isActiveComponent) {
          mediaStream.getTracks().forEach(track => track.stop());
          return;
        }

        mediaStreamRef.current = mediaStream;
        video.srcObject = mediaStream;

        const videoTrack = mediaStream.getVideoTracks()[0];
        if (videoTrack) {
          videoTrackRef.current = videoTrack;
          const capabilities = videoTrack.getCapabilities() as any;
          if (capabilities.zoom) {
            setZoomCapabilities({
              min: capabilities.zoom.min,
              max: capabilities.zoom.max,
              step: capabilities.zoom.step || 0.1,
            });
            setZoomLevel(capabilities.zoom.current || capabilities.zoom.min);
          }
        }

        video.addEventListener('loadedmetadata', () => {
          if (!isActiveComponent || !videoRef.current) return;
          videoRef.current.play()
            .then(() => {
              if (isActiveComponent) {
                setIsCameraActive(true);
                setIsMediaReady(true);
                startDrawingLoop();
              }
            });
        }, { once: true });

      } catch (err) {
        console.error('Error accessing camera:', err);
      }
    };

    setupCameraStream();

    return () => {
      isActiveComponent = false;
      stopCamera();
    };
  }, [startDrawingLoop, stopCamera]);

  // GPS Speed Monitoring
  useEffect(() => {
    if (!navigator.geolocation) return;

    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        const speedMps = position.coords.speed || 0;
        const speedKmh = Math.round(speedMps * 3.6); // Convert m/s to km/h
        setCurrentSpeed(speedKmh);

        if (speedKmh > SPEED_LIMIT_KMH) {
          setIsSpeeding(true);
          // Only trigger automatic detection once per speeding event
          if (!hasTriggeredSpeedingRef.current && isMediaReady && !isAnalyzing && !detectedCase) {
            triggerSpeedingViolation();
          }
        } else {
          setIsSpeeding(false);
          hasTriggeredSpeedingRef.current = false;
        }
      },
      (error) => console.error('Geolocation speed error:', error),
      { enableHighAccuracy: true }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, [isMediaReady, isAnalyzing, detectedCase]);

  const getCurrentLocation = useCallback(async (): Promise<LatLng | undefined> => {
    return new Promise((resolve) => {
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (position) => resolve({ latitude: position.coords.latitude, longitude: position.coords.longitude }),
          () => resolve(undefined),
          { enableHighAccuracy: true, timeout: 5000 }
        );
      } else {
        resolve(undefined);
      }
    });
  }, []);

  const triggerSpeedingViolation = async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing) return;

    hasTriggeredSpeedingRef.current = true;
    setIsAnalyzing(true);

    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.9);
      const result = await detectViolationWithGemini(imageData);
      const location = await getCurrentLocation();

      const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
        id: '',
        createdAt: new Date().toISOString(),
        status: CaseStatus.DRAFT,
        violationTypes: [ViolationType.SPEEDING],
        confidence: 0.98,
        plateText: result.plateText || 'UNKNOWN',
        plateConfidence: result.plateText ? 0.9 : 0,
        location: location ? {
          ...location,
          geoHash: 'speed-trigger',
          placeName: `Speeding Detected (${currentSpeed} km/h)`,
        } : { latitude: 0, longitude: 0, geoHash: 'unknown', placeName: 'Unknown Location' },
        deviceId: 'm-traffic-cop-001',
        recorderId: recorderId,
        mediaUrls: [imageData],
        rulesMatched: [`Speeding-GPS-${currentSpeed}kmh`],
        duplicateOf: null,
        detectionArea: result.detectionArea,
      };
      setDetectedCase(newCase);
    } catch (error) {
      console.error("Speeding Detection Error:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  // AI Detection Loop using Gemini (General Violations)
  useEffect(() => {
    if (!isMediaReady || detectedCase || isAnalyzing || isSpeeding) return;

    const runDetectionCycle = async () => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current < detectionIntervalMs) return;

      const canvas = canvasRef.current;
      const video = videoRef.current;
      if (!canvas || !video || video.paused) return;

      setIsAnalyzing(true);
      lastDetectionTimeRef.current = now;

      try {
        const imageData = canvas.toDataURL('image/jpeg', 0.8);
        const result = await detectViolationWithGemini(imageData);

        if (result.violationDetected && result.violationType) {
          const location = await getCurrentLocation();

          const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
            id: '',
            createdAt: new Date().toISOString(),
            status: CaseStatus.DRAFT,
            violationTypes: [result.violationType],
            confidence: result.confidence || 0.85,
            plateText: result.plateText || 'UNKNOWN',
            plateConfidence: result.plateText ? 0.9 : 0,
            location: location ? {
              ...location,
              geoHash: 'ai-gen',
              placeName: 'Detected via Mobile AI',
            } : { latitude: 0, longitude: 0, geoHash: 'unknown', placeName: 'Unknown Location' },
            deviceId: 'm-traffic-cop-001',
            recorderId: recorderId,
            mediaUrls: [imageData],
            rulesMatched: ['Gemini-Vision-Detection'],
            duplicateOf: null,
            detectionArea: result.detectionArea,
          };
          setDetectedCase(newCase);
        }
      } catch (error) {
        console.error("AI Detection Error:", error);
      } finally {
        setIsAnalyzing(false);
      }
    };

    const interval = setInterval(runDetectionCycle, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, detectedCase, isAnalyzing, getCurrentLocation, recorderId, isSpeeding]);

  const handleApproveCase = useCallback(async () => {
    if (!detectedCase) return;
    try {
      const { detectionArea, ...caseToSubmit } = detectedCase; 
      const finalCase = { ...caseToSubmit, status: CaseStatus.PENDING_REVIEW };
      await ingestCase(finalCase);
      setDetectedCase(null);
    } catch (error) {
      console.error('Error submitting case:', error);
    }
  }, [detectedCase]);

  const handleDismissCase = useCallback(() => {
    setDetectedCase(null);
  }, []);

  const handleZoomChange = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
    const newZoom = parseFloat(event.target.value);
    if (videoRef.current && videoTrackRef.current && zoomCapabilities) {
        try {
            await videoTrackRef.current.applyConstraints({ advanced: [{ zoom: newZoom }] });
            setZoomLevel(newZoom);
        } catch (error) {
            console.error('Error applying zoom constraints:', error);
        }
    }
  }, [zoomCapabilities]);

  return (
    <div className="relative h-full w-full bg-black flex flex-col justify-center items-center overflow-hidden">
      <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover"></video>
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

      {/* Speedometer Overlay */}
      <div className={`absolute bottom-24 right-4 z-40 p-4 rounded-full flex flex-col items-center justify-center border-4 transition-all duration-300 ${isSpeeding ? 'bg-red-600 border-white scale-110 animate-pulse ring-4 ring-red-500 ring-opacity-50' : 'bg-black bg-opacity-60 border-indigo-500 shadow-lg'}`} style={{ width: '100px', height: '100px' }}>
        <span className="text-3xl font-black text-white tabular-nums">{currentSpeed}</span>
        <span className="text-[10px] font-bold text-white uppercase tracking-tighter">KM/H</span>
      </div>

      {/* Speeding Warning Bar */}
      {isSpeeding && (
        <div className="absolute top-0 left-0 w-full bg-red-600 text-white text-center py-1 font-bold z-50 animate-bounce shadow-md">
          ⚠️ SPEEDING DETECTED ({currentSpeed} KM/H)
        </div>
      )}

      {/* AI Analyzing indicator */}
      {isAnalyzing && (
        <div className="absolute top-8 left-4 bg-indigo-600 text-white text-sm px-4 py-2 rounded-full flex items-center shadow-lg z-20">
          <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full mr-3"></div>
          AI Analyzing Frame...
        </div>
      )}

      {/* Detecting indicator */}
      {!isAnalyzing && !detectedCase && isMediaReady && (
        <div className="absolute top-8 left-4 bg-gray-900 bg-opacity-60 text-white text-xs px-3 py-1 rounded-full flex items-center shadow-md">
          <span className="flex h-2 w-2 mr-2">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
          </span>
          AI Monitoring Active
        </div>
      )}

      {!isCameraActive && (
        <div className="absolute inset-0 bg-gray-900 bg-opacity-80 flex flex-col items-center justify-center text-white text-lg">
          <LoadingSpinner />
          <p className="mt-4 font-medium">Initializing Vision AI...</p>
        </div>
      )}

      {zoomCapabilities && zoomLevel !== null && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-gray-800 bg-opacity-75 px-4 py-2 rounded-full flex items-center space-x-2 shadow-lg z-40">
          <span className="text-white text-xs font-bold">ZOOM</span>
          <input
            type="range"
            min={zoomCapabilities.min}
            max={zoomCapabilities.max}
            step={zoomCapabilities.step}
            value={zoomLevel}
            onChange={handleZoomChange}
            className="w-32 h-2 rounded-lg appearance-none cursor-pointer bg-gray-700 accent-indigo-500"
          />
          <span className="text-white text-sm tabular-nums">{zoomLevel.toFixed(1)}x</span>
        </div>
      )}

      {detectedCase && (
        <CaseReviewOverlay
          caseData={detectedCase}
          onApprove={handleApproveCase}
          onDismiss={handleDismissCase}
        />
      )}
    </div>
  );
};

