              <Button variant="danger" onClick={() => handleStatusUpdate(CaseStatus.REJECTED)}>
                Reject
              </Button>
            </>
          )}
          {(caseDetail.status === CaseStatus.ACCEPTED || caseDetail.status === CaseStatus.PENDING_REVIEW) && (
            <Button variant="secondary" onClick={openAssignModal}>
              Assign
            </Button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Case Info */}
        <div className="lg:col-span-2 bg-gray-800 rounded-lg shadow-xl p-6">
          <h3 className="text-xl font-semibold text-white mb-4">Case Information</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-gray-300">
            <div>
              <p><strong className="font-medium">Status:</strong> <span className={`px-2 py-1 rounded-full text-sm font-medium ${statusColor(caseDetail.status)}`}>{caseDetail.status.replace(/_/g, ' ')}</span></p>
              <p className="mt-2"><strong className="font-medium">Created At:</strong> {new Date(caseDetail.createdAt).toLocaleString()}</p>
              <p className="mt-2"><strong className="font-medium">Confidence:</strong> {(caseDetail.confidence * 100).toFixed(0)}%</p>
              <p className="mt-2"><strong className="font-medium">Device ID:</strong> {caseDetail.deviceId}</p>
            </div>
            <div>
              <p><strong className="font-medium">Plate Text:</strong> {caseDetail.plateText}</p>
              <p className="mt-2"><strong className="font-medium">Plate Confidence:</strong> {(caseDetail.plateConfidence * 100).toFixed(0)}%</p>
              <p className="mt-2"><strong className="font-medium">Recorder ID:</strong> {caseDetail.recorderId}</p>
              <p className="mt-2"><strong className="font-medium">Duplicate Of:</strong> {caseDetail.duplicateOf || 'N/A'}</p>
            </div>
          </div>
          <div className="mt-4">
            <p><strong className="font-medium">Violation Types:</strong></p>
            <div className="flex flex-wrap gap-2 mt-2">
              {caseDetail.violationTypes.map(type => (
                <span key={type} className={`text-sm font-medium px-3 py-1 rounded-full ${VIOLATION_TYPE_COLORS[type]} text-white`}>
                  {type.replace(/_/g, ' ')}
