        {/* AI Summary Section - Enhanced */}
        <div className="lg:col-span-3">
          <div className="relative p-[1px] rounded-xl bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 shadow-2xl overflow-hidden">
