interface CaseDetailProps {
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseDetail: React.FC<CaseDetailProps> = ({ onNotify }) => {
  const { id } = useParams<{ id: string }>();
  const [caseDetail, setCaseDetail] = useState<Case | null>(null);
  const [loading, setLoading] = useState(true);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);

  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [summaryTimestamp, setSummaryTimestamp] = useState<string | null>(null);
  const [generatingSummary, setGeneratingSummary] = useState(false);
  const [summaryError, setSummaryError] = useState<string | null>(null);

  const fetchCaseAndLogs = useCallback(async () => {
    setLoading(true);
    if (!id) return;
    try {
      const fetchedCase = await fetchCaseById(id);
      if (fetchedCase) {
        setCaseDetail(fetchedCase);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
      } else {
        console.error('Case not found.');
      }
    } catch (error) {
      console.error('Failed to fetch case details:', error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  const generateCaseSummary = useCallback(async (force = false) => {
    if (!caseDetail || auditLogs.length === 0) return;
    if (aiSummary && !force) return; // Don't regenerate automatically if already exists

    setGeneratingSummary(true);
    setSummaryError(null);

    const caseInfo = `
      Case ID: ${caseDetail.id}
      Status: ${caseDetail.status.replace(/_/g, ' ')}
      Violation Types: ${caseDetail.violationTypes.map(type => type.replace(/_/g, ' ')).join(', ')}
      Confidence: ${(caseDetail.confidence * 100).toFixed(0)}%
      Plate Text: ${caseDetail.plateText}
      Location: ${caseDetail.location.placeName}
      Created At: ${new Date(caseDetail.createdAt).toLocaleString()}
    `;

    const logInfo = auditLogs.map(log =>
      ` - ${log.action} by ${log.actorId} (${new Date(log.ts).toLocaleString()}): ${log.notes || 'No notes'}`
    ).join('\n');

    const prompt = `
      As a traffic safety analyst, provide a concise summary of this violation case.
      Analyze the provided data and the evidence image (if provided).
      Summarize the incident, the current administrative status, and any notable patterns in 3-4 professional sentences.

      Case Context:
      ${caseInfo}

      Administrative History:
      ${logInfo}
    `;

    try {
      // Use primary evidence image for multimodal analysis
      const primaryImage = caseDetail.mediaUrls[0];
      const summary = await analyzeContentWithGemini(prompt, primaryImage);
      setAiSummary(summary);
      setSummaryTimestamp(new Date().toLocaleTimeString());
    } catch (error) {
      console.error('Error generating AI summary:', error);
      setSummaryError('Failed to generate AI summary.');
    } finally {
      setGeneratingSummary(false);
    }
  }, [caseDetail, auditLogs, aiSummary]);

  useEffect(() => {
    fetchCaseAndLogs();
  }, [fetchCaseAndLogs]);

  useEffect(() => {
      // Auto-generate summary once on initial load
      if (caseDetail && auditLogs.length > 0 && !aiSummary && !generatingSummary && !summaryError) {
          generateCaseSummary();
      }
  }, [caseDetail, auditLogs, generateCaseSummary, aiSummary, generatingSummary, summaryError]);

  const handleStatusUpdate = async (status: CaseStatus) => {
    if (!id) return;
    setLoading(true);
    try {
      const updatedCase = await updateCaseStatus(id, status);
      if (updatedCase) {
        setCaseDetail(updatedCase);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(`Case status updated to ${status.replace(/_/g, ' ')}.`, 'success');
      }
    } catch (error) {
      console.error('Failed to update case status:', error);
      onNotify?.('Failed to update case status.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const openAssignModal = useCallback(async () => {
    if (!id) return;
    try {
      const reviewers = await fetchUsersByRole(UserRole.REVIEWER);
      setAssignees(reviewers);
      if (reviewers.length > 0) {
        setSelectedAssigneeId(reviewers[0].id);
      }
      setIsAssignModalOpen(true);
    } catch (error) {
      console.error('Failed to fetch assignees:', error);
      onNotify?.('Failed to load assignees.', 'error');
    }
  }, [id, onNotify]);

  const closeAssignModal = () => {
    setIsAssignModalOpen(false);
  };

  const handleAssignCase = async () => {
    if (!id || !selectedAssigneeId) return;
    setLoading(true);
    try {
      const result = await assignCase(id, selectedAssigneeId);
      if (result.success) {
        if (result.case) setCaseDetail(result.case);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(result.message, 'success');
      } else {
        onNotify?.(result.message, 'error');
      }
    } catch (error) {
      console.error('Failed to assign case:', error);
      onNotify?.('Failed to assign case.', 'error');
    } finally {
      setLoading(false);
      closeAssignModal();
    }
  };

  const statusColor = (status: CaseStatus): string => {
    switch (status) {
      case CaseStatus.ACCEPTED: return 'bg-green-700 text-white';
      case CaseStatus.REJECTED: return 'bg-red-700 text-white';
      case CaseStatus.PENDING_REVIEW: return 'bg-yellow-700 text-white';
      case CaseStatus.ASSIGNED: return 'bg-blue-700 text-white';
      case CaseStatus.DRAFT: return 'bg-gray-700 text-white';
