import { GoogleGenAI, Type } from '@google/genai';
import { API_KEY, MOCK_CASES, MOCK_USERS, MOCK_AUDIT_LOGS } from '../constants';
import { Case, CaseStatus, FilterOptions, PaginationInfo, User, AuditLog, LatLng, UserRole, ViolationType, ManualReport } from '../types';

// Initialize Gemini API client
const ai = new GoogleGenAI({ apiKey: API_KEY });

// Simulate network delay
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export interface PaginatedCases {
  cases: Case[];
  pagination: PaginationInfo;
}

export interface DetectionResult {
  violationDetected: boolean;
  violationType?: ViolationType;
  confidence?: number;
  plateText?: string;
  placeName?: string; // New: AI identified place name
  detectionArea?: {
    x: number;
    y: number;
    width: number;
    height: number;
  };
}

export interface AssignResult {
  success: boolean;
  case?: Case;
  message: string;
}

/**
 * Utility to ensure we have a raw base64 string.
 */
async function ensureBase64(input: string): Promise<string | null> {
  if (!input) return null;

  if (input.startsWith('data:')) {
    const parts = input.split(',');
    return parts.length > 1 ? parts[1] : null;
  }

  if (input.startsWith('http')) {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000);
      const response = await fetch(input, { signal: controller.signal });
      clearTimeout(timeoutId);
      if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
      const blob = await response.blob();
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const result = reader.result as string;
          resolve(result.split(',')[1]);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Failed to fetch image "${input}" for base64 conversion:`, e);
      return null;
    }
  }
  return input;
}

export const detectViolationWithGemini = async (imageBase64: string, locationContext?: LatLng): Promise<DetectionResult> => {
  if (!API_KEY || API_KEY === 'YOUR_GEMINI_API_KEY_HERE') {
    throw new Error("Gemini API key is not configured.");
  }

  try {
    const cleanBase64 = await ensureBase64(imageBase64);
    if (!cleanBase64) return { violationDetected: false };

    const locPrompt = locationContext 
      ? `The camera is at coordinates [${locationContext.latitude}, ${locationContext.longitude}]. ` 
      : "";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            text: `${locPrompt}Analyze this traffic camera frame. 
            1. Detect violations (RED_LIGHT_JUMP, NO_HELMET, TRIPLE_RIDING, NO_SEATBELT, WRONG_WAY, PHONE_IN_HAND, STOP_LINE_OVERRUN, SPEEDING, ILLEGAL_PARKING).
            2. Identify the specific location, street name, intersection, or landmark visible in the image.
            3. Provide a bounding box (detectionArea) in normalized coordinates (0-100). 
            4. Extract the license plate text precisely. If not found, leave as null.`
          },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: cleanBase64,
            },
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            violationDetected: { type: Type.BOOLEAN },
            violationType: { type: Type.STRING, enum: Object.values(ViolationType) },
            confidence: { type: Type.NUMBER },
            plateText: { type: Type.STRING },
            placeName: { type: Type.STRING, description: "Specific street, intersection or landmark identified visually" },
            detectionArea: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                width: { type: Type.NUMBER },
                height: { type: Type.NUMBER },
              },
              required: ["x", "y", "width", "height"]
            }
          },
          required: ["violationDetected"]
        }
      },
    });

    const result = JSON.parse(response.text || '{}');
    return result as DetectionResult;
  } catch (error) {
    console.error('Error during Gemini detection:', error);
    return { violationDetected: false };
  }
};

export const fetchCases = async (filters: FilterOptions, pagination: { page: number; pageSize: number }): Promise<PaginatedCases> => {
  await delay(500); 
  let filteredCases = [...MOCK_CASES];
  if (filters.status) filteredCases = filteredCases.filter(c => c.status === filters.status);
  if (filters.violationType) filteredCases = filteredCases.filter(c => c.violationTypes.includes(filters.violationType!));
  if (filters.confidenceMin !== undefined) filteredCases = filteredCases.filter(c => c.confidence >= filters.confidenceMin!);
  if (filters.locationSearch) {
    const searchLower = filters.locationSearch.toLowerCase();
    filteredCases = filteredCases.filter(c => c.location.placeName.toLowerCase().includes(searchLower));
  }
  if (filters.createdAtAfter) {
    const afterDate = new Date(filters.createdAtAfter);
    filteredCases = filteredCases.filter(c => new Date(c.createdAt) >= afterDate);
  }
  if (filters.createdAtBefore) {
    const beforeDate = new Date(filters.createdAtBefore);
    const endOfDayBeforeDate = new Date(beforeDate);
    endOfDayBeforeDate.setHours(23, 59, 59, 999);
    filteredCases = filteredCases.filter(c => new Date(c.createdAt) <= endOfDayBeforeDate);
  }
  if (filters.searchTerm) {
    const termLower = filters.searchTerm.toLowerCase();
    filteredCases = filteredCases.filter(c =>
      c.id.toLowerCase().includes(termLower) ||
      c.plateText.toLowerCase().includes(termLower) ||
      c.location.placeName.toLowerCase().includes(termLower) ||
      c.violationTypes.some(vt => vt.toLowerCase().includes(termLower))
    );
  }
  filteredCases.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  const totalItems = filteredCases.length;
  const totalPages = Math.ceil(totalItems / pagination.pageSize);
  const startIndex = (pagination.page - 1) * pagination.pageSize;
  const endIndex = startIndex + pagination.pageSize;
  const paginatedCases = filteredCases.slice(startIndex, endIndex);
  return {
    cases: paginatedCases,
    pagination: { page: pagination.page, pageSize: pagination.pageSize, totalItems, totalPages },
  };
};

export const fetchCaseById = async (id: string): Promise<Case | undefined> => {
  await delay(300); 
  return MOCK_CASES.find(c => c.id === id);
};

export const updateCaseStatus = async (id: string, status: CaseStatus): Promise<Case | undefined> => {
  await delay(200); 
  const caseIndex = MOCK_CASES.findIndex(c => c.id === id);
  if (caseIndex > -1) {
    MOCK_CASES[caseIndex].status = status;
    const newLog: AuditLog = {
      id: `audit-${id}-${MOCK_AUDIT_LOGS.length + 1}`,
      caseId: id,
      action: `Status Updated to ${status}`,
      actorId: MOCK_USERS[0].id, 
      notes: `Case status changed to ${status}`,
      ts: new Date().toISOString(),
    };
    MOCK_AUDIT_LOGS.push(newLog);
    return MOCK_CASES[caseIndex];
  }
  return undefined;
};

export const assignCase = async (id: string, userId: string): Promise<AssignResult> => {
  await delay(200); 
  const caseIndex = MOCK_CASES.findIndex(c => c.id === id);
  const assignee = MOCK_USERS.find(u => u.id === userId);
  if (caseIndex > -1 && assignee) {
    MOCK_CASES[caseIndex].status = CaseStatus.ASSIGNED;
    const newLog: AuditLog = {
      id: `audit-${id}-${MOCK_AUDIT_LOGS.length + 1}`,
      caseId: id,
      action: `Case Assigned to ${assignee.email}`,
      actorId: MOCK_USERS[0].id, 
      notes: `Assigned to ${assignee.unit}`,
      ts: new Date().toISOString(),
    };
    MOCK_AUDIT_LOGS.push(newLog);
    return {
      success: true,
      case: MOCK_CASES[caseIndex],
      message: `Case ${id} successfully assigned to ${assignee.unit} (${assignee.email}).`
    };
  }
  return { success: false, message: `Failed to assign case ${id}. User or case not found.` };
};

export const fetchUsersByRole = async (role: UserRole): Promise<User[]> => {
  await delay(100);
  return MOCK_USERS.filter(u => u.role === role);
};

export const searchUsers = async (searchTerm: string): Promise<User[]> => {
  await delay(300); 
  if (!searchTerm) return [];
  const termLower = searchTerm.toLowerCase();
  return MOCK_USERS.filter(user =>
    user.id.toLowerCase().includes(termLower) ||
    user.email.toLowerCase().includes(termLower) ||
    user.role.toLowerCase().includes(termLower) ||
    user.unit.toLowerCase().includes(termLower) ||
    (user.phone && user.phone.toLowerCase().includes(termLower))
  );
};

export const fetchAuditLogsForCase = async (caseId: string): Promise<AuditLog[]> => {
  await delay(100);
  return MOCK_AUDIT_LOGS.filter(log => log.caseId === caseId).sort((a, b) => new Date(a.ts).getTime() - new Date(b.ts).getTime());
};

export const analyzeContentWithGemini = async (prompt: string, imageBase64?: string): Promise<string> => {
  if (!API_KEY || API_KEY === 'YOUR_GEMINI_API_KEY_HERE') return "Gemini API key is not configured.";
  try {
    const contents: any[] = [{ text: prompt }];
    if (imageBase64) {
      const cleanBase64 = await ensureBase64(imageBase64);
      if (cleanBase64) {
        contents.push({ inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } });
      }
    }
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
    });
    return response.text || "No response.";
  } catch (error: any) {
    console.error('Error calling Gemini API:', error);
    if (error?.message?.includes('xhr error') || error?.message?.includes('ProxyUnaryCall')) {
      return "The AI service is currently having connection issues.";
    }
    return `Analysis failed: ${error.message || 'Unknown error'}`;
  }
};

export const ingestCase = async (caseData: Case): Promise<Case> => {
  await delay(500); 
  const newCase = { ...caseData, id: `case-${Date.now()}-${Math.random().toString(36).substring(2, 7)}` };
  MOCK_CASES.unshift(newCase); 
  const newLog: AuditLog = {
    id: `audit-${newCase.id}-001`,
    caseId: newCase.id,
    action: 'Case Ingested (AI Detected)',
    actorId: newCase.recorderId,
    notes: 'Automatically detected and submitted from mobile app',
    ts: newCase.createdAt,
  };
  MOCK_AUDIT_LOGS.push(newLog);
  return newCase;
};

export const ingestManualReport = async (reportData: ManualReport): Promise<Case> => {
  await delay(500); 
  const newCase: Case = {
    id: `case-${Date.now()}-${Math.random().toString(36).substring(2, 7)}`,
    createdAt: reportData.timestamp,
    status: CaseStatus.PENDING_REVIEW, 
    violationTypes: reportData.violationType, 
    confidence: 0.99, 
    plateText: 'UNKNOWN', 
    plateConfidence: 0,
    location: reportData.location ? { ...reportData.location, geoHash: 'manual', placeName: 'Manual Report Location' } : { latitude: 0, longitude: 0, geoHash: 'manual', placeName: 'Unknown Manual Location' },
    deviceId: 'manual-device', 
    recorderId: reportData.reporterId,
    mediaUrls: [reportData.imageBase64], 
    rulesMatched: ['Manual-Report'],
    duplicateOf: null,
  };
  MOCK_CASES.unshift(newCase); 
  const newLog: AuditLog = {
    id: `audit-${newCase.id}-001`,
    caseId: newCase.id,
    action: 'Manual Report Submitted',
    actorId: reportData.reporterId,
    notes: reportData.notes || 'Submitted manually from mobile app',
    ts: newCase.createdAt,
  };
  MOCK_AUDIT_LOGS.push(newLog);
  return newCase;
};

export const acceptAllPendingCases = async (): Promise<{ success: number; failed: number }> => {
  await delay(1000); 
  let successCount = 0;
  let failedCount = 0;
  for (let i = 0; i < MOCK_CASES.length; i++) {
    if (MOCK_CASES[i].status === CaseStatus.PENDING_REVIEW) {
      try {
        MOCK_CASES[i].status = CaseStatus.ACCEPTED;
        const newLog: AuditLog = {
          id: `audit-${MOCK_CASES[i].id}-${MOCK_AUDIT_LOGS.length + 1}`,
          caseId: MOCK_CASES[i].id,
          action: `Status Updated to ${CaseStatus.ACCEPTED}`,
          actorId: MOCK_USERS[0].id, 
          notes: 'Accepted all pending cases via bulk action',
          ts: new Date().toISOString(),
        };
        MOCK_AUDIT_LOGS.push(newLog);
        successCount++;
      } catch (error) {
        failedCount++;
      }
    }
  }
  return { success: successCount, failed: failedCount };
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Case, CaseStatus, LatLng, ViolationType } from '../types';
import { ingestCase, detectViolationWithGemini } from '../services/api';
import { SPEED_LIMIT_KMH } from '../constants';
import CaseReviewOverlay from './CaseReviewOverlay';
import LoadingSpinner from '../components/LoadingSpinner';

interface CameraViewProps {
  recorderId: string;
}

const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const videoTrackRef = useRef<MediaStreamTrack | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [detectedCase, setDetectedCase] = useState<(Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 5000;

  // Speed related state
  const [currentSpeed, setCurrentSpeed] = useState<number>(0);
  const [isSpeeding, setIsSpeeding] = useState(false);
  const hasTriggeredSpeedingRef = useRef(false);

  const [zoomLevel, setZoomLevel] = useState<number | null>(null);
  const [zoomCapabilities, setZoomCapabilities] = useState<{ min: number; max: number; step: number } | null>(null);

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d', { willReadFrequently: true });
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight || video.paused || video.ended) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (detectedCase && detectedCase.detectionArea) {
          const { x, y, width, height } = detectedCase.detectionArea;
          const rectX = (x / 100) * canvas.width;
          const rectY = (y / 100) * canvas.height;
          const rectW = (width / 100) * canvas.width;
          const rectH = (height / 100) * canvas.height;

          context.strokeStyle = '#ef4444';
          context.lineWidth = 4;
          context.strokeRect(rectX, rectY, rectW, rectH);

          context.fillStyle = '#ef4444';
          context.font = 'bold 24px sans-serif';
          context.fillText(`${detectedCase.violationTypes[0].replace(/_/g, ' ')} (${(detectedCase.confidence * 100).toFixed(0)}%)`, rectX + 5, rectY - 10);

          if (detectedCase.plateText && detectedCase.plateText !== 'UNKNOWN') {
             context.fillStyle = '#ffffff';
             context.font = 'bold 20px sans-serif';
             context.fillText(`PLATE: ${detectedCase.plateText}`, rectX + 5, rectY + rectH + 25);
          }
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [detectedCase]);

  const stopCamera = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (animationFrameId.current) {
      cancelAnimationFrame(animationFrameId.current);
      animationFrameId.current = null;
    }
    if (videoRef.current) {
      videoRef.current.pause();
      videoRef.current.srcObject = null;
    }
    videoTrackRef.current = null;
    setZoomCapabilities(null);
    setZoomLevel(null);
    setIsCameraActive(false);
    setIsMediaReady(false);
    setIsAnalyzing(false);
  }, []);

  useEffect(() => {
    let isActiveComponent = true;
    const video = videoRef.current;
    const setupCameraStream = async () => {
      if (!video) return;
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
        });
        if (!isActiveComponent) {
          mediaStream.getTracks().forEach(track => track.stop());
          return;
        }
        mediaStreamRef.current = mediaStream;
        video.srcObject = mediaStream;
        const videoTrack = mediaStream.getVideoTracks()[0];
        if (videoTrack) {
          videoTrackRef.current = videoTrack;
          const capabilities = videoTrack.getCapabilities() as any;
          if (capabilities.zoom) {
            setZoomCapabilities({
              min: capabilities.zoom.min,
              max: capabilities.zoom.max,
              step: capabilities.zoom.step || 0.1,
            });
            setZoomLevel(capabilities.zoom.current || capabilities.zoom.min);
          }
        }
        video.addEventListener('loadedmetadata', () => {
          if (!isActiveComponent || !videoRef.current) return;
          videoRef.current.play().then(() => {
            if (isActiveComponent) {
              setIsCameraActive(true);
              setIsMediaReady(true);
              startDrawingLoop();
            }
          });
        }, { once: true });
      } catch (err) {
        console.error('Error accessing camera:', err);
      }
    };
    setupCameraStream();
    return () => { isActiveComponent = false; stopCamera(); };
  }, [startDrawingLoop, stopCamera]);

  useEffect(() => {
    if (!navigator.geolocation) return;
    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        const speedMps = position.coords.speed || 0;
        const speedKmh = Math.round(speedMps * 3.6);
        setCurrentSpeed(speedKmh);
        if (speedKmh > SPEED_LIMIT_KMH) {
          setIsSpeeding(true);
          if (!hasTriggeredSpeedingRef.current && isMediaReady && !isAnalyzing && !detectedCase) {
            triggerSpeedingViolation();
          }
        } else {
          setIsSpeeding(false);
          hasTriggeredSpeedingRef.current = false;
        }
      },
      (error) => console.error('Geolocation speed error:', error),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, [isMediaReady, isAnalyzing, detectedCase]);

  const getCurrentLocation = useCallback(async (): Promise<LatLng | undefined> => {
    return new Promise((resolve) => {
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (position) => resolve({ latitude: position.coords.latitude, longitude: position.coords.longitude }),
          () => resolve(undefined),
          { enableHighAccuracy: true, timeout: 5000 }
        );
      } else {
        resolve(undefined);
      }
    });
  }, []);

  const triggerSpeedingViolation = async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing) return;
    hasTriggeredSpeedingRef.current = true;
    setIsAnalyzing(true);
    try {
      const location = await getCurrentLocation();
      const imageData = canvas.toDataURL('image/jpeg', 0.9);
      const result = await detectViolationWithGemini(imageData, location);
      const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
        id: '',
        createdAt: new Date().toISOString(),
        status: CaseStatus.DRAFT,
        violationTypes: [ViolationType.SPEEDING],
        confidence: 0.98,
        plateText: result.plateText || 'UNKNOWN',
        plateConfidence: result.plateText ? 0.95 : 0,
        location: location ? {
          ...location,
          geoHash: 'speed-trigger',
          placeName: result.placeName || `Speeding Detected at ${currentSpeed} km/h`,
        } : { latitude: 0, longitude: 0, geoHash: 'unknown', placeName: 'Unknown Location' },
        deviceId: 'm-traffic-cop-001',
        recorderId: recorderId,
        mediaUrls: [imageData],
        rulesMatched: [`Speeding-GPS-${currentSpeed}kmh`],
        duplicateOf: null,
        detectionArea: result.detectionArea,
      };
      setDetectedCase(newCase);
    } catch (error) {
      console.error("Speeding Detection Error:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    if (!isMediaReady || detectedCase || isAnalyzing || isSpeeding) return;
    const runDetectionCycle = async () => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current < detectionIntervalMs) return;
      const canvas = canvasRef.current;
      const video = videoRef.current;
      if (!canvas || !video || video.paused) return;
      setIsAnalyzing(true);
      lastDetectionTimeRef.current = now;
      try {
        const location = await getCurrentLocation();
        const imageData = canvas.toDataURL('image/jpeg', 0.8);
        const result = await detectViolationWithGemini(imageData, location);
        if (result.violationDetected && result.violationType) {
          const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
            id: '',
            createdAt: new Date().toISOString(),
            status: CaseStatus.DRAFT,
            violationTypes: [result.violationType],
            confidence: result.confidence || 0.85,
            plateText: result.plateText || 'UNKNOWN',
            plateConfidence: result.plateText ? 0.92 : 0,
            location: location ? {
              ...location,
              geoHash: 'ai-gen',
              placeName: result.placeName || 'Detected via AI',
            } : { latitude: 0, longitude: 0, geoHash: 'unknown', placeName: 'Unknown Location' },
            deviceId: 'm-traffic-cop-001',
            recorderId: recorderId,
            mediaUrls: [imageData],
            rulesMatched: ['Gemini-Vision-Detection'],
            duplicateOf: null,
            detectionArea: result.detectionArea,
          };
          setDetectedCase(newCase);
        }
      } catch (error) {
        console.error("AI Detection Error:", error);
      } finally {
        setIsAnalyzing(false);
      }
    };
    const interval = setInterval(runDetectionCycle, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, detectedCase, isAnalyzing, getCurrentLocation, recorderId, isSpeeding]);

  const handleApproveCase = useCallback(async () => {
    if (!detectedCase) return;
    try {
      const { detectionArea, ...caseToSubmit } = detectedCase; 
      const finalCase = { ...caseToSubmit, status: CaseStatus.PENDING_REVIEW };
      await ingestCase(finalCase);
      setDetectedCase(null);
    } catch (error) {
      console.error('Error submitting case:', error);
    }
  }, [detectedCase]);

  const handleDismissCase = useCallback(() => {
    setDetectedCase(null);
  }, []);

  const handleZoomChange = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
    const newZoom = parseFloat(event.target.value);
    if (videoRef.current && videoTrackRef.current && zoomCapabilities) {
        try {
            await videoTrackRef.current.applyConstraints({ advanced: [{ zoom: newZoom }] });
            setZoomLevel(newZoom);
        } catch (error) {
            console.error('Error applying zoom constraints:', error);
        }
    }
  }, [zoomCapabilities]);

  return (
    <div className="relative h-full w-full bg-black flex flex-col justify-center items-center overflow-hidden">
      <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover"></video>
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>
      {isAnalyzing && (
        <div className="absolute top-8 left-4 bg-indigo-600 text-white text-sm px-4 py-2 rounded-full flex items-center shadow-lg z-20">
          <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full mr-3"></div>
          Pinpointing Violation & Location...
        </div>
      )}
      {!isAnalyzing && !detectedCase && isMediaReady && (
        <div className="absolute top-8 left-4 bg-gray-900 bg-opacity-60 text-white text-xs px-3 py-1 rounded-full flex items-center shadow-md">
          <span className="flex h-2 w-2 mr-2">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
          </span>
          Precise Monitoring Active
        </div>
      )}
      {!isCameraActive && (
        <div className="absolute inset-0 bg-gray-900 bg-opacity-80 flex flex-col items-center justify-center text-white text-lg">
          <LoadingSpinner />
          <p className="mt-4 font-medium">Initializing Vision AI...</p>
        </div>
      )}
      {zoomCapabilities && zoomLevel !== null && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-gray-800 bg-opacity-75 px-4 py-2 rounded-full flex items-center space-x-2 shadow-lg z-40">
          <span className="text-white text-xs font-bold">ZOOM</span>
          <input
            type="range"
            min={zoomCapabilities.min}
            max={zoomCapabilities.max}
            step={zoomCapabilities.step}
            value={zoomLevel}
            onChange={handleZoomChange}
            className="w-32 h-2 rounded-lg appearance-none cursor-pointer bg-gray-700 accent-indigo-500"
          />
          <span className="text-white text-sm tabular-nums">{zoomLevel.toFixed(1)}x</span>
        </div>
      )}
      {detectedCase && (
        <CaseReviewOverlay
          caseData={detectedCase}
          onApprove={handleApproveCase}
          onDismiss={handleDismissCase}
        />
      )}
    </div>
  );
};

export default CameraView;

