import React, { useState, useRef, useCallback, useEffect } from 'react';
import { LatLng, ManualReport, ViolationType } from '../types';
import Button from '../components/Button';
import { ingestManualReport } from '../services/api';
import Modal from '../components/Modal';

interface ManualReportFormProps {
  recorderId: string;
}

const ManualReportForm: React.FC<ManualReportFormProps> = ({ recorderId }) => {
  const [selectedViolationTypes, setSelectedViolationTypes] = useState<ViolationType[]>([]);
  const [isViolationSelectModalOpen, setIsViolationSelectModalOpen] = useState(false);
  const [notes, setNotes] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [currentLocation, setCurrentLocation] = useState<LatLng | null>(null);
  const [locationLoading, setLocationLoading] = useState(true);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const fetchLoc = async () => {
      setLocationLoading(true);
      const loc = await getCurrentLocation();
      if (loc) setCurrentLocation(loc);
      setLocationLoading(false);
    };
    fetchLoc();
  }, []);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setImageFile(e.target.files[0]);
    } else {
      setImageFile(null);
    }
  };

  const getBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const getCurrentLocation = useCallback(async (): Promise<LatLng | undefined> => {
    return new Promise((resolve) => {
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (position) => resolve({ latitude: position.coords.latitude, longitude: position.coords.longitude }),
          () => resolve(undefined),
          { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
        );
      } else {
        resolve(undefined);
      }
    });
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedViolationTypes.length === 0 || !imageFile) return;

    setIsSubmitting(true);
    try {
      const imageBase64 = await getBase64(imageFile);
      const location = await getCurrentLocation();
      const report: ManualReport = {
        violationType: selectedViolationTypes,
        notes: notes,
        imageBase64: imageBase64,
        location: location || undefined,
        timestamp: new Date().toISOString(),
        reporterId: recorderId,
      };
      await ingestManualReport(report);
      setSelectedViolationTypes([]);
      setNotes('');
      setImageFile(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    } catch (error) {
      console.error('Error submitting manual report:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="p-4 bg-gray-900 min-h-full text-white">
      <h2 className="text-2xl font-bold mb-6 text-center">Manual Report</h2>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium mb-2">Location Status</label>
          <div className="bg-gray-800 p-3 rounded-lg border border-gray-700 flex items-center">
            {locationLoading ? (
              <span className="text-gray-400 text-xs flex items-center italic">
                <div className="animate-spin h-3 w-3 border-2 border-indigo-500 border-t-transparent rounded-full mr-2"></div>
                Locking GPS coordinates...
              </span>
            ) : currentLocation ? (
              <span className="text-green-400 text-xs flex items-center font-medium">
                <svg className="w-4 h-4 mr-2" fill="currentColor" viewBox="0 0 20 20">
                   <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                </svg>
                Coordinates Captured: {currentLocation.latitude.toFixed(4)}, {currentLocation.longitude.toFixed(4)}
              </span>
            ) : (
              <span className="text-red-400 text-xs font-medium">GPS Access Required</span>
            )}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">
            Violation Type(s) <span className="text-red-500">*</span>
          </label>
          <Button
            type="button"
            onClick={() => setIsViolationSelectModalOpen(true)}
            className="w-full flex items-center justify-between bg-black border border-gray-700 text-white px-4 py-2 hover:bg-gray-700"
          >
            <span className="flex-grow text-left overflow-hidden text-ellipsis whitespace-nowrap text-sm">
                {selectedViolationTypes.length > 0
                    ? selectedViolationTypes.map(type => type.replace(/_/g, ' ')).join(', ')
                    : 'Select Type(s)'}
            </span>
            <svg className="ml-2 h-5 w-5 text-indigo-400" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
            </svg>
          </Button>
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">Evidence Photo <span className="text-red-500">*</span></label>
          <input
            type="file"
            id="evidence-photo"
            accept="image/*"
            capture="environment"
            ref={fileInputRef}
            className="block w-full text-xs text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-indigo-500 file:text-white hover:file:bg-indigo-600 bg-gray-800 rounded-lg border border-gray-700 cursor-pointer p-1"
            onChange={handleImageChange}
          />
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">Notes</label>
          <textarea
            rows={3}
            className="w-full p-3 rounded-lg bg-gray-800 border border-gray-700 text-white text-sm focus:ring-indigo-500"
            placeholder="Incident details..."
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
          ></textarea>
        </div>

        <Button
          type="submit"
          variant="primary"
          className="w-full py-4 text-lg font-bold"
          disabled={selectedViolationTypes.length === 0 || !imageFile || isSubmitting}
        >
          {isSubmitting ? 'Submitting Report...' : 'File Report'}
        </Button>
      </form>

      <Modal
        isOpen={isViolationSelectModalOpen}
        onClose={() => setIsViolationSelectModalOpen(false)}
        title="Violation Types"
        size="sm"
        footer={
