// Initialize Gemini API client strictly from process.env.API_KEY
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Simulate network delay
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

/**
 * Robust wrapper for Gemini API calls with exponential backoff for 429/500 errors.
 */
async function callGeminiWithRetry<T>(fn: (ai: any) => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError: any;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const ai = getAI();
      return await fn(ai);
    } catch (error: any) {
      lastError = error;
      const errorMsg = error?.message || "";
      const isQuotaError = errorMsg.includes('429') || errorMsg.includes('RESOURCE_EXHAUSTED') || errorMsg.includes('quota');
      const isRetryable = isQuotaError || errorMsg.includes('500') || errorMsg.includes('503');

      if (isRetryable && attempt < maxRetries) {
        const waitTime = Math.pow(2, attempt) * 1000 + Math.random() * 1000;
        console.warn(`Gemini API Quota/Server error. Retrying in ${Math.round(waitTime)}ms... (Attempt ${attempt + 1}/${maxRetries})`);
        await delay(waitTime);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

export interface PaginatedCases {
  cases: Case[];
  pagination: PaginationInfo;
}

export interface DetectionResult {
  violationDetected: boolean;
  violationType?: ViolationType;
  confidence?: number;
  plateText?: string;
  detectionArea?: {
    x: number;
    y: number;
    width: number;
    height: number;
  };
}

export interface AssignResult {
  success: boolean;
  case?: Case;
