// Initialize Gemini API client strictly from process.env.API_KEY
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

// Simulate network delay
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

/**
 * Robust wrapper for Gemini API calls with exponential backoff for 429/500 errors.
 */
async function callGeminiWithRetry<T>(fn: (ai: any) => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError: any;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const ai = getAI();
      return await fn(ai);
    } catch (error: any) {
      lastError = error;
      const errorMsg = error?.message || "";
      const isQuotaError = errorMsg.includes('429') || errorMsg.includes('RESOURCE_EXHAUSTED') || errorMsg.includes('quota');
      const isRetryable = isQuotaError || errorMsg.includes('500') || errorMsg.includes('503');

      if (isRetryable && attempt < maxRetries) {
        const waitTime = Math.pow(2, attempt) * 1000 + Math.random() * 1000;
        console.warn(`Gemini API Quota/Server error. Retrying in ${Math.round(waitTime)}ms... (Attempt ${attempt + 1}/${maxRetries})`);
        await delay(waitTime);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

export interface TrafficInfo {
  summary: string;
  sources: { title: string; uri: string }[];
}

/**
 * Uses Google Maps Grounding to fetch nearby traffic congestion info.
 */
export const fetchTrafficGrounding = async (location: LatLng): Promise<TrafficInfo> => {
  return callGeminiWithRetry(async (ai) => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: "Identify all major traffic jams, road closures, and heavy congestion within a 5km radius of my current location. Be specific about street names and the severity of delays.",
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        }
      },
    });

    const summary = response.text || "No specific traffic data available for this area.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const sources = chunks
      .filter((chunk: any) => chunk.maps?.uri)
      .map((chunk: any) => ({
        title: chunk.maps.title || "Traffic Alert Location",
        uri: chunk.maps.uri
      }));

    return { summary, sources };
  }).catch(err => {
    console.error("Traffic grounding error:", err);
    return { 
      summary: "Unable to retrieve real-time traffic data at this moment.", 
      sources: [] 
    };
  });
};

