async function ensureBase64(input: string): Promise<string | null> {
  if (!input) return null;
  if (input.startsWith('data:')) {
    const parts = input.split(',');
    return parts.length > 1 ? parts[1] : null;
  }
  if (input.startsWith('http')) {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000);
      const response = await fetch(input, { signal: controller.signal });
      clearTimeout(timeoutId);
      if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
      const blob = await response.blob();
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const result = reader.result as string;
          resolve(result.split(',')[1]);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Failed to fetch image "${input}" for base64 conversion:`, e);
      return null;
    }
  }
  return input;
}

export const detectViolationWithGemini = async (imageBase64: string): Promise<DetectionResult> => {
  return callGeminiWithRetry(async (ai) => {
    const cleanBase64 = await ensureBase64(imageBase64);
    if (!cleanBase64) return { violationDetected: false };

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            text: `Analyze this traffic camera frame. Detect violations like RED_LIGHT_JUMP, NO_HELMET, TRIPLE_RIDING, NO_SEATBELT, WRONG_WAY, PHONE_IN_HAND, STOP_LINE_OVERRUN, SPEEDING, or ILLEGAL_PARKING. 
            If a violation is found, identify the type and provide a bounding box (detectionArea) in normalized coordinates (0-100). 
            Also extract the license plate text if visible.`
          },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: cleanBase64,
            },
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            violationDetected: { type: Type.BOOLEAN },
            violationType: { type: Type.STRING, enum: Object.values(ViolationType) },
            confidence: { type: Type.NUMBER },
            plateText: { type: Type.STRING },
            detectionArea: {
              type: Type.OBJECT,
              properties: {
                x: { type: Type.NUMBER },
                y: { type: Type.NUMBER },
                width: { type: Type.NUMBER },
                height: { type: Type.NUMBER },
              },
              required: ["x", "y", "width", "height"]
            }
          },
          required: ["violationDetected"]
        }
      },
    });

    return JSON.parse(response.text || '{}') as DetectionResult;
  }).catch(err => {
    console.error("Detection final error:", err);
    return { violationDetected: false };
  });
};

export const fetchCases = async (filters: FilterOptions, pagination: { page: number; pageSize: number }): Promise<PaginatedCases> => {
  await delay(500); 
  let filteredCases = [...MOCK_CASES];
  if (filters.status) filteredCases = filteredCases.filter(c => c.status === filters.status);
  if (filters.violationType) filteredCases = filteredCases.filter(c => c.violationTypes.includes(filters.violationType!));
  if (filters.confidenceMin !== undefined) filteredCases = filteredCases.filter(c => c.confidence >= filters.confidenceMin!);
  if (filters.locationSearch) {
    const searchLower = filters.locationSearch.toLowerCase();
    filteredCases = filteredCases.filter(c => c.location.placeName.toLowerCase().includes(searchLower));
  }
  if (filters.createdAtAfter) {
    const afterDate = new Date(filters.createdAtAfter);
    filteredCases = filteredCases.filter(c => new Date(c.createdAt) >= afterDate);
  }
  if (filters.createdAtBefore) {
    const beforeDate = new Date(filters.createdAtBefore);
    const endOfDayBeforeDate = new Date(beforeDate);
    endOfDayBeforeDate.setHours(23, 59, 59, 999);
    filteredCases = filteredCases.filter(c => new Date(c.createdAt) <= endOfDayBeforeDate);
  }
  if (filters.searchTerm) {
    const termLower = filters.searchTerm.toLowerCase();
    filteredCases = filteredCases.filter(c =>
      c.id.toLowerCase().includes(termLower) ||
      c.plateText.toLowerCase().includes(termLower) ||
      c.location.placeName.toLowerCase().includes(termLower) ||
      c.violationTypes.some(vt => vt.toLowerCase().includes(termLower))
    );
  }
  filteredCases.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  const totalItems = filteredCases.length;
  const totalPages = Math.ceil(totalItems / pagination.pageSize);
  const startIndex = (pagination.page - 1) * pagination.pageSize;
  const endIndex = startIndex + pagination.pageSize;
  const paginatedCases = filteredCases.slice(startIndex, endIndex);
  return {
    cases: paginatedCases,
    pagination: { page: pagination.page, pageSize: pagination.pageSize, totalItems, totalPages },
  };
};

export const fetchCaseById = async (id: string): Promise<Case | undefined> => {
  await delay(300); 
  return MOCK_CASES.find(c => c.id === id);
};

export const updateCaseStatus = async (id: string, status: CaseStatus): Promise<Case | undefined> => {
  await delay(200); 
  const caseIndex = MOCK_CASES.findIndex(c => c.id === id);
  if (caseIndex > -1) {
    MOCK_CASES[caseIndex].status = status;
    const newLog: AuditLog = {
      id: `audit-${id}-${MOCK_AUDIT_LOGS.length + 1}`,
      caseId: id,
      action: `Status Updated to ${status}`,
      actorId: MOCK_USERS[0].id, 
      notes: `Case status changed to ${status}`,
      ts: new Date().toISOString(),
    };
    MOCK_AUDIT_LOGS.push(newLog);
    return MOCK_CASES[caseIndex];
  }
  return undefined;
};

export const assignCase = async (id: string, userId: string): Promise<AssignResult> => {
  await delay(200); 
  const caseIndex = MOCK_CASES.findIndex(c => c.id === id);
  const assignee = MOCK_USERS.find(u => u.id === userId);
  if (caseIndex > -1 && assignee) {
    MOCK_CASES[caseIndex].status = CaseStatus.ASSIGNED;
    const newLog: AuditLog = {
      id: `audit-${id}-${MOCK_AUDIT_LOGS.length + 1}`,
      caseId: id,
      action: `Case Assigned to ${assignee.email}`,
      actorId: MOCK_USERS[0].id, 
      notes: `Assigned to ${assignee.unit}`,
      ts: new Date().toISOString(),
    };
    MOCK_AUDIT_LOGS.push(newLog);
    return {
      success: true,
      case: MOCK_CASES[caseIndex],
      message: `Case ${id} successfully assigned to ${assignee.unit} (${assignee.email}).`
    };
  }
  return { success: false, message: `Failed to assign case ${id}. User or case not found.` };
};

export const fetchUsersByRole = async (role: UserRole): Promise<User[]> => {
  await delay(100);
  return MOCK_USERS.filter(u => u.role === role);
};

export const searchUsers = async (searchTerm: string): Promise<User[]> => {
  await delay(300); 
  if (!searchTerm) return [];
  const termLower = searchTerm.toLowerCase();
  return MOCK_USERS.filter(user =>
    user.id.toLowerCase().includes(termLower) ||
    user.email.toLowerCase().includes(termLower) ||
    user.role.toLowerCase().includes(termLower) ||
    user.unit.toLowerCase().includes(termLower) ||
    (user.phone && user.phone.toLowerCase().includes(termLower))
  );
};

export const fetchAuditLogsForCase = async (caseId: string): Promise<AuditLog[]> => {
  await delay(100);
  return MOCK_AUDIT_LOGS.filter(log => log.caseId === caseId).sort((a, b) => new Date(a.ts).getTime() - new Date(b.ts).getTime());
};

export const analyzeContentWithGemini = async (prompt: string, imageBase64?: string): Promise<string> => {
  return callGeminiWithRetry(async (ai) => {
    const contents: any[] = [{ text: prompt }];
    if (imageBase64) {
      const cleanBase64 = await ensureBase64(imageBase64);
      if (cleanBase64) {
        contents.push({ inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } });
      }
    }
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: contents },
    });
    return response.text || "No response received.";
  }).catch(err => {
    const msg = err?.message || "";
    if (msg.includes('429') || msg.includes('RESOURCE_EXHAUSTED')) {
      return "AI Quota Exceeded. Please wait a minute or ensure your API key is properly configured.";
    }
    return `Analysis failed: ${msg}`;
  });
};

export const ingestCase = async (caseData: Case): Promise<Case> => {
