  const newCase = { ...caseData, id: `case-${Date.now()}-${Math.random().toString(36).substring(2, 7)}` };
  MOCK_CASES.unshift(newCase); 
  const newLog: AuditLog = {
    id: `audit-${newCase.id}-001`,
    caseId: newCase.id,
    action: 'Case Ingested (AI Detected)',
    actorId: newCase.recorderId,
    notes: 'Automatically detected and submitted from mobile app',
    ts: newCase.createdAt,
  };
  MOCK_AUDIT_LOGS.push(newLog);
  return newCase;
};

export const ingestManualReport = async (reportData: ManualReport): Promise<Case> => {
  await delay(500); 
  const newCase: Case = {
    id: `case-${Date.now()}-${Math.random().toString(36).substring(2, 7)}`,
    createdAt: reportData.timestamp,
    status: CaseStatus.PENDING_REVIEW, 
    violationTypes: reportData.violationType, 
    confidence: 0.99, 
    plateText: 'UNKNOWN', 
    plateConfidence: 0,
    location: reportData.location ? { ...reportData.location, geoHash: 'manual', placeName: 'Manual Report Location' } : { latitude: 0, longitude: 0, geoHash: 'manual', placeName: 'Unknown Manual Location' },
    deviceId: 'manual-device', 
    recorderId: reportData.reporterId,
    mediaUrls: [reportData.imageBase64], 
    rulesMatched: ['Manual-Report'],
    duplicateOf: null,
  };
  MOCK_CASES.unshift(newCase); 
  const newLog: AuditLog = {
    id: `audit-${newCase.id}-001`,
    caseId: newCase.id,
    action: 'Manual Report Submitted',
    actorId: reportData.reporterId,
    notes: reportData.notes || 'Submitted manually from mobile app',
    ts: newCase.createdAt,
  };
  MOCK_AUDIT_LOGS.push(newLog);
  return newCase;
};

export const acceptAllPendingCases = async (): Promise<{ success: number; failed: number }> => {
  await delay(1000); 
  let successCount = 0;
  let failedCount = 0;
  for (let i = 0; i < MOCK_CASES.length; i++) {
    if (MOCK_CASES[i].status === CaseStatus.PENDING_REVIEW) {
      try {
        MOCK_CASES[i].status = CaseStatus.ACCEPTED;
        const newLog: AuditLog = {
          id: `audit-${MOCK_CASES[i].id}-${MOCK_AUDIT_LOGS.length + 1}`,
          caseId: MOCK_CASES[i].id,
          action: `Status Updated to ${CaseStatus.ACCEPTED}`,
          actorId: MOCK_USERS[0].id, 
          notes: 'Accepted all pending cases via bulk action',
          ts: new Date().toISOString(),
        };
        MOCK_AUDIT_LOGS.push(newLog);
        successCount++;
      } catch (error) {
        failedCount++;
      }
    }
  }
  return { success: successCount, failed: failedCount };
};

import React, { useState, useEffect, useCallback } from 'react';
import { LatLng } from '../types';
import { fetchTrafficGrounding, TrafficInfo } from '../services/api';
import LoadingSpinner from '../components/LoadingSpinner';
import Button from '../components/Button';

const TrafficMapView: React.FC = () => {
  const [location, setLocation] = useState<LatLng | null>(null);
  const [trafficInfo, setTrafficInfo] = useState<TrafficInfo | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const updateTraffic = useCallback(async (currentLoc: LatLng) => {
    setIsLoading(true);
    setError(null);
    try {
      const info = await fetchTrafficGrounding(currentLoc);
      setTrafficInfo(info);
    } catch (err) {
      setError("Failed to analyze traffic. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const loc = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
          setLocation(loc);
          updateTraffic(loc);
        },
        () => setError("Could not determine your location."),
        { enableHighAccuracy: true }
      );
    }
  }, [updateTraffic]);

  return (
    <div className="p-4 bg-gray-900 min-h-full text-white pb-24">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold">Traffic Jam Monitor</h2>
        {location && (
          <Button 
            variant="outline" 
            size="sm" 
            onClick={() => updateTraffic(location)} 
            disabled={isLoading}
            className="!py-1"
          >
            {isLoading ? 'Syncing...' : 'Refresh Radar'}
          </Button>
        )}
