interface MobileAppProps {
  loggedInUser: User; // User object for the logged-in user
  onLogout: () => void; // Function to handle logout
}

const MobileApp: React.FC<MobileAppProps> = ({ loggedInUser, onLogout }) => {
  const [cameraPermissionGranted, setCameraPermissionGranted] = useState<boolean | null>(null);
  const [locationPermissionGranted, setLocationPermissionGranted] = useState<boolean | null>(null);

  const navigate = useNavigate();
  const location = useLocation();

  const requestPermissions = useCallback(async () => {
    try {
      // Request Camera Permission
      const cameraStatus = await navigator.permissions.query({ name: 'camera' as PermissionName });
      if (cameraStatus.state === 'granted') {
        setCameraPermissionGranted(true);
      } else {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
        stream.getTracks().forEach(track => track.stop()); // Stop immediate stream after permission
        setCameraPermissionGranted(true);
      }
    } catch (error) {
      console.error('Camera permission denied:', error);
      setCameraPermissionGranted(false);
    }

    try {
      // Request Geolocation Permission
      const geoStatus = await navigator.permissions.query({ name: 'geolocation' as PermissionName });
      if (geoStatus.state === 'granted') {
        setLocationPermissionGranted(true);
      } else {
        const position = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject);
        });
        if (position) {
          setLocationPermissionGranted(true);
        }
      }
    } catch (error) {
      console.error('Geolocation permission denied:', error);
      setLocationPermissionGranted(false);
    }
  }, []);

  useEffect(() => {
    requestPermissions();
  }, [requestPermissions]);

  const onPermissionRetry = () => {
    setCameraPermissionGranted(null);
    setLocationPermissionGranted(null);
    requestPermissions();
  };

  if (cameraPermissionGranted === null || locationPermissionGranted === null) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gray-900 p-4 text-center text-white">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mb-4"></div>
        <p className="text-lg">Requesting camera and location permissions...</p>
      </div>
    );
  }

  const allPermissionsGranted = cameraPermissionGranted && locationPermissionGranted;

  if (!allPermissionsGranted) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gray-900 p-4 text-center text-white">
        <h2 className="text-2xl font-bold text-red-500 mb-4">Permissions Required</h2>
        <p className="mb-4">
          This app needs camera and geolocation access to detect and report traffic violations.
          Please grant permissions to continue.
        </p>
        <button 
          onClick={onPermissionRetry} 
          className="bg-indigo-600 hover:bg-indigo-700 text-white font-medium rounded-md px-4 py-2 text-base transition duration-150 ease-in-out focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
          aria-label="Retry Permissions"
        >
          Retry Permissions
        </button>
      </div>
    );
  }

  // If permissions are granted, show the main app content directly
  return (
    <div className="relative flex flex-col h-screen overflow-hidden">
      {/* Mobile Header with Logout */}
      <header className="bg-indigo-800 p-4 flex items-center justify-between shadow-md z-10">
        <h1 className="text-xl font-bold text-white">M-Traffic Cop</h1>
        <button 
          onClick={onLogout} 
          className="text-white text-sm font-medium bg-transparent hover:bg-transparent focus:outline-none focus:ring-0"
          aria-label="Log out"
        >
          Log out
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto bg-gray-900 pb-16 hide-scrollbar">
        <Routes>
          <Route path="/" element={<CameraView recorderId={loggedInUser.id} />} />
          <Route path="/traffic" element={<TrafficMapView />} />
          <Route path="/report" element={<ManualReportForm recorderId={loggedInUser.id} />} />
          <Route path="/cases" element={<SubmittedCasesView />} />
          <Route path="/chatbot" element={<ChatbotPage />} /> {/* New Chatbot Route */}
          <Route path="/profile" element={<ProfilePage loggedInUser={loggedInUser} />} />
        </Routes>
      </main>

      {/* Mobile Navigation Bar */}
      <nav className="fixed bottom-0 left-0 w-full bg-indigo-700 text-white shadow-lg z-20">
        <ul className="flex justify-around items-center h-16">
          <li>
            <button
              className={`flex flex-col items-center text-xs p-1 bg-transparent hover:bg-transparent focus:outline-none focus:ring-0 ${location.pathname === '/' ? 'text-white' : 'text-indigo-200'}`}
              onClick={() => navigate('/')}
              aria-label="Camera"
            >
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6.827 6.175A2.31 2.31 0 0 1 5.186 7.23c-.38.054-.757.112-1.134.175C2.999 7.58 2.25 8.507 2.25 9.574V18a2.25 2.25 0 0 0 2.25 2.25h15.5a2.25 2.25 0 0 0 2.25-2.25V9.574c0-1.067-.75-1.994-1.802-2.169a47.865 47.865 0 0 0-1.134-.175 2.31 2.31 0 0 1-1.64-1.055l-.822-1.316a2.192 2.192 0 0 0-1.736-1.039 48.774 48.774 0 0 0-5.232 0 2.192 2.192 0 0 0-1.736 1.04z" />
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 9a3.75 3.75 0 1 0 0 7.5A3.75 3.75 0 0 0 12 9z" />
