              </svg>
              Traffic
            </button>
          </li>
          <li>
            <button
              className={`flex flex-col items-center text-xs p-1 bg-transparent hover:bg-transparent focus:outline-none focus:ring-0 ${location.pathname === '/report' ? 'text-white' : 'text-indigo-200'}`}
              onClick={() => navigate('/report')}
              aria-label="Report"
            >
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 0 0-3.375-3.375h-1.5A1.125 1.125 0 0 1 13.5 7.125v-1.5a3.375 3.375 0 0 0-3.375-3.375H8.25m0 12.75h.008v.008H8.25m.375 0a.375.375 0 1 1-.75 0 .375.375 0 0 1 .75 0Zm.375 3v-6m-3 0h6m-3 0a9 9 0 1 1-9-9c0 1.62.45 3.112 1.25 4.334L7.25 10.5m0 0l-1.5 1.5m1.5-1.5-.75.75V4.385A2.625 2.625 0 0 1 9.875 1.75h4.25c1.246 0 2.25.992 2.25 2.215v3.15c0 .62.504 1.125 1.125 1.125H20.25a2.625 2.625 0 0 1 2.625 2.625v4.25c0 1.246-.992 2.25-2.215 2.25h-3.15a1.125 1.125 0 0 1-1.125-1.125V19.5" />
              </svg>
