                <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 0 0-3.375-3.375h-1.5A1.125 1.125 0 0 1 13.5 7.125v-1.5a3.375 3.375 0 0 0-3.375-3.375H8.25M9 16.5H6.5v-4.75a.75.75 0 0 1 .75-.75h2.5c.331 0 .6-.269.6-.6V9c0-.621-.504-1.125-1.125-1.125h-2.25c-.516 0-.932-.397-.974-.91V2.25a.75.75 0 0 1 .75-.75h5.5c.331 0 .6.269.6.6v.75a.75.75 0 0 1-.75.75H10.5M19.5 14.25H21.75a.75.75 0 0 1 .75.75v4.5a.75.75 0 0 1-.75.75h-5.5a.75.75 0 0 1-.75-.75v-3.75c0-.621.504-1.125 1.125-1.125H18" />
