    const video = videoRef.current;
    if (!canvas || !video || video.paused || isAnalyzing || detectedCase) return;

    setIsAnalyzing(true);
    if (!isManual) lastDetectionTimeRef.current = Date.now();

    try {
      const location = await getCurrentLocation();
      const imageData = canvas.toDataURL('image/jpeg', 0.8);
      const result = await detectViolationWithGemini(imageData);

      if (result.violationDetected && result.violationType) {
        const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
          id: '',
          createdAt: new Date().toISOString(),
          status: CaseStatus.DRAFT,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.85,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: result.plateText ? 0.92 : 0,
          location: {
            latitude: location?.latitude || 0,
            longitude: location?.longitude || 0,
            geoHash: isManual ? 'manual-scan' : 'ai-gen',
            placeName: isManual ? 'Manual Scan Location' : 'Detected Location',
          },
          deviceId: 'm-traffic-cop-001',
          recorderId: recorderId,
          mediaUrls: [imageData],
          rulesMatched: [isManual ? 'Manual-AI-Trigger' : 'Gemini-Vision-Detection'],
          duplicateOf: null,
          detectionArea: result.detectionArea,
        };
        setDetectedCase(newCase);
      }
    } catch (error) {
      console.error("AI Detection Error:", error);
    } finally {
      setIsAnalyzing(false);
    }
  }, [isAnalyzing, detectedCase, getCurrentLocation, recorderId]);

  const triggerSpeedingViolation = async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing) return;
    hasTriggeredSpeedingRef.current = true;
    setIsAnalyzing(true);
    try {
      const location = await getCurrentLocation();
      const imageData = canvas.toDataURL('image/jpeg', 0.9);
      const result = await detectViolationWithGemini(imageData);
      const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
        id: '',
        createdAt: new Date().toISOString(),
        status: CaseStatus.DRAFT,
        violationTypes: [ViolationType.SPEEDING],
        confidence: 0.98,
        plateText: result.plateText || 'UNKNOWN',
        plateConfidence: result.plateText ? 0.95 : 0,
        location: {
          latitude: location?.latitude || 0,
          longitude: location?.longitude || 0,
          geoHash: 'speed-trigger',
          placeName: `Speeding Detected at ${currentSpeed} km/h`,
        },
        deviceId: 'm-traffic-cop-001',
        recorderId: recorderId,
        mediaUrls: [imageData],
        rulesMatched: [`Speeding-GPS-${currentSpeed}kmh`],
        duplicateOf: null,
        detectionArea: result.detectionArea,
      };
      setDetectedCase(newCase);
    } catch (error) {
      console.error("Speeding Detection Error:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    if (!isMediaReady || detectedCase || isAnalyzing || isSpeeding) return;
    const runDetectionCycle = async () => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current < detectionIntervalMs) return;
      await performDetection(false);
    };
    const interval = setInterval(runDetectionCycle, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, detectedCase, isAnalyzing, isSpeeding, performDetection]);

  const handleApproveCase = useCallback(async () => {
    if (!detectedCase) return;
    try {
      const { detectionArea, ...caseToSubmit } = detectedCase; 
      const finalCase = { ...caseToSubmit, status: CaseStatus.PENDING_REVIEW };
      await ingestCase(finalCase);
      setDetectedCase(null);
    } catch (error) {
      console.error('Error submitting case:', error);
    }
  }, [detectedCase]);

  const handleDismissCase = useCallback(() => {
    setDetectedCase(null);
  }, []);

  const handleZoomChange = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
    const newZoom = parseFloat(event.target.value);
    if (videoRef.current && videoTrackRef.current && zoomCapabilities) {
        try {
            await videoTrackRef.current.applyConstraints({ advanced: [{ zoom: newZoom }] });
            setZoomLevel(newZoom);
        } catch (error) {
            console.error('Error applying zoom constraints:', error);
        }
    }
  }, [zoomCapabilities]);

  return (
    <div className="relative h-full w-full bg-black flex flex-col justify-center items-center overflow-hidden">
      <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover"></video>
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

      {/* Dynamic Status Badges */}
      <div className="absolute top-8 left-4 right-4 flex justify-between pointer-events-none z-20">
        {isAnalyzing && (
          <div className="bg-indigo-600 text-white text-sm px-4 py-2 rounded-full flex items-center shadow-lg animate-pulse">
            <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full mr-3"></div>
            Analyzing Violation & Location...
          </div>
        )}
        {!isAnalyzing && !detectedCase && isMediaReady && (
          <div className="bg-gray-900 bg-opacity-60 text-white text-xs px-3 py-1 rounded-full flex items-center shadow-md">
            <span className="flex h-2 w-2 mr-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
            </span>
            Vision AI: Precise Monitoring
          </div>
        )}
      </div>

      {!isCameraActive && (
        <div className="absolute inset-0 bg-gray-900 bg-opacity-80 flex flex-col items-center justify-center text-white text-lg">
          <LoadingSpinner />
          <p className="mt-4 font-medium">Initializing Vision AI...</p>
        </div>
      )}

      {zoomCapabilities && zoomLevel !== null && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-gray-800 bg-opacity-75 px-4 py-2 rounded-full flex items-center space-x-2 shadow-lg z-40">
          <span className="text-white text-xs font-bold">ZOOM</span>
          <input
            type="range"
            min={zoomCapabilities.min}
            max={zoomCapabilities.max}
            step={zoomCapabilities.step}
            value={zoomLevel}
            onChange={handleZoomChange}
            className="w-32 h-2 rounded-lg appearance-none cursor-pointer bg-gray-700 accent-indigo-500"
          />
          <span className="text-white text-sm tabular-nums">{zoomLevel.toFixed(1)}x</span>
        </div>
      )}

      {detectedCase && (
        <CaseReviewOverlay
          caseData={detectedCase}
          onApprove={handleApproveCase}
          onDismiss={handleDismissCase}
        />
      )}
    </div>
  );
};

