/**
 * Uses Google Maps Grounding to fetch nearby traffic congestion info.
 */
export const fetchTrafficGrounding = async (location: LatLng): Promise<TrafficInfo> => {
  return callGeminiWithRetry(async (ai) => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: "Identify all major traffic jams, road closures, and heavy congestion within a 5km radius of my current location. Be specific about street names and the severity of delays.",
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        }
      },
    });

    const summary = response.text || "No specific traffic data available for this area.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const sources = chunks
      .filter((chunk: any) => chunk.maps?.uri)
      .map((chunk: any) => ({
        title: chunk.maps.title || "Traffic Alert Location",
        uri: chunk.maps.uri
      }));

    return { summary, sources };
  }).catch(err => {
    console.error("Traffic grounding error:", err);
    return { 
      summary: "Unable to retrieve real-time traffic data at this moment.", 
      sources: [] 
    };
  });
};

