export const updateCaseStatus = async (id: string, status: CaseStatus): Promise<Case | undefined> => {
  await delay(200); 
  const caseIndex = MOCK_CASES.findIndex(c => c.id === id);
  if (caseIndex > -1) {
    MOCK_CASES[caseIndex].status = status;
    const newLog: AuditLog = {
      id: `audit-${id}-${MOCK_AUDIT_LOGS.length + 1}`,
      caseId: id,
      action: `Status Updated to ${status}`,
      actorId: MOCK_USERS[0].id, 
      notes: `Case status changed to ${status}`,
      ts: new Date().toISOString(),
    };
    MOCK_AUDIT_LOGS.push(newLog);
    return MOCK_CASES[caseIndex];
  }
  return undefined;
};

export const assignCase = async (id: string, userId: string): Promise<AssignResult> => {
  await delay(200); 
  const caseIndex = MOCK_CASES.findIndex(c => c.id === id);
  const assignee = MOCK_USERS.find(u => u.id === userId);
  if (caseIndex > -1 && assignee) {
    MOCK_CASES[caseIndex].status = CaseStatus.ASSIGNED;
    const newLog: AuditLog = {
      id: `audit-${id}-${MOCK_AUDIT_LOGS.length + 1}`,
      caseId: id,
      action: `Case Assigned to ${assignee.email}`,
      actorId: MOCK_USERS[0].id, 
      notes: `Assigned to ${assignee.unit}`,
      ts: new Date().toISOString(),
    };
    MOCK_AUDIT_LOGS.push(newLog);
    return {
      success: true,
      case: MOCK_CASES[caseIndex],
      message: `Case ${id} successfully assigned to ${assignee.unit} (${assignee.email}).`
    };
  }
  return { success: false, message: `Failed to assign case ${id}. User or case not found.` };
};

