                   <div className="mt-3 flex items-center space-x-4">
                      <div>
                        <p className="text-[10px] text-gray-500 font-bold uppercase mb-0.5">Shift</p>
                        <p className="text-xs font-semibold text-gray-200">{officer.shift}</p>
