import React, { useState } from 'react';
import Button from '../components/Button';
import { MOCK_USER_CREDENTIALS, MOCK_USERS } from '../constants';
import { User } from '../types';

interface LoginPageProps {
  onLogin: (user: User) => void;
  onLoginError: (message: string) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onLoginError }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);

  const handleLoginSubmit = async (e?: React.FormEvent, overrideUser?: string, overridePass?: string) => {
    e?.preventDefault();
    setIsAuthenticating(true);
    setLocalError(null);

    // Simulate API call delay
    await new Promise(resolve => setTimeout(resolve, 800));

    const finalUsername = (overrideUser || username).trim();
    const finalPassword = (overridePass || password).trim();

    const userCredential = MOCK_USER_CREDENTIALS[finalUsername as keyof typeof MOCK_USER_CREDENTIALS];

    if (userCredential && userCredential.password === finalPassword) {
      const foundUser = MOCK_USERS.find(u => u.id === userCredential.id);
      if (foundUser) {
        onLogin(foundUser);
      } else {
        const msg = 'Authentication failed: User data not found.';
        setLocalError(msg);
        onLoginError(msg);
      }
    } else {
      const msg = 'Invalid username or password.';
      setLocalError(msg);
      onLoginError(msg);
    }
    setIsAuthenticating(false);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-900 p-6 text-white">
      <div className="w-full max-w-sm">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center p-3 bg-indigo-600 rounded-2xl shadow-lg shadow-indigo-500/20 mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-8 h-8 text-white">
              <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.744c0 3.89 1.88 7.342 4.783 9.474a11.861 11.861 0 0 0 14.434 0c2.903-2.132 4.783-5.584 4.783-9.474a11.99 11.99 0 0 0-.598-3.744A11.959 11.959 0 0 1 12 2.714Z" />
            </svg>
          </div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight">M-Traffic Cop</h2>
          <p className="text-gray-400 mt-2">Vision AI Enforcement Platform</p>
        </div>

        <div className="bg-gray-800 p-8 rounded-2xl shadow-2xl border border-gray-700/50">
          <form onSubmit={handleLoginSubmit} className="space-y-5">
            {localError && (
              <div className="bg-red-900/20 border border-red-500/50 text-red-400 text-sm p-3 rounded-lg text-center animate-shake">
                {localError}
              </div>
            )}

            <div>
              <label htmlFor="username" className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">
                Username
              </label>
              <input
                type="text"
                id="username"
                className="w-full p-3 rounded-xl bg-gray-900 border border-gray-700 text-white placeholder-gray-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                placeholder="Username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                required
                autoComplete="username"
              />
            </div>

            <div>
              <label htmlFor="password" className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">
                Password
              </label>
              <input
                type="password"
                id="password"
                className="w-full p-3 rounded-xl bg-gray-900 border border-gray-700 text-white placeholder-gray-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                autoComplete="current-password"
              />
            </div>

            <Button
              type="submit"
              variant="primary"
              className="w-full py-3.5 text-base font-bold shadow-lg shadow-indigo-600/20 rounded-xl"
              disabled={isAuthenticating}
            >
              {isAuthenticating ? (
                <span className="flex items-center justify-center">
                  <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Authenticating...
                </span>
              ) : 'Sign In'}
            </Button>
          </form>
        </div>

        <p className="mt-8 text-center text-gray-500 text-sm">
          Secure Login for Departmental Use Only
        </p>
      </div>
    </div>
  );
};

