  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthenticating(true);
    setLocalError(null);

    await new Promise(resolve => setTimeout(resolve, 800));
    const cred = MOCK_USER_CREDENTIALS[username as keyof typeof MOCK_USER_CREDENTIALS];

    if (cred && cred.password === password) {
      const foundUser = MOCK_USERS.find(u => u.id === cred.id);
      if (foundUser) {
        onLogin(foundUser);
      } else {
        setLocalError('Authentication failed: User data not found.');
      }
    } else {
      setLocalError('Invalid username or password.');
    }
    setIsAuthenticating(false);
  };

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!regName || !regDob || !regAadhaar) {
      setLocalError('Please fill in all identity fields.');
      return;
    }
    if (regAadhaar.length !== 12) {
      setLocalError('Aadhaar must be exactly 12 digits.');
      return;
    }

    setIsAuthenticating(true);
    setLocalError(null);
    try {
      const newUser = await signUpUser({
        name: regName,
        dob: regDob,
        aadhaar: regAadhaar,
        role: regRole
      });
      onLogin(newUser);
    } catch (err) {
      setLocalError('Registration failed. Please try again.');
    } finally {
      setIsAuthenticating(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-900 p-6 text-white font-sans">
      <div className="w-full max-w-sm">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center p-4 bg-indigo-600 rounded-3xl shadow-2xl mb-4 transform hover:scale-105 transition-transform duration-300">
            <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.744c0 3.89 1.88 7.342 4.783 9.474a11.861 11.861 0 0 0 14.434 0c2.903-2.132 4.783-5.584 4.783-9.474a11.99 11.99 0 0 0-.598-3.744A11.959 11.959 0 0 1 12 2.714Z" />
            </svg>
          </div>
          <h2 className="text-4xl font-black text-white tracking-tight">M-Traffic Cop</h2>
          <p className="text-indigo-400 mt-2 font-bold tracking-widest uppercase text-[10px]">Vision AI Enforcement Solution</p>
        </div>

        <div className="bg-gray-800 p-8 rounded-[40px] border border-gray-700/50 shadow-2xl backdrop-blur-sm">
          <div className="flex p-1 bg-gray-950 rounded-2xl mb-8 border border-gray-800">
            <button
              onClick={() => { setIsSignUp(false); setLocalError(null); }}
              className={`flex-1 py-2.5 text-xs font-black rounded-xl transition-all ${!isSignUp ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
            >
              SIGN IN
            </button>
            <button
              onClick={() => { setIsSignUp(true); setLocalError(null); }}
              className={`flex-1 py-2.5 text-xs font-black rounded-xl transition-all ${isSignUp ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
            >
              SIGN UP
            </button>
          </div>

          <form onSubmit={isSignUp ? handleSignUp : handleSignIn} className="space-y-5">
            {localError && (
              <div className="bg-red-500/10 border border-red-500/50 text-red-400 text-[11px] p-3 rounded-2xl text-center font-bold animate-pulse">
                {localError}
              </div>
            )}

            {isSignUp ? (
              <>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Identity Name</label>
                  <input
                    type="text"
                    className="w-full p-4 rounded-2xl bg-gray-900 border border-gray-700 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder-gray-600"
                    placeholder="Full Legal Name"
                    value={regName}
                    onChange={(e) => setRegName(e.target.value)}
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Date of Birth</label>
                  <input
                    type="date"
                    className="w-full p-4 rounded-2xl bg-gray-900 border border-gray-700 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all color-scheme-dark"
                    value={regDob}
                    onChange={(e) => setRegDob(e.target.value)}
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Aadhaar Card Number</label>
                  <input
                    type="number"
                    maxLength={12}
                    className="w-full p-4 rounded-2xl bg-gray-900 border border-gray-700 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder-gray-600"
                    placeholder="12 Digit Unique ID"
                    value={regAadhaar}
                    onChange={(e) => setRegAadhaar(e.target.value.slice(0, 12))}
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Organizational Role</label>
                  <div className="grid grid-cols-1 gap-2">
                    {[UserRole.PUBLIC, UserRole.POLICE, UserRole.ADMIN].map(role => (
                      <button
                        key={role}
                        type="button"
                        onClick={() => setRegRole(role)}
