                      >
                        {role === UserRole.PUBLIC ? 'General Public' : role === UserRole.POLICE ? 'Police Officer' : 'Administrator'}
                      </button>
                    ))}
                  </div>
                </div>
              </>
            ) : (
              <>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Username / Badge</label>
                  <input
                    type="text"
                    className="w-full p-4 rounded-2xl bg-gray-900 border border-gray-700 text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder-gray-600"
                    placeholder="Enter ID"
