import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import { Case, CaseStatus, AuditLog, User, UserRole } from '../types';
import { VIOLATION_TYPE_COLORS } from '../constants';
import { fetchCaseById, updateCaseStatus, fetchAuditLogsForCase, assignCase, fetchAllPotentialAssignees, analyzeContentWithGemini, fetchUserById } from '../services/api';
import LoadingSpinner from './LoadingSpinner';
import MapComponent from './MapComponent';
import Button from './Button';
import Modal from './Modal';
import Dropdown from './Dropdown';

interface CaseDetailProps {
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseDetail: React.FC<CaseDetailProps> = ({ onNotify }) => {
  const { id } = useParams<{ id: string }>();
  const [caseDetail, setCaseDetail] = useState<Case | null>(null);
  const [assigneeUser, setAssigneeUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);

  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [generatingSummary, setGeneratingSummary] = useState(false);

  const fetchCaseAndLogs = useCallback(async () => {
    setLoading(true);
    if (!id) return;
    try {
      const fetchedCase = await fetchCaseById(id);
      if (fetchedCase) {
        setCaseDetail(fetchedCase);
        if (fetchedCase.assigneeId) {
          const user = await fetchUserById(fetchedCase.assigneeId);
          if (user) setAssigneeUser(user);
        }
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
      }
    } catch (error) {
      console.error('Failed to fetch case details:', error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchCaseAndLogs();
  }, [fetchCaseAndLogs]);

  const generateCaseSummary = useCallback(async (force = false) => {
    if (!caseDetail || auditLogs.length === 0) return;
    if (aiSummary && !force) return;

    setGeneratingSummary(true);
    const prompt = `Summarize this traffic violation case professionally: Case ID ${caseDetail.id}, Violation: ${caseDetail.violationTypes.join(', ')}. Plate: ${caseDetail.plateText}. Status: ${caseDetail.status}.`;

    try {
      const summary = await analyzeContentWithGemini(prompt, caseDetail.mediaUrls[0]);
      setAiSummary(summary);
    } catch (err) {
      setAiSummary("AI Analysis failed.");
    } finally {
      setGeneratingSummary(false);
    }
  }, [caseDetail, auditLogs, aiSummary]);

  const openAssignModal = async () => {
    try {
      const potential = await fetchAllPotentialAssignees();
      setAssignees(potential);
      if (potential.length > 0) setSelectedAssigneeId(potential[0].id);
      setIsAssignModalOpen(true);
    } catch (error) {
      onNotify?.('Failed to load users.', 'error');
    }
  };

  const handleAssignCase = async () => {
    if (!id || !selectedAssigneeId) return;
    setLoading(true);
    try {
      const result = await assignCase(id, selectedAssigneeId);
      if (result.success) {
        if (result.case) setCaseDetail(result.case);
        const user = await fetchUserById(selectedAssigneeId);
        if (user) setAssigneeUser(user);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(result.message, 'success');
      }
    } catch (error) {
      onNotify?.('Failed to assign case.', 'error');
    } finally {
      setLoading(false);
      setIsAssignModalOpen(false);
    }
  };

  if (loading) return <LoadingSpinner />;
  if (!caseDetail) return <div className="p-6 text-center text-red-500">Case not found.</div>;

  return (
    <div className="flex-1 p-6 bg-gray-900 text-white pb-24">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold">Case ID: {caseDetail.id}</h2>
        <div className="flex space-x-2">
           <Button variant="secondary" onClick={openAssignModal}>Assign</Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-gray-800 rounded-2xl p-6 border border-gray-700">
          <h3 className="text-lg font-bold mb-4 uppercase tracking-widest text-indigo-400">Violation Details</h3>
          <div className="grid grid-cols-2 gap-4 text-sm">
            <div>
              <p className="text-gray-500 font-bold uppercase text-[10px]">Current Status</p>
              <span className="inline-block mt-1 px-3 py-1 rounded-full bg-indigo-600 text-[11px] font-black uppercase">{caseDetail.status}</span>
            </div>
            {assigneeUser && (
              <div>
                <p className="text-gray-500 font-bold uppercase text-[10px]">Assigned Personnel</p>
                <div className="mt-1 flex items-center space-x-2">
                   <p className="font-bold text-white">{assigneeUser.name}</p>
                   <span className={`text-[9px] px-1.5 py-0.5 rounded-md font-black uppercase ${assigneeUser.role === UserRole.PUBLIC ? 'bg-gray-700 text-gray-400' : 'bg-green-600/20 text-green-400'}`}>
                     {assigneeUser.role === UserRole.PUBLIC ? 'General Public' : 'Officer'}
                   </span>
                </div>
              </div>
            )}
          </div>
          <div className="mt-6">
             <p className="text-gray-500 font-bold uppercase text-[10px] mb-2">Detected Infractions</p>
             <div className="flex flex-wrap gap-2">
               {caseDetail.violationTypes.map(type => (
                 <span key={type} className={`px-4 py-1.5 rounded-full text-xs font-bold uppercase border border-white/10 ${VIOLATION_TYPE_COLORS[type]} text-white shadow-lg`}>
                   {type.replace(/_/g, ' ')}
                 </span>
               ))}
             </div>
          </div>
        </div>

        <div className="lg:col-span-1 space-y-6">
          <div className="bg-gray-800 rounded-2xl p-4 border border-gray-700">
            <h3 className="text-sm font-bold text-indigo-400 mb-3 uppercase">Visual Evidence</h3>
            <img src={caseDetail.mediaUrls[0]} className="w-full h-48 object-cover rounded-xl border border-white/5" alt="Evidence" />
          </div>
          <div className="bg-gray-800 rounded-2xl p-4 border border-gray-700">
            <h3 className="text-sm font-bold text-indigo-400 mb-3 uppercase">Geolocation</h3>
            <MapComponent location={caseDetail.location} placeName={caseDetail.location.placeName} />
          </div>
        </div>
      </div>

      <Modal
        isOpen={isAssignModalOpen}
        onClose={() => setIsAssignModalOpen(false)}
        title="Deployment Selection"
        size="xs"
        footer={<Button onClick={handleAssignCase} disabled={!selectedAssigneeId}>Deploy Task</Button>}
      >
        <p className="mb-4 text-xs text-gray-400 font-bold uppercase tracking-widest">Select Agent (Personnel or Public)</p>
        <Dropdown
          options={assignees.map(u => ({ label: `[${u.role === UserRole.PUBLIC ? 'PUBLIC' : 'POLICE'}] ${u.name}`, value: u.id }))}
          selectedValue={selectedAssigneeId}
          onSelect={setSelectedAssigneeId}
          buttonClassName="w-full !bg-gray-900"
          menuClassName="!bg-gray-950"
        />
      </Modal>
    </div>
  );
};

