import React, { useState } from 'react';
import Button from '../components/Button';
import { authenticateUser, signUpUser } from '../services/api';
import { User, UserRole } from '../types';

interface LoginPageProps {
  onLogin: (user: User) => void;
  onLoginError: (message: string) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onLoginError }) => {
  const [isSignUp, setIsSignUp] = useState(false);

  // Sign In State
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  // Sign Up State
  const [regName, setRegName] = useState('');
  const [regDob, setRegDob] = useState('');
  const [regAadhaar, setRegAadhaar] = useState('');
  const [regRole, setRegRole] = useState<UserRole>(UserRole.PUBLIC);
  const [regPassword, setRegPassword] = useState('123'); // Default password for simplicity

  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthenticating(true);
    setLocalError(null);

    try {
      const user = await authenticateUser(username, password);
      if (user) {
        onLogin(user);
      } else {
        setLocalError('Invalid username or password. Try "murugan_222" / "123".');
      }
    } catch (err) {
      setLocalError('Authentication service error.');
    } finally {
      setIsAuthenticating(false);
    }
  };

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!regName || !regDob || !regAadhaar) {
      setLocalError('Please fill in all identity fields.');
      return;
    }
    if (regAadhaar.length !== 12) {
      setLocalError('Aadhaar must be exactly 12 digits.');
      return;
    }

    setIsAuthenticating(true);
    setLocalError(null);
    try {
      const newUser = await signUpUser({
        name: regName,
        dob: regDob,
        aadhaar: regAadhaar,
        role: regRole,
        password: regPassword
      });
      onLogin(newUser);
    } catch (err) {
      setLocalError('Registration failed. Please try again.');
    } finally {
      setIsAuthenticating(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-950 p-6 text-white font-sans selection:bg-indigo-500 selection:text-white">
      <div className="w-full max-w-sm">
        {/* Header Section */}
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center p-5 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-[2.5rem] shadow-[0_20px_50px_rgba(79,70,229,0.3)] mb-6 transform hover:scale-105 transition-transform duration-500">
            <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.744c0 3.89 1.88 7.342 4.783 9.474a11.861 11.861 0 0 0 14.434 0c2.903-2.132 4.783-5.584 4.783-9.474a11.99 11.99 0 0 0-.598-3.744A11.959 11.959 0 0 1 12 2.714Z" />
            </svg>
          </div>
          <h2 className="text-5xl font-black text-white tracking-tighter mb-2">M-Traffic</h2>
          <div className="flex items-center justify-center space-x-2">
            <span className="h-[2px] w-6 bg-indigo-500 rounded-full"></span>
            <p className="text-indigo-400 font-black tracking-[0.3em] uppercase text-[10px]">Vision AI Shield</p>
            <span className="h-[2px] w-6 bg-indigo-500 rounded-full"></span>
          </div>
        </div>

        {/* Card Section */}
        <div className="bg-gray-900 p-8 rounded-[3rem] border border-gray-800/50 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

          <h3 className="text-2xl font-black mb-8 text-center text-white">
            {isSignUp ? 'New Officer Enrollment' : 'Welcome Back'}
          </h3>

          <form onSubmit={isSignUp ? handleSignUp : handleSignIn} className="space-y-6">
