import React, { useState, useEffect, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import { Case, CaseStatus, AuditLog, User, UserRole } from '../types';
import { VIOLATION_TYPE_COLORS } from '../constants';
import { fetchCaseById, updateCaseStatus, fetchAuditLogsForCase, assignCase, fetchAllPotentialAssignees, analyzeContentWithGemini, fetchUserById } from '../services/api';
import LoadingSpinner from './LoadingSpinner';
import MapComponent from './MapComponent';
import Button from './Button';
import Modal from './Modal';
import Dropdown from './Dropdown';

interface CaseDetailProps {
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseDetail: React.FC<CaseDetailProps> = ({ onNotify }) => {
  const { id } = useParams<{ id: string }>();
  const [caseDetail, setCaseDetail] = useState<Case | null>(null);
  const [assigneeUser, setAssigneeUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);

  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [generatingSummary, setGeneratingSummary] = useState(false);

  const fetchCaseAndLogs = useCallback(async () => {
    setLoading(true);
    if (!id) return;
    try {
      const fetchedCase = await fetchCaseById(id);
      if (fetchedCase) {
        setCaseDetail(fetchedCase);
        if (fetchedCase.assigneeId) {
          const user = await fetchUserById(fetchedCase.assigneeId);
          if (user) setAssigneeUser(user);
        }
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
      }
    } catch (error) {
      console.error('Failed to fetch case details:', error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchCaseAndLogs();
  }, [fetchCaseAndLogs]);

  const openAssignModal = async () => {
    try {
      const potential = await fetchAllPotentialAssignees();
      setAssignees(potential);
      if (potential.length > 0) setSelectedAssigneeId(potential[0].id);
      setIsAssignModalOpen(true);
    } catch (error) {
      onNotify?.('Failed to load users.', 'error');
    }
  };

  const handleAssignCase = async () => {
    if (!id || !selectedAssigneeId) return;
    setLoading(true);
    try {
      const result = await assignCase(id, selectedAssigneeId);
      if (result.success) {
        if (result.case) setCaseDetail(result.case);
        const user = await fetchUserById(selectedAssigneeId);
        if (user) setAssigneeUser(user);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(result.message, 'success');
      }
    } catch (error) {
      console.error('Failed to assign case:', error);
      onNotify?.('Failed to assign case.', 'error');
    } finally {
      setLoading(false);
      setIsAssignModalOpen(false);
    }
  };

  if (loading) return <LoadingSpinner />;
  if (!caseDetail) return <div className="p-6 text-center text-red-500">Case not found.</div>;

  return (
    <div className="flex-1 p-6 bg-gray-900 text-white pb-24">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-black tracking-tight">Case ID: <span className="text-indigo-400">{caseDetail.id}</span></h2>
        <div className="flex space-x-2">
           <Button variant="secondary" onClick={openAssignModal} className="font-black uppercase text-xs tracking-widest rounded-xl">Assign Task</Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Violation & Personnel Column */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-gray-800 rounded-[2.5rem] p-8 border border-gray-700/50 shadow-2xl">
            <h3 className="text-[10px] font-black mb-6 uppercase tracking-[0.2em] text-indigo-400">Violation Diagnostics</h3>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
              <div className="space-y-4">
                <div className="p-4 bg-gray-900 rounded-2xl border border-gray-700">
                  <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mb-2">Live Status</p>
                  <span className={`inline-block px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider ${
                    caseDetail.status === CaseStatus.ACCEPTED ? 'bg-green-500/20 text-green-400 border border-green-500/20' :
                    caseDetail.status === CaseStatus.REJECTED ? 'bg-red-500/20 text-red-400 border border-red-500/20' :
                    'bg-indigo-500/20 text-indigo-400 border border-indigo-500/20'
                  }`}>
                    {caseDetail.status.replace(/_/g, ' ')}
                  </span>
                </div>

                <div className="p-4 bg-gray-900 rounded-2xl border border-gray-700">
                  <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mb-2">Confidence Level</p>
                  <div className="flex items-center space-x-3">
                    <div className="flex-1 h-2 bg-gray-800 rounded-full overflow-hidden">
                      <div className="h-full bg-indigo-500" style={{ width: `${caseDetail.confidence * 100}%` }}></div>
                    </div>
                    <span className="text-xs font-black text-indigo-400">{(caseDetail.confidence * 100).toFixed(0)}%</span>
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {assigneeUser && (
                  <div className="p-4 bg-indigo-950/20 rounded-2xl border border-indigo-500/20">
                    <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mb-2">Assigned Personnel</p>
                    <div className="flex items-center space-x-3">
                       <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center font-black text-white uppercase text-sm">
                         {assigneeUser.name.charAt(0)}
                       </div>
                       <div>
                         <p className="text-sm font-bold text-white">{assigneeUser.name}</p>
                         <span className={`text-[9px] px-2 py-0.5 rounded-lg font-black uppercase tracking-wider ${
                           assigneeUser.role === UserRole.PUBLIC ? 'bg-gray-700 text-gray-400' : 'bg-green-600/20 text-green-400'
                         }`}>
                           {assigneeUser.role === UserRole.PUBLIC ? 'General Public' : 'Police Officer'}
                         </span>
                       </div>
                    </div>
                  </div>
                )}

                <div className="p-4 bg-gray-900 rounded-2xl border border-gray-700">
                  <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mb-2">License Plate</p>
                  <p className="text-2xl font-black text-white tracking-tighter uppercase">{caseDetail.plateText}</p>
                </div>
              </div>
            </div>

            <div className="mt-8">
               <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest mb-3 ml-1">Detected Infractions</p>
               <div className="flex flex-wrap gap-3">
                 {caseDetail.violationTypes.map(type => (
                   <span key={type} className={`px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-white/5 ${VIOLATION_TYPE_COLORS[type]} text-white shadow-xl transform hover:scale-105 transition-all`}>
                     {type.replace(/_/g, ' ')}
                   </span>
                 ))}
               </div>
            </div>
          </div>
        </div>

        {/* Evidence Column */}
        <div className="lg:col-span-1 space-y-8">
          <div className="bg-gray-800 rounded-[2.5rem] p-6 border border-gray-700/50 shadow-2xl">
            <h3 className="text-[10px] font-black text-indigo-400 mb-4 uppercase tracking-[0.2em]">Visual Evidence</h3>
            <div className="relative rounded-[2rem] overflow-hidden border-4 border-gray-900 bg-black group">
              <img src={caseDetail.mediaUrls[0]} className="w-full h-64 object-cover transform group-hover:scale-110 transition-transform duration-700" alt="Evidence" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none"></div>
              <div className="absolute bottom-4 left-4 bg-black/80 px-3 py-1 rounded-full text-[9px] font-black uppercase text-indigo-300">Cam: {caseDetail.deviceId}</div>
            </div>
          </div>

          <div className="bg-gray-800 rounded-[2.5rem] p-6 border border-gray-700/50 shadow-2xl">
            <h3 className="text-[10px] font-black text-indigo-400 mb-4 uppercase tracking-[0.2em]">Satellite Grounding</h3>
            <div className="rounded-[2rem] overflow-hidden border-4 border-gray-900">
              <MapComponent location={caseDetail.location} placeName={caseDetail.location.placeName} />
            </div>
          </div>
        </div>
      </div>

      <Modal
        isOpen={isAssignModalOpen}
        onClose={() => setIsAssignModalOpen(false)}
        title="Deployment Command"
        size="xs"
        footer={<Button onClick={handleAssignCase} disabled={!selectedAssigneeId} className="w-full font-black uppercase tracking-widest py-4">Execute Deployment</Button>}
      >
        <p className="mb-4 text-[10px] text-gray-400 font-black uppercase tracking-widest text-center">Select Personnel for Field Review</p>
        <div className="space-y-4">
          <Dropdown
            options={assignees.map(u => ({ label: `[${u.role === UserRole.PUBLIC ? 'PUBLIC' : 'POLICE'}] ${u.name}`, value: u.id }))}
            selectedValue={selectedAssigneeId}
            onSelect={setSelectedAssigneeId}
            buttonClassName="w-full !bg-gray-950 !rounded-2xl !p-5 !border-gray-800"
            menuClassName="!bg-gray-950 !border-gray-800 !rounded-2xl"
          />
          <p className="text-[9px] text-gray-600 text-center uppercase font-black tracking-widest italic leading-relaxed px-4">
            Deployment will notify the agent and sync case evidence to their secure edge device.
          </p>
        </div>
      </Modal>
    </div>
  );
};

export default CaseDetail;

