            <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.744c0 3.89 1.88 7.342 4.783 9.474a11.861 11.861 0 0 0 14.434 0c2.903-2.132 4.783-5.584 4.783-9.474a11.99 11.99 0 0 0-.598-3.744A11.959 11.959 0 0 1 12 2.714Z" />
            </svg>
          </div>
          <h2 className="text-5xl font-black text-white tracking-tighter mb-2">M-Traffic</h2>
          <div className="flex items-center justify-center space-x-2">
            <span className="h-[2px] w-6 bg-indigo-500 rounded-full"></span>
            <p className="text-indigo-400 font-black tracking-[0.3em] uppercase text-[10px]">Vision AI Shield</p>
