let SESSION_OFFICER_DUTIES: OfficerDuty[] = [
  { id: '1', userId: 'public-murugan', name: 'Murugan R.', badgeId: 'TP-1022', status: DutyStatus.ON_DUTY, shift: '08:00 - 16:00', assignedUnit: 'Anna Salai Patrol', location: 'Mount Road' },
  { id: '2', userId: 'user-3', name: 'Sharma V.', badgeId: 'TP-0988', status: DutyStatus.ON_DUTY, shift: '06:00 - 14:00', assignedUnit: 'Patrol Unit 1', location: 'MG Road' },
];

async function callGeminiWithRetry<T>(fn: (ai: any) => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError: any;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const ai = getAI();
      return await fn(ai);
    } catch (error: any) {
      lastError = error;
      if (attempt < maxRetries) {
        await delay(Math.pow(2, attempt) * 1000);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

// Added authenticateUser to handle sign-in logic
export const authenticateUser = async (username: string, password: string): Promise<User | undefined> => {
  await delay(500);
  const creds = (MOCK_USER_CREDENTIALS as any)[username];
  if (creds && creds.password === password) {
    return SESSION_USERS.find(u => u.id === creds.id);
  }
  // Check users registered in this session
  return SESSION_USERS.find(u => (u.name === username || u.id === username) && u.password === password);
};

