];

async function callGeminiWithRetry<T>(fn: (ai: any) => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError: any;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const ai = getAI();
      return await fn(ai);
    } catch (error: any) {
      lastError = error;
      if (attempt < maxRetries) {
        await delay(Math.pow(2, attempt) * 1000);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

