export const fetchUsersByRole = async (role: UserRole): Promise<User[]> => {
  await delay(100);
  return SESSION_USERS.filter(u => u.role === role);
};

export const fetchAllPotentialAssignees = async (): Promise<User[]> => {
  await delay(200);
  // Allow assigning to both Police and Public as per prompt logic
  return SESSION_USERS.filter(u => u.role !== UserRole.ADMIN);
};

export const fetchUserById = async (id: string): Promise<User | undefined> => {
  return SESSION_USERS.find(u => u.id === id);
};

// Added fetchCaseById to resolve error in CaseDetail.tsx
export const fetchCaseById = async (id: string): Promise<Case | undefined> => {
  await delay(200);
  return MOCK_CASES.find(c => c.id === id);
};

export const fetchCases = async (filters: FilterOptions, pagination: { page: number; pageSize: number }): Promise<PaginatedCases> => {
  await delay(300);
  let res = [...MOCK_CASES];
  if (filters.searchTerm) {
    const term = filters.searchTerm.toLowerCase();
    res = res.filter(c => c.id.toLowerCase().includes(term) || c.plateText.toLowerCase().includes(term));
  }
  const totalItems = res.length;
  const startIndex = (pagination.page - 1) * pagination.pageSize;
  return {
    cases: res.slice(startIndex, startIndex + pagination.pageSize),
    pagination: { ...pagination, totalItems, totalPages: Math.ceil(totalItems / pagination.pageSize) }
  };
};

export const updateCaseStatus = async (id: string, status: CaseStatus) => {
  const c = MOCK_CASES.find(x => x.id === id);
  if (c) c.status = status;
  return c;
};

export const assignCase = async (id: string, userId: string) => {
  const c = MOCK_CASES.find(x => x.id === id);
  if (c) {
    c.status = CaseStatus.ASSIGNED;
    c.assigneeId = userId;
  }
  return { success: true, case: c, message: "Assigned successfully." };
};

export const fetchAuditLogsForCase = async (caseId: string) => MOCK_AUDIT_LOGS.filter(l => l.caseId === caseId);

export const detectViolationWithGemini = async (imageBase64: string) => {
  return callGeminiWithRetry(async (ai) => {
    const data = imageBase64.includes(',') ? imageBase64.split(',')[1] : imageBase64;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [{ text: "Analyze traffic frame for violations." }, { inlineData: { mimeType: 'image/jpeg', data } }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            violationDetected: { type: Type.BOOLEAN },
            violationType: { type: Type.STRING, enum: Object.values(ViolationType) },
            confidence: { type: Type.NUMBER },
            plateText: { type: Type.STRING },
            detectionArea: { type: Type.OBJECT, properties: { x: { type: Type.NUMBER }, y: { type: Type.NUMBER }, width: { type: Type.NUMBER }, height: { type: Type.NUMBER } } }
          }
        }
      },
    });
    return JSON.parse(response.text || '{}');
  });
};

export const analyzeContentWithGemini = async (p: string, i?: string) => {
  const ai = getAI();
  const parts: any[] = [{ text: p }];
  if (i) parts.push({ inlineData: { mimeType: 'image/jpeg', data: i.split(',')[1] || i } });
  const r = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: { parts } });
  return r.text || "No analysis.";
};

export const ingestCase = async (c: Case) => { MOCK_CASES.unshift(c); return c; };
export const ingestManualReport = async (r: ManualReport) => {
  const c: Case = {
    id: `m-${Date.now()}`, createdAt: r.timestamp, status: CaseStatus.PENDING_REVIEW, violationTypes: r.violationType, confidence: 1, plateText: 'N/A', plateConfidence: 0,
    location: r.location ? { ...r.location, geoHash: 'm', placeName: 'Manual' } : { latitude: 0, longitude: 0, geoHash: 'm', placeName: 'Manual' },
    deviceId: 'm', recorderId: r.reporterId, mediaUrls: [r.imageBase64], rulesMatched: [], duplicateOf: null
  };
  MOCK_CASES.unshift(c);
  return c;
};

export const fetchTrafficGrounding = async (location: LatLng): Promise<TrafficInfo> => {
  return callGeminiWithRetry(async (ai) => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: "Identify all major traffic jams near my current location.",
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: { retrievalConfig: { latLng: { latitude: location.latitude, longitude: location.longitude } } }
      },
    });
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = chunks.filter((c: any) => c.maps?.uri).map((c: any) => ({ title: c.maps.title, uri: c.maps.uri }));
    return { summary: response.text || "No data.", sources };
  }).catch(() => ({ summary: "Unavailable.", sources: [] }));
};

export const acceptAllPendingCases = async () => {
  MOCK_CASES.forEach(c => { if (c.status === CaseStatus.PENDING_REVIEW) c.status = CaseStatus.ACCEPTED; });
  return { success: 1, failed: 0 };
};

export const searchUsers = async (term: string) => SESSION_USERS.filter(u => u.name.toLowerCase().includes(term.toLowerCase()));

import React, { useState } from 'react';
import Button from '../components/Button';
import { MOCK_USER_CREDENTIALS, MOCK_USERS } from '../constants';
import { signUpUser } from '../services/api';
import { User, UserRole } from '../types';

interface LoginPageProps {
  onLogin: (user: User) => void;
  onLoginError: (message: string) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onLoginError }) => {
  const [isSignUp, setIsSignUp] = useState(false);

  // Sign In State
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  // Sign Up State
  const [regName, setRegName] = useState('');
  const [regDob, setRegDob] = useState('');
  const [regAadhaar, setRegAadhaar] = useState('');
  const [regRole, setRegRole] = useState<UserRole>(UserRole.PUBLIC);
  const [regPassword, setRegPassword] = useState('');

  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [localError, setLocalError] = useState<string | null>(null);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthenticating(true);
    setLocalError(null);

    await new Promise(resolve => setTimeout(resolve, 800));
    const cred = MOCK_USER_CREDENTIALS[username as keyof typeof MOCK_USER_CREDENTIALS];

    if (cred && cred.password === password) {
      const foundUser = MOCK_USERS.find(u => u.id === cred.id);
      if (foundUser) {
        onLogin(foundUser);
      } else {
        setLocalError('User data not found.');
      }
    } else {
      setLocalError('Invalid credentials.');
    }
    setIsAuthenticating(false);
  };

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!regName || !regDob || !regAadhaar || !regPassword) {
      setLocalError('Please fill all fields.');
      return;
    }
    if (regAadhaar.length !== 12) {
      setLocalError('Aadhaar must be 12 digits.');
      return;
    }

    setIsAuthenticating(true);
    setLocalError(null);
    try {
      const newUser = await signUpUser({
        name: regName,
        dob: regDob,
        aadhaar: regAadhaar,
        role: regRole,
        password: regPassword
      });
      onLogin(newUser);
    } catch (err) {
      setLocalError('Registration failed.');
    } finally {
      setIsAuthenticating(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-gray-900 p-6 text-white font-sans overflow-hidden">
      <div className="w-full max-w-[340px] flex flex-col items-center">
        {/* Header Section */}
        <div className="text-center mb-6">
          <div className="inline-flex items-center justify-center p-3 bg-indigo-600 rounded-2xl shadow-2xl mb-2 transform hover:scale-105 transition-transform duration-300">
            <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.744c0 3.89 1.88 7.342 4.783 9.474a11.861 11.861 0 0 0 14.434 0c2.903-2.132 4.783-5.584 4.783-9.474a11.99 11.99 0 0 0-.598-3.744A11.959 11.959 0 0 1 12 2.714Z" />
            </svg>
          </div>
          <h2 className="text-3xl font-black text-white tracking-tight">M-Traffic Cop</h2>
          <p className="text-indigo-400 font-bold tracking-[0.25em] uppercase text-[9px] mt-1">Vision AI Enforcement</p>
        </div>

        {/* Main Card */}
        <div className="w-full bg-gray-800 p-6 rounded-[36px] border border-gray-700/50 shadow-2xl backdrop-blur-md">
          <div className="flex p-1 bg-gray-950 rounded-2xl mb-6 border border-gray-800">
            <button
              onClick={() => { setIsSignUp(false); setLocalError(null); }}
              className={`flex-1 py-2 text-xs font-black rounded-xl transition-all duration-300 ${!isSignUp ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
            >
              SIGN IN
            </button>
            <button
              onClick={() => { setIsSignUp(true); setLocalError(null); }}
              className={`flex-1 py-2 text-xs font-black rounded-xl transition-all duration-300 ${isSignUp ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
            >
              SIGN UP
            </button>
          </div>

          <form onSubmit={isSignUp ? handleSignUp : handleSignIn} className="space-y-4">
            {localError && (
              <div className="bg-red-500/10 border border-red-500/30 text-red-400 text-[10px] p-2 rounded-xl text-center font-bold animate-pulse">
                {localError}
              </div>
            )}

            {isSignUp ? (
              <div className="space-y-3">
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 ml-1">Legal Name</label>
                  <input
                    type="text"
                    className="w-full p-3 rounded-xl bg-gray-900 border border-gray-700 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    placeholder="Enter your name"
                    value={regName}
                    onChange={(e) => setRegName(e.target.value)}
                    required
                  />
                </div>
                <div className="flex gap-3">
                  <div className="flex-1">
                    <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 ml-1">DOB</label>
                    <input
                      type="date"
                      className="w-full p-3 rounded-xl bg-gray-900 border border-gray-700 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none color-scheme-dark"
                      value={regDob}
                      onChange={(e) => setRegDob(e.target.value)}
                      required
                    />
                  </div>
                  <div className="flex-1">
                    <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 ml-1">Aadhaar</label>
                    <input
                      type="number"
                      className="w-full p-3 rounded-xl bg-gray-900 border border-gray-700 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                      placeholder="12 Digits"
                      value={regAadhaar}
                      onChange={(e) => setRegAadhaar(e.target.value.slice(0, 12))}
                      required
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 ml-1">User Role</label>
                  <div className="flex gap-2">
                    {[UserRole.PUBLIC, UserRole.POLICE].map(role => (
                      <button
