                        onClick={() => setRegRole(role)}
                        className={`flex-1 py-2 rounded-xl border text-[10px] font-black uppercase tracking-wider transition-all duration-300 ${regRole === role ? 'bg-indigo-600/20 border-indigo-500 text-white' : 'bg-gray-900 border-gray-700 text-gray-500 hover:border-gray-600'}`}
                      >
                        {role === UserRole.PUBLIC ? 'Public' : 'Police'}
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 ml-1">Set Security Key</label>
                  <input
                    type="password"
                    className="w-full p-3 rounded-xl bg-gray-900 border border-gray-700 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    placeholder="Create Password"
                    value={regPassword}
                    onChange={(e) => setRegPassword(e.target.value)}
                    required
                  />
                </div>
              </div>
            ) : (
              <div className="space-y-5 py-2">
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Access Identity</label>
                  <input
                    type="text"
                    className="w-full p-4 rounded-2xl bg-gray-900 border border-gray-700 text-white text-base focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    placeholder="Username or Badge ID"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    required
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5 ml-1">Security Key</label>
                  <input
                    type="password"
                    className="w-full p-4 rounded-2xl bg-gray-900 border border-gray-700 text-white text-base focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    placeholder="••••••••"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </div>
              </div>
            )}

            <Button
              type="submit"
              variant="primary"
              className="w-full py-4 text-xs font-black rounded-[24px] shadow-xl shadow-indigo-600/30 active:scale-95 transition-all mt-4"
              disabled={isAuthenticating}
            >
              {isAuthenticating ? 'PROCESSING...' : isSignUp ? 'CREATE SECURE ACCOUNT' : 'SECURE SIGN IN'}
            </Button>
          </form>
        </div>

        {/* Footer info */}
        <div className="mt-6 flex flex-col items-center space-y-3 opacity-20">
