interface MobileAppProps {
  loggedInUser: User;
  onLogout: () => void;
}

const MobileApp: React.FC<MobileAppProps> = ({ loggedInUser, onLogout }) => {
  const [cameraStatus, setCameraStatus] = useState<'pending' | 'granted' | 'denied'>('pending');
  const [locationStatus, setLocationStatus] = useState<'pending' | 'granted' | 'denied'>('pending');

  const navigate = useNavigate();
  const location = useLocation();

  const requestPermissions = useCallback(async () => {
    // Attempt Location first
    try {
      await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
      });
      setLocationStatus('granted');
    } catch (error) {
      console.warn('Location access failed:', error);
      setLocationStatus('denied');
    }

    // Attempt Camera
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      stream.getTracks().forEach(track => track.stop());
      setCameraStatus('granted');
    } catch (error) {
      console.warn('Camera access failed:', error);
      setCameraStatus('denied');
    }
  }, []);

  useEffect(() => {
    requestPermissions();
  }, [requestPermissions]);

  if (cameraStatus === 'pending' || locationStatus === 'pending') {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-black p-6 text-center text-white">
