import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Case, CaseStatus, LatLng, ViolationType } from '../types';
import { ingestCase, detectViolationWithGemini } from '../services/api';
import { SPEED_LIMIT_KMH } from '../constants';
import CaseReviewOverlay from './CaseReviewOverlay';
import LoadingSpinner from '../components/LoadingSpinner';

interface CameraViewProps {
  recorderId: string;
}

const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const videoTrackRef = useRef<MediaStreamTrack | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [detectedCase, setDetectedCase] = useState<(Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 8000; // Slower interval for stability

  // Speed related state
  const [currentSpeed, setCurrentSpeed] = useState<number>(0);
  const [isSpeeding, setIsSpeeding] = useState(false);
  const hasTriggeredSpeedingRef = useRef(false);

  const [zoomLevel, setZoomLevel] = useState<number | null>(null);
  const [zoomCapabilities, setZoomCapabilities] = useState<{ min: number; max: number; step: number } | null>(null);

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d', { willReadFrequently: true });
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight || video.paused || video.ended) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        // Drawing HUD Elements
        context.strokeStyle = 'rgba(79, 70, 229, 0.4)';
        context.lineWidth = 1;
        context.beginPath();
        context.moveTo(canvas.width / 2, 0);
        context.lineTo(canvas.width / 2, canvas.height);
        context.stroke();
        context.beginPath();
        context.moveTo(0, canvas.height / 2);
        context.lineTo(canvas.width, canvas.height / 2);
        context.stroke();

        if (detectedCase && detectedCase.detectionArea) {
          const { x, y, width, height } = detectedCase.detectionArea;
          const rectX = (x / 100) * canvas.width;
          const rectY = (y / 100) * canvas.height;
          const rectW = (width / 100) * canvas.width;
          const rectH = (height / 100) * canvas.height;

          context.strokeStyle = '#ef4444';
          context.lineWidth = 4;
          context.strokeRect(rectX, rectY, rectW, rectH);

          context.fillStyle = '#ef4444';
          context.font = 'bold 24px sans-serif';
          context.fillText(`[${detectedCase.violationTypes[0].replace(/_/g, ' ')}]`, rectX, rectY - 15);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [detectedCase]);

  const stopCamera = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (animationFrameId.current) {
      cancelAnimationFrame(animationFrameId.current);
      animationFrameId.current = null;
    }
    if (videoRef.current) {
      videoRef.current.pause();
      videoRef.current.srcObject = null;
    }
    videoTrackRef.current = null;
    setZoomCapabilities(null);
    setZoomLevel(null);
    setIsCameraActive(false);
    setIsMediaReady(false);
    setIsAnalyzing(false);
  }, []);

  useEffect(() => {
    let isActiveComponent = true;
    const setupCameraStream = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
        });
        if (!isActiveComponent) {
          mediaStream.getTracks().forEach(track => track.stop());
          return;
        }
        mediaStreamRef.current = mediaStream;
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          const videoTrack = mediaStream.getVideoTracks()[0];
          if (videoTrack) {
            videoTrackRef.current = videoTrack;
            try {
              const capabilities = videoTrack.getCapabilities() as any;
              if (capabilities.zoom) {
                setZoomCapabilities({
                  min: capabilities.zoom.min,
                  max: capabilities.zoom.max,
                  step: capabilities.zoom.step || 0.1,
                });
                setZoomLevel(capabilities.zoom.current || capabilities.zoom.min);
              }
            } catch(e) { console.warn("Zoom not supported", e); }
          }

          videoRef.current.onloadedmetadata = () => {
            videoRef.current?.play().then(() => {
              setIsCameraActive(true);
              setIsMediaReady(true);
              startDrawingLoop();
            });
          };
        }
      } catch (err) {
        console.error('Hardware error:', err);
      }
    };
    setupCameraStream();
    return () => { isActiveComponent = false; stopCamera(); };
  }, [startDrawingLoop, stopCamera]);

  useEffect(() => {
    if (!navigator.geolocation) return;
    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        const speedMps = position.coords.speed || 0;
        const speedKmh = Math.round(speedMps * 3.6);
        setCurrentSpeed(speedKmh);
        if (speedKmh > SPEED_LIMIT_KMH) {
          setIsSpeeding(true);
          if (!hasTriggeredSpeedingRef.current && isMediaReady && !isAnalyzing && !detectedCase) {
             // triggerSpeedingViolation logic...
          }
        } else {
          setIsSpeeding(false);
        }
      },
      (error) => console.error('GPS tracking error:', error),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, [isMediaReady, isAnalyzing, detectedCase]);

  const performDetection = useCallback(async (isManual = false) => {
    const canvas = canvasRef.current;
    const video = videoRef.current;
    if (!canvas || !video || video.paused || isAnalyzing || detectedCase) return;

    setIsAnalyzing(true);
    if (!isManual) lastDetectionTimeRef.current = Date.now();

    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.8);
      const result = await detectViolationWithGemini(imageData);

      if (result.violationDetected && result.violationType) {
        const newCase: (Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) = {
          id: `case-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: CaseStatus.DRAFT,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.85,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: result.plateText ? 0.92 : 0,
          location: {
            latitude: 0,
            longitude: 0,
            geoHash: isManual ? 'manual-scan' : 'ai-gen',
            placeName: isManual ? 'Field Evidence' : 'Automated Patrol',
          },
          deviceId: 'M-PATROL-1',
          recorderId: recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['Cloud-Vision-Core'],
          duplicateOf: null,
          detectionArea: result.detectionArea,
        };
        setDetectedCase(newCase);
      }
    } catch (error) {
      console.error("Analysis Failure:", error);
    } finally {
      setIsAnalyzing(false);
    }
  }, [isAnalyzing, detectedCase, recorderId]);

  useEffect(() => {
    if (!isMediaReady || detectedCase || isAnalyzing) return;
    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current >= detectionIntervalMs) {
        performDetection(false);
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, detectedCase, isAnalyzing, performDetection]);

  const handleZoomChange = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
    const newZoom = parseFloat(event.target.value);
    if (videoTrackRef.current && zoomCapabilities) {
        try {
            await videoTrackRef.current.applyConstraints({ advanced: [{ zoom: newZoom }] });
            setZoomLevel(newZoom);
        } catch (e) {}
    }
  }, [zoomCapabilities]);

  return (
    <div className="relative h-full w-full bg-black flex flex-col items-center justify-center">
      <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover grayscale opacity-60"></video>
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

      {/* Tactical Status Overlay */}
      <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between">
        <div className="flex justify-between items-start">
           <div className="space-y-1">
              <div className="flex items-center space-x-2">
                 <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                 <p className="text-[10px] font-black text-white uppercase tracking-widest">Patrol Active</p>
              </div>
              <p className="text-[9px] text-gray-500 font-mono tracking-tighter uppercase">Sensors: Active | Feed: Stream-01</p>
           </div>
           <div className="text-right">
              <p className="text-[10px] font-black text-white uppercase tracking-widest">Velocity</p>
              <p className={`text-3xl font-black ${isSpeeding ? 'text-red-500' : 'text-indigo-400'}`}>{currentSpeed} <span className="text-xs">KM/H</span></p>
           </div>
        </div>

        <div className="flex flex-col items-center">
           {isAnalyzing && (
             <div className="bg-indigo-600/90 backdrop-blur-md px-6 py-3 rounded-2xl border border-indigo-400/30 flex items-center space-x-3 shadow-2xl animate-pulse pointer-events-auto">
               <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
               <span className="text-xs font-black text-white uppercase tracking-widest">Analyzing Frame...</span>
             </div>
           )}
        </div>

        <div className="flex justify-between items-end">
           <div className="bg-black/50 backdrop-blur px-3 py-1.5 rounded-lg border border-white/10">
              <p className="text-[8px] text-gray-500 font-black uppercase mb-0.5">Device ID</p>
              <p className="text-[10px] text-white font-mono uppercase">PATROL-M1-SYS</p>
           </div>
           {!detectedCase && !isAnalyzing && (
              <button 
                onClick={() => performDetection(true)}
                className="pointer-events-auto w-16 h-16 bg-white/10 border-4 border-white rounded-full flex items-center justify-center active:scale-90 transition-all shadow-2xl"
              >
                 <div className="w-4 h-4 bg-red-500 rounded-full"></div>
              </button>
           )}
        </div>
      </div>

      {!isCameraActive && (
        <div className="absolute inset-0 bg-gray-950 flex flex-col items-center justify-center z-50">
           <LoadingSpinner />
           <p className="mt-4 text-xs font-black text-indigo-400 uppercase tracking-widest">Waking Sensors...</p>
        </div>
      )}

      {zoomCapabilities && zoomLevel !== null && (
        <div className="absolute right-4 top-1/2 -translate-y-1/2 flex flex-col items-center space-y-4 pointer-events-auto z-40 bg-black/40 p-2 rounded-full backdrop-blur">
          <input
            type="range"
            orient="vertical"
            min={zoomCapabilities.min}
            max={zoomCapabilities.max}
            step={zoomCapabilities.step}
            value={zoomLevel}
            onChange={handleZoomChange}
            className="h-32 accent-indigo-500 bg-gray-700/50 rounded-lg"
            style={{ writingMode: 'bt-lr' } as any}
          />
          <span className="text-[10px] font-black text-white tabular-nums">{zoomLevel.toFixed(1)}x</span>
        </div>
      )}

      {detectedCase && (
        <CaseReviewOverlay
          caseData={detectedCase}
          onApprove={async () => {
            const finalCase = { ...detectedCase, status: CaseStatus.PENDING_REVIEW };
            await ingestCase(finalCase);
            setDetectedCase(null);
          }}
          onDismiss={() => setDetectedCase(null)}
        />
      )}
    </div>
  );
};

