/**
 * Robust API Key Retrieval for Mobile/APK
 * Mobile WebViews often strip process.env. 
 * We check process.env first, then fallback to a window variable.
 */
const getApiKey = () => {
  return process.env.API_KEY || (window as any).FALLBACK_API_KEY || '';
};

const getAI = () => {
  const key = getApiKey();
  if (!key) {
    console.error("CRITICAL: API Key is missing. Detection will fail.");
  }
  return new GoogleGenAI({ apiKey: key });
};

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

let SESSION_USERS = [...MOCK_USERS];

async function callGeminiWithRetry<T>(fn: (ai: any) => Promise<T>, maxRetries = 2): Promise<T> {
  let lastError: any;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const ai = getAI();
      return await fn(ai);
    } catch (error: any) {
      lastError = error;
      console.warn(`Gemini Attempt ${attempt + 1} failed:`, error.message);
      // Specific check for APK network issues
      if (error.message?.includes('Failed to fetch')) {
        console.error("Network Error: Check if APK has INTERNET permission.");
      }
      if (attempt < maxRetries) {
        await delay(Math.pow(2, attempt) * 1000);
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

