          duplicateOf: null,
          detectionArea: result.detectionArea
        });
      }
    } catch (e) {
      console.error("Detection task failed:", e);
    } finally {
      setIsAnalyzing(false);
      lastDetectionTimeRef.current = Date.now();
    }
  }, [isAnalyzing, detectedCase, recorderId]);

  useEffect(() => {
    if (!isMediaReady || detectedCase) return;
    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current >= detectionIntervalMs) {
        performDetection(false);
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, detectedCase, performDetection]);

  return (
    <div className="relative h-full w-full bg-black">
      {cameraError ? (
        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
          <p className="text-red-500 font-bold mb-4 uppercase tracking-widest text-xs">System Error</p>
          <p className="text-white text-sm mb-8">{cameraError}</p>
          <button onClick={setupCamera} className="px-6 py-3 bg-indigo-600 rounded-xl font-black text-xs uppercase">Restart Sensors</button>
        </div>
      ) : (
        <>
          <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover grayscale opacity-40"></video>
          <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

          <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between">
            <div className="flex justify-between items-start">
               <div className="bg-black/40 backdrop-blur p-3 rounded-xl border border-white/10">
                  <div className="flex items-center space-x-2">
                     <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                     <p className="text-[10px] font-black text-white uppercase tracking-widest">Vision Online</p>
                  </div>
               </div>
               <div className="text-right bg-black/40 backdrop-blur p-3 rounded-xl border border-white/10">
                  <p className="text-[10px] font-black text-white uppercase tracking-widest">Velocity</p>
                  <p className="text-2xl font-black text-indigo-400">{currentSpeed} <span className="text-[10px]">KM/H</span></p>
               </div>
            </div>

            <div className="flex flex-col items-center">
               {isAnalyzing && (
                 <div className="bg-indigo-600 px-6 py-3 rounded-2xl shadow-2xl flex items-center space-x-3">
                   <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                   <span className="text-[10px] font-black text-white uppercase tracking-widest">Processing AI Frame...</span>
