               </button>
               {!detectedCase && !isAnalyzing && (
                  <button 
                    onClick={() => performDetection(true)}
                    className="w-20 h-20 bg-white/10 border-4 border-white rounded-full flex items-center justify-center active:scale-90 transition-all shadow-2xl"
                  >
                     <div className="w-6 h-6 bg-red-500 rounded-full shadow-[0_0_15px_rgba(239,68,68,0.8)]"></div>
                  </button>
               )}
               <div className="w-12"></div>
