        if (!video.videoWidth || !video.videoHeight || video.paused || video.ended) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        // Draw Bounding Box if a case is flagged
        if (flaggedCase && flaggedCase.detectionArea) {
          const { x, y, width, height } = flaggedCase.detectionArea;
          const rectX = (x / 100) * canvas.width;
          const rectY = (y / 100) * canvas.height;
          const rectW = (width / 100) * canvas.width;
          const rectH = (height / 100) * canvas.height;

          // Red Flag Indicator
          context.strokeStyle = '#ef4444';
          context.lineWidth = 4;
          context.strokeRect(rectX, rectY, rectW, rectH);

          // Shadow for text readability
          context.fillStyle = 'rgba(0,0,0,0.6)';
          context.fillRect(rectX, rectY - 30, rectW, 30);

          context.fillStyle = '#ffffff';
          context.font = 'bold 16px sans-serif';
          context.fillText(flaggedCase.violationTypes[0].replace(/_/g, ' '), rectX + 5, rectY - 10);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [flaggedCase]);

  const stopCamera = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
    if (videoRef.current) videoRef.current.srcObject = null;
    setIsCameraActive(false);
    setIsMediaReady(false);
  }, []);

  const setupCamera = useCallback(async () => {
    setCameraError(null);
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
      });
      mediaStreamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().then(() => {
            setIsCameraActive(true);
            setIsMediaReady(true);
            startDrawingLoop();
          });
        };
      }
    } catch (err: any) {
      console.error('Camera Hardware Error:', err);
      setCameraError(err.message || "Camera blocked.");
    }
  }, [startDrawingLoop]);

  useEffect(() => {
    setupCamera();
    return () => stopCamera();
  }, [setupCamera, stopCamera]);

  const performDetection = useCallback(async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing || flaggedCase) return;

    setIsAnalyzing(true);
    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.6);
      const result = await detectViolationWithGemini(imageData);

      if (result && result.violationDetected) {
        setFlaggedCase({
          id: `flag-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: CaseStatus.DRAFT,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.9,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: result.plateText ? 0.9 : 0,
          location: { latitude: 0, longitude: 0, geoHash: 'mob', placeName: 'Mobile Unit' },
          deviceId: 'M-VISION-X',
          recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['AI-Edge-Vision'],
          duplicateOf: null,
          detectionArea: result.detectionArea
        });
      }
    } catch (e) {
      console.error("AI Analysis encountered an error.");
    } finally {
      setIsAnalyzing(false);
      lastDetectionTimeRef.current = Date.now();
    }
  }, [isAnalyzing, flaggedCase, recorderId]);

  useEffect(() => {
    if (!isMediaReady || flaggedCase) return;
    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current >= detectionIntervalMs) {
        performDetection();
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, flaggedCase, performDetection]);

  const handleApprove = async () => {
    if (flaggedCase) {
      setIsAnalyzing(true); // Reuse analyzing state for submission UX
      await ingestCase({ ...flaggedCase, status: CaseStatus.PENDING_REVIEW });
      setFlaggedCase(null);
      setIsAnalyzing(false);
    }
  };

  const handleDecline = () => {
    setFlaggedCase(null);
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      {cameraError ? (
        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center bg-gray-950">
          <p className="text-red-500 font-black uppercase text-[10px] tracking-widest mb-4">Hardware Locked</p>
          <button onClick={setupCamera} className="px-8 py-3 bg-white text-black font-black text-[10px] uppercase rounded-full">Unlock Sensors</button>
        </div>
      ) : (
        <>
          <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover grayscale opacity-30"></video>
          <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

          {/* AI Status Indicators - Top Left */}
          <div className="absolute top-6 left-6 pointer-events-none">
            <div className="bg-black/80 backdrop-blur-xl px-4 py-2 rounded-2xl border border-white/10 flex items-center space-x-3 shadow-2xl">
              <div className={`w-2 h-2 rounded-full animate-pulse ${isAnalyzing ? 'bg-yellow-500' : 'bg-green-500'}`}></div>
              <span className="text-[11px] font-black text-white uppercase tracking-widest whitespace-nowrap">
                {isAnalyzing ? 'AI is analyzing' : 'AI is detecting'}
              </span>
            </div>
          </div>

          {/* Flagging Action Bar - Bottom */}
          {flaggedCase && (
            <div className="absolute bottom-10 left-6 right-6 z-50 animate-in fade-in slide-in-from-bottom-4 duration-300">
              <div className="bg-gray-950/95 backdrop-blur-2xl border border-white/10 rounded-[32px] p-6 shadow-2xl">
                <div className="mb-6">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-2">Flagged Violation</p>
                  <div className="flex items-end justify-between">
                    <div>
                      <h3 className="text-2xl font-black text-white uppercase tracking-tight">
                        {flaggedCase.violationTypes[0].replace(/_/g, ' ')}
                      </h3>
                      <p className="text-xs text-gray-500 font-mono mt-1">PLATE: {flaggedCase.plateText}</p>
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-gray-600 uppercase">Confidence</p>
                       <p className="text-lg font-black text-indigo-400">{(flaggedCase.confidence * 100).toFixed(0)}%</p>
                    </div>
                  </div>
                </div>

                <div className="flex space-x-4">
                  <button 
                    onClick={handleDecline}
                    className="flex-1 py-4 bg-gray-900 text-gray-400 font-black text-xs uppercase tracking-widest rounded-2xl border border-white/5 active:scale-95 transition-all"
                  >
                    Decline
                  </button>
                  <button 
                    onClick={handleApprove}
                    className="flex-1 py-4 bg-indigo-600 text-white font-black text-xs uppercase tracking-widest rounded-2xl shadow-xl shadow-indigo-600/20 active:scale-95 transition-all"
                  >
                    Approve
                  </button>
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {!isCameraActive && !cameraError && (
        <div className="absolute inset-0 bg-black flex flex-col items-center justify-center z-50">
           <LoadingSpinner />
           <p className="mt-4 text-[10px] font-black text-indigo-400 uppercase tracking-widest animate-pulse">Waking System...</p>
        </div>
      )}
    </div>
  );
};

