                className="w-full flex items-center justify-between bg-gray-900 border border-gray-700 text-white px-4 py-3 rounded-xl hover:border-indigo-500 transition-all text-sm"
              >
                <span className="truncate">
                    {selectedViolationTypes.length > 0
                        ? selectedViolationTypes.map(type => type.replace(/_/g, ' ')).join(', ')
                        : 'Select Violations'}
                </span>
                <svg className="h-4 w-4 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
              </button>
            </div>

            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2 ml-1">Incident Notes</label>
              <textarea
                rows={3}
                className="w-full p-4 rounded-xl bg-gray-900 border border-gray-700 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder-gray-600"
                placeholder="Describe the vehicle or situation..."
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
              ></textarea>
            </div>

            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2 ml-1">Visual Evidence</label>
              <div className="relative group">
                <input
                  type="file"
