import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Case, CaseStatus, LatLng, ViolationType } from '../types';
import { ingestCase, detectViolationWithGemini } from '../services/api';
import LoadingSpinner from '../components/LoadingSpinner';

interface CameraViewProps {
  recorderId: string;
}

const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);

  // Detection/Flagging State
  const [flaggedCase, setFlaggedCase] = useState<(Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 8000; 

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d', { willReadFrequently: true });
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight || video.paused || video.ended) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        // Draw Bounding Box if a case is flagged
        if (flaggedCase && flaggedCase.detectionArea) {
          const { x, y, width, height } = flaggedCase.detectionArea;
          const rectX = (x / 100) * canvas.width;
          const rectY = (y / 100) * canvas.height;
          const rectW = (width / 100) * canvas.width;
          const rectH = (height / 100) * canvas.height;

          context.strokeStyle = '#ef4444';
          context.lineWidth = 4;
          context.strokeRect(rectX, rectY, rectW, rectH);

          context.fillStyle = 'rgba(0,0,0,0.6)';
          context.fillRect(rectX, rectY - 30, rectW, 30);

          context.fillStyle = '#ffffff';
          context.font = 'bold 16px sans-serif';
          context.fillText(flaggedCase.violationTypes[0].replace(/_/g, ' '), rectX + 5, rectY - 10);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [flaggedCase]);

  const stopCamera = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
    if (videoRef.current) videoRef.current.srcObject = null;
    setIsCameraActive(false);
    setIsMediaReady(false);
  }, []);

  const setupCamera = useCallback(async () => {
    setCameraError(null);
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
      });
      mediaStreamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().then(() => {
            setIsCameraActive(true);
            setIsMediaReady(true);
            startDrawingLoop();
          });
        };
      }
    } catch (err: any) {
      console.error('Camera Hardware Error:', err);
      setCameraError("Camera access required for AI scanning.");
    }
  }, [startDrawingLoop]);

  useEffect(() => {
    setupCamera();
    return () => stopCamera();
  }, [setupCamera, stopCamera]);

  const performDetection = useCallback(async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing || flaggedCase) return;

    setIsAnalyzing(true);
    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.6);
      const result = await detectViolationWithGemini(imageData);

      if (result && result.violationDetected) {
        setFlaggedCase({
          id: `case-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: CaseStatus.DRAFT,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.9,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: result.plateText ? 0.9 : 0,
          location: { latitude: 0, longitude: 0, geoHash: 'mob', placeName: 'Mobile Unit' },
          deviceId: 'M-VISION-X',
          recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['AI-Edge-Vision'],
          duplicateOf: null,
          detectionArea: result.detectionArea
        });
      }
    } catch (e) {
      console.error("AI Analysis encountered an error.");
    } finally {
      setIsAnalyzing(false);
      lastDetectionTimeRef.current = Date.now();
    }
  }, [isAnalyzing, flaggedCase, recorderId]);

  useEffect(() => {
    if (!isMediaReady || flaggedCase) return;
    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current >= detectionIntervalMs) {
        performDetection();
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, flaggedCase, performDetection]);

  const handleApprove = async () => {
    if (flaggedCase) {
      setIsAnalyzing(true);
      await ingestCase({ ...flaggedCase, status: CaseStatus.PENDING_REVIEW });
      setFlaggedCase(null);
      setIsAnalyzing(false);
    }
  };

  const handleDecline = () => {
    setFlaggedCase(null);
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      {cameraError ? (
        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center bg-gray-950">
          <p className="text-red-500 font-black uppercase text-[10px] tracking-widest mb-4">Hardware Locked</p>
          <button onClick={setupCamera} className="px-8 py-3 bg-white text-black font-black text-[10px] uppercase rounded-full">Unlock Sensors</button>
        </div>
      ) : (
        <>
          <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover grayscale opacity-30"></video>
          <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

          {/* AI Status Indicators - Top Left */}
          <div className="absolute top-6 left-6 pointer-events-none">
            <div className="bg-black/80 backdrop-blur-xl px-4 py-2 rounded-2xl border border-white/10 flex items-center space-x-3 shadow-2xl">
              <div className={`w-2 h-2 rounded-full animate-pulse ${isAnalyzing ? 'bg-yellow-500' : 'bg-green-500'}`}></div>
              <span className="text-[11px] font-black text-white uppercase tracking-widest whitespace-nowrap">
                {isAnalyzing ? 'AI is analyzing' : 'AI is detecting'}
              </span>
            </div>
          </div>

          {/* Action HUD - Bottom */}
          {flaggedCase && (
            <div className="absolute bottom-10 left-6 right-6 z-50 animate-in fade-in slide-in-from-bottom-4 duration-300">
              <div className="bg-gray-950/95 backdrop-blur-2xl border border-white/10 rounded-[32px] p-6 shadow-2xl">
                <div className="mb-6">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-2">Violation Flagged</p>
                  <div className="flex items-end justify-between">
                    <div>
                      <h3 className="text-2xl font-black text-white uppercase tracking-tight">
                        {flaggedCase.violationTypes[0].replace(/_/g, ' ')}
                      </h3>
                      <p className="text-xs text-gray-400 font-mono mt-1">PLATE: {flaggedCase.plateText}</p>
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-gray-600 uppercase">AI Conf.</p>
                       <p className="text-lg font-black text-indigo-400">{(flaggedCase.confidence * 100).toFixed(0)}%</p>
                    </div>
                  </div>
                </div>

                <div className="flex space-x-4">
                  <button 
                    onClick={handleDecline}
                    className="flex-1 py-4 bg-gray-900 text-gray-400 font-black text-xs uppercase tracking-widest rounded-2xl border border-white/5 active:scale-95 transition-all"
                  >
                    Decline
                  </button>
                  <button 
                    onClick={handleApprove}
                    className="flex-1 py-4 bg-indigo-600 text-white font-black text-xs uppercase tracking-widest rounded-2xl shadow-xl shadow-indigo-600/20 active:scale-95 transition-all"
                  >
                    Approve
                  </button>
                </div>
              </div>
            </div>
          )}
        </>
      )}

      {!isCameraActive && !cameraError && (
        <div className="absolute inset-0 bg-black flex flex-col items-center justify-center z-50">
           <LoadingSpinner />
           <p className="mt-4 text-[10px] font-black text-indigo-400 uppercase tracking-widest animate-pulse">Initializing Neural Engine...</p>
        </div>
      )}
    </div>
  );
};

export default CameraView;

import React, { useState, useRef, useCallback } from 'react';
import { LatLng, ManualReport, ViolationType } from '../types';
import Button from '../components/Button';
import { ingestManualReport } from '../services/api';

interface ManualReportFormProps {
  recorderId: string;
}

const ManualReportForm: React.FC<ManualReportFormProps> = ({ recorderId }) => {
  const [selectedViolationTypes, setSelectedViolationTypes] = useState<ViolationType[]>([]);
  const [notes, setNotes] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) setImageFile(e.target.files[0]);
    else setImageFile(null);
  };

  const getBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const getCurrentLocation = useCallback(async (): Promise<LatLng | undefined> => {
    return new Promise((resolve) => {
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (p) => resolve({ latitude: p.coords.latitude, longitude: p.coords.longitude }),
          () => resolve(undefined),
          { enableHighAccuracy: true, timeout: 5000 }
        );
      } else resolve(undefined);
    });
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedViolationTypes.length === 0 || !imageFile) return;

    setIsSubmitting(true);
    try {
      const imageBase64 = await getBase64(imageFile);
      const location = await getCurrentLocation();
      const report: ManualReport = {
        violationType: selectedViolationTypes,
        notes: notes,
        imageBase64: imageBase64,
        location: location,
        timestamp: new Date().toISOString(),
        reporterId: recorderId,
      };
      await ingestManualReport(report);
      setSelectedViolationTypes([]);
      setNotes('');
      setImageFile(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
      alert("Report successfully filed.");
    } catch (error) {
      console.error('Submission failed:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleViolation = (type: ViolationType) => {
    setSelectedViolationTypes(prev => 
      prev.includes(type) ? prev.filter(t => t !== type) : [...prev, type]
    );
  };

  return (
    <div className="p-6 bg-gray-900 min-h-full text-white pb-24">
      <div className="max-w-md mx-auto">
        <h2 className="text-2xl font-bold mb-6 text-white">Manual Report</h2>

        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Inline Selection - Removed Modal */}
          <div>
            <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-4 ml-1">Violation Categories</label>
            <div className="grid grid-cols-2 gap-2">
              {Object.values(ViolationType).map(type => (
                <button
                  key={type}
                  type="button"
                  onClick={() => toggleViolation(type)}
                  className={`px-3 py-3 rounded-xl border text-[10px] font-bold uppercase transition-all text-left flex items-center justify-between ${
                    selectedViolationTypes.includes(type)
                    ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg'
                    : 'bg-gray-800 border-gray-700 text-gray-400 hover:border-gray-600'
                  }`}
                >
                  <span className="truncate">{type.replace(/_/g, ' ')}</span>
                  {selectedViolationTypes.includes(type) && (
                    <svg className="w-3 h-3 text-white ml-2 shrink-0" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                    </svg>
                  )}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-2 ml-1">Incident Notes</label>
            <textarea
              rows={3}
              className="w-full p-4 rounded-xl bg-gray-800 border border-gray-700 text-white text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder-gray-600"
              placeholder="Provide vehicle details or context..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            ></textarea>
          </div>

          <div>
            <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-2 ml-1">Evidence Capture</label>
            <input
              type="file"
              accept="image/*"
              capture="environment"
              ref={fileInputRef}
              className="hidden"
              onChange={handleImageChange}
            />
            <button
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className={`w-full py-10 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center space-y-3 transition-all ${
                imageFile ? 'border-green-500/50 bg-green-500/5' : 'border-gray-700 hover:border-indigo-500 bg-gray-800/50'
              }`}
            >
              <svg className={`w-10 h-10 ${imageFile ? 'text-green-400' : 'text-gray-600'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
              <span className="text-[10px] font-black uppercase tracking-widest text-gray-500">
                {imageFile ? 'Image Loaded' : 'Open Camera Sensor'}
              </span>
            </button>
          </div>

          <Button
            type="submit"
            variant="primary"
            className="w-full py-4 text-xs font-black uppercase tracking-widest rounded-2xl shadow-xl shadow-indigo-600/20"
            disabled={selectedViolationTypes.length === 0 || !imageFile || isSubmitting}
          >
            {isSubmitting ? 'Submitting...' : 'File Violation Report'}
          </Button>
        </form>
      </div>
    </div>
  );
};

