import React, { useState, useEffect, useCallback } from 'react';
import { LatLng } from '../types';
import { fetchTrafficGrounding, TrafficInfo } from '../services/api';
import LoadingSpinner from '../components/LoadingSpinner';

const MONITOR_OPTIONS = [
  { id: 'jams', label: 'Jams' },
  { id: 'closures', label: 'Closures' },
  { id: 'accidents', label: 'Incidents' },
];

const TrafficMapView: React.FC = () => {
  const [location, setLocation] = useState<LatLng | null>(null);
  const [trafficInfo, setTrafficInfo] = useState<TrafficInfo | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeOptions, setActiveOptions] = useState<string[]>(['jams']);

  const toggleOption = (id: string) => {
    setActiveOptions(prev => 
      prev.includes(id) ? prev.filter(o => o !== id) : [...prev, id]
    );
  };

  const updateTraffic = useCallback(async (currentLoc: LatLng) => {
    setIsLoading(true);
    setError(null);
    try {
      const info = await fetchTrafficGrounding(currentLoc);
      setTrafficInfo(info);
    } catch (err) {
      setError("Sync Error.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const loc = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
          setLocation(loc);
          updateTraffic(loc);
        },
        () => setError("Location blocked."),
        { enableHighAccuracy: true }
      );
    }
  }, [updateTraffic]);

  const locationName = trafficInfo?.sources?.[0]?.title?.split(' near ')?.[1] || "Scanning Area...";

  return (
    <div className="bg-gray-950 min-h-full text-white pb-24 flex flex-col items-center">
      <div className="w-full p-6">
        <div className="flex items-center justify-between mb-8 border-b border-white/10 pb-4">
          <h2 className="text-xl font-black uppercase tracking-widest">Radar</h2>
          {location && (
            <button 
              onClick={() => updateTraffic(location)} 
              disabled={isLoading}
              className="text-[10px] font-black text-indigo-400 uppercase tracking-widest border border-indigo-400/30 px-3 py-1 rounded"
            >
              {isLoading ? 'Syncing...' : 'Sync Satellite'}
            </button>
          )}
        </div>

        {/* Minimalist Filter Indicators - Removed Boxes */}
        <div className="flex space-x-6 mb-10 overflow-x-auto hide-scrollbar">
          {MONITOR_OPTIONS.map(opt => (
            <button
              key={opt.id}
              onClick={() => toggleOption(opt.id)}
              className={`text-[10px] font-black uppercase tracking-widest transition-all ${
                activeOptions.includes(opt.id) 
                ? 'text-white border-b border-white pb-1' 
                : 'text-gray-600 border-b border-transparent pb-1'
              }`}
            >
              {opt.label}
            </button>
          ))}
        </div>

        {/* Radar Visualization */}
        <div className="relative w-full max-w-[280px] aspect-square mx-auto mb-10">
          <div className="relative w-full h-full rounded-full border border-white/5 overflow-hidden flex items-center justify-center">
            {/* Radar Grid */}
            <div className="absolute inset-0 opacity-10">
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-3/4 h-3/4 border border-white rounded-full"></div>
                <div className="absolute w-1/2 h-1/2 border border-white rounded-full"></div>
                <div className="absolute w-1/4 h-1/4 border border-white rounded-full"></div>
              </div>
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-full h-[1px] bg-white"></div>
                <div className="h-full w-[1px] bg-white"></div>
              </div>
            </div>

            {/* Sweep Line */}
            <div className="absolute inset-0 animate-[spin_3s_linear_infinite] origin-center">
              <div className="absolute top-0 left-1/2 w-[1px] h-1/2 bg-white/40 shadow-[0_0_10px_white]"></div>
            </div>

            {/* Center Node */}
            <div className="relative z-20 w-1.5 h-1.5 bg-white rounded-full"></div>
          </div>
        </div>

        {/* Address Overlay - Removed Box Styling */}
        <div className="mb-10 text-center">
            <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] mb-2">Location Node</p>
            <h3 className="text-xl font-bold text-white mb-1 uppercase tracking-tight">
              {isLoading ? 'Updating...' : locationName}
            </h3>
            {location && (
              <p className="text-[10px] text-gray-600 font-mono">
                COORD: {location.latitude.toFixed(4)}, {location.longitude.toFixed(4)}
              </p>
            )}
        </div>

        {/* Source Feed */}
        {trafficInfo && trafficInfo.sources.length > 0 && (
          <div className="w-full space-y-4">
            <p className="text-[9px] font-black text-gray-700 uppercase tracking-widest">Grounding Nodes</p>
            <div className="space-y-2">
              {trafficInfo.sources.map((source, i) => (
                <a 
                  key={i} 
                  href={source.uri} 
                  target="_blank" 
                  rel="noreferrer"
                  className="block text-[11px] font-bold text-gray-400 hover:text-white transition-colors"
                >
                  [{i + 1}] {source.title.slice(0, 40)}...
                </a>
              ))}
            </div>
          </div>
        )}

        {error && (
          <div className="mt-10 p-4 border border-red-500/20 text-red-500 text-[10px] font-black uppercase text-center">
            {error}
          </div>
        )}
      </div>
    </div>
  );
};

export default TrafficMapView;

