import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Case, CaseStatus, LatLng, ViolationType } from '../types';
import { ingestCase, detectViolationWithGemini } from '../services/api';
import LoadingSpinner from '../components/LoadingSpinner';

interface CameraViewProps {
  recorderId: string;
}

const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);

  const [flaggedCase, setFlaggedCase] = useState<(Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 6000; 

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d', { willReadFrequently: true });
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight || video.paused || video.ended) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (flaggedCase && flaggedCase.detectionArea) {
          const { x, y, width, height } = flaggedCase.detectionArea;
          const rectX = (x / 100) * canvas.width;
          const rectY = (y / 100) * canvas.height;
          const rectW = (width / 100) * canvas.width;
          const rectH = (height / 100) * canvas.height;

          context.strokeStyle = '#ef4444';
          context.lineWidth = 4;
          context.strokeRect(rectX, rectY, rectW, rectH);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [flaggedCase]);

  const stopCamera = useCallback(() => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
    if (videoRef.current) videoRef.current.srcObject = null;
    setIsCameraActive(false);
    setIsMediaReady(false);
  }, []);

  const setupCamera = useCallback(async () => {
    setCameraError(null);
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
      });
      mediaStreamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().then(() => {
            setIsCameraActive(true);
            setIsMediaReady(true);
            startDrawingLoop();
          });
        };
      }
    } catch (err: any) {
      setCameraError("Camera access required.");
    }
  }, [startDrawingLoop]);

  useEffect(() => {
    setupCamera();
    return () => stopCamera();
  }, [setupCamera, stopCamera]);

  const performDetection = useCallback(async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing || flaggedCase) return;

    setIsAnalyzing(true);
    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.6);
      const result = await detectViolationWithGemini(imageData);

      if (result && result.violationDetected) {
        setFlaggedCase({
          id: `case-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: CaseStatus.DRAFT,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.9,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: result.plateText ? 0.9 : 0,
          location: { latitude: 0, longitude: 0, geoHash: 'mob', placeName: 'Mobile Unit' },
          deviceId: 'M-VISION-X',
          recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['AI-Edge-Vision'],
          duplicateOf: null,
          detectionArea: result.detectionArea
        });
      }
    } catch (e) {
      console.error("Analysis Error");
    } finally {
      setIsAnalyzing(false);
      lastDetectionTimeRef.current = Date.now();
    }
  }, [isAnalyzing, flaggedCase, recorderId]);

  useEffect(() => {
    if (!isMediaReady || flaggedCase) return;
    const interval = setInterval(() => {
      const now = Date.now();
      if (now - lastDetectionTimeRef.current >= detectionIntervalMs) {
        performDetection();
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, flaggedCase, performDetection]);

  const handleApprove = async () => {
    if (flaggedCase) {
      setIsAnalyzing(true);
      await ingestCase({ ...flaggedCase, status: CaseStatus.PENDING_REVIEW });
      setFlaggedCase(null);
      setIsAnalyzing(false);
    }
  };

  const handleDecline = () => {
    setFlaggedCase(null);
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden flex flex-col">
      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover grayscale opacity-40"></video>
        <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

        {/* Status indicator - Top Left */}
        <div className="absolute top-4 left-4 z-10">
          <div className="bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10 flex items-center space-x-2">
            <div className={`w-2 h-2 rounded-full ${isAnalyzing ? 'bg-yellow-500 animate-pulse' : 'bg-green-500'}`}></div>
            <span className="text-[10px] font-black text-white uppercase tracking-widest">
              {isAnalyzing ? 'Analyzing' : 'Ready'}
            </span>
          </div>
        </div>
      </div>

      {/* Flagged Case Overlay - Compact and bottom-aligned */}
      {flaggedCase && (
        <div className="absolute bottom-4 left-4 right-4 z-40">
          <div className="bg-gray-950/90 backdrop-blur-2xl border border-white/10 rounded-2xl p-4 shadow-2xl">
            <div className="flex justify-between items-center mb-3">
              <div>
                <p className="text-[9px] font-black text-red-500 uppercase tracking-widest mb-0.5">Violation Found</p>
                <h3 className="text-lg font-black text-white uppercase tracking-tight">
                  {flaggedCase.violationTypes[0].replace(/_/g, ' ')}
                </h3>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-mono text-indigo-400">{flaggedCase.plateText}</span>
              </div>
            </div>

            <div className="flex space-x-2">
              <button 
                onClick={handleDecline}
                className="flex-1 py-3 bg-gray-900 text-gray-400 font-black text-[10px] uppercase tracking-widest rounded-xl"
              >
                Decline
              </button>
              <button 
                onClick={handleApprove}
                className="flex-1 py-3 bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest rounded-xl shadow-lg shadow-indigo-600/20"
              >
                Approve
              </button>
            </div>
          </div>
        </div>
      )}

      {cameraError && (
        <div className="absolute inset-0 bg-black flex items-center justify-center p-8 text-center">
          <p className="text-red-500 text-[10px] font-black uppercase tracking-widest">{cameraError}</p>
        </div>
      )}

      {!isCameraActive && !cameraError && (
        <div className="absolute inset-0 bg-black flex flex-col items-center justify-center z-50">
           <LoadingSpinner />
        </div>
      )}
    </div>
  );
};

export default CameraView;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat } from "@google/genai";
import Button from '../components/Button';
import LoadingSpinner from '../components/LoadingSpinner';

interface Message {
  text: string;
  sender: 'user' | 'gemini';
}

const ChatbotPage: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<Chat | null>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initializeChat = async () => {
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        chatRef.current = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction: 'You are a concise traffic enforcement AI assistant. Answer support questions briefly.',
          },
        });
        setMessages([{ text: "System ready. How can I help?", sender: 'gemini' }]);
      } catch (error) {
        console.error('Gemini init failed');
      }
    };
    initializeChat();
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const sendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { text: input, sender: 'user' as const };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      if (!chatRef.current) throw new Error("No session");
      const responseStream = await chatRef.current.sendMessageStream({ message: userMessage.text });
      let geminiResponseText = '';
      setMessages(prev => [...prev, { text: '', sender: 'gemini' as const }]);

      for await (const chunk of responseStream) {
        const currentChunkText = chunk.text;
        if (currentChunkText) {
          geminiResponseText += currentChunkText;
          setMessages(prev => {
            const newMessages = [...prev];
            if (newMessages.length > 0 && newMessages[newMessages.length - 1].sender === 'gemini') {
              newMessages[newMessages.length - 1].text = geminiResponseText;
            }
            return newMessages;
          });
        }
      }
    } catch (error) {
      setMessages(prev => [...prev, { text: `Error: Connection lost.`, sender: 'gemini' as const }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-950 text-white">
      <div className="flex-1 overflow-y-auto p-3 space-y-2 hide-scrollbar" ref={chatContainerRef}>
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] p-2.5 rounded-2xl text-xs leading-relaxed ${
                msg.sender === 'user' ? 'bg-indigo-600 text-white' : 'bg-gray-800 text-gray-100 border border-white/5'
              }`}
            >
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="p-2 bg-gray-800 rounded-2xl border border-white/5">
              <LoadingSpinner />
            </div>
          </div>
        )}
      </div>

      <form onSubmit={sendMessage} className="flex p-3 bg-indigo-950/30 border-t border-white/5 backdrop-blur-md">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Message AI Assistant..."
          className="flex-1 p-3 rounded-xl bg-gray-900 border border-gray-800 text-sm text-white focus:outline-none focus:ring-1 focus:ring-indigo-500"
          disabled={isLoading}
        />
        <button
          type="submit"
          className="ml-2 bg-indigo-600 text-white p-3 rounded-xl disabled:opacity-50"
          disabled={!input.trim() || isLoading}
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" />
          </svg>
        </button>
      </form>
    </div>
  );
};

export default ChatbotPage;

