export const fetchUsersByRole = async (role: UserRole): Promise<User[]> => SESSION_USERS.filter(u => u.role === role);
export const acceptAllPendingCases = async () => {
  const pending = MOCK_CASES.filter(c => c.status === CaseStatus.PENDING_REVIEW);
  pending.forEach(c => c.status = CaseStatus.ACCEPTED);
  return { success: pending.length, failed: 0 };
};

export const fetchTrafficGrounding = async (location: LatLng): Promise<TrafficInfo> => {
  return callGeminiWithRetry(async (ai) => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Identify the specific neighborhood, nearest major intersection, and provide a 1-sentence traffic status report for the coordinates: latitude ${location.latitude}, longitude ${location.longitude}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        }
      },
    });

    const summary = response.text || "Traffic status unavailable.";

    // Extract Grounding Chunks for links
    const sources: { title: string; uri: string }[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "View on Google Maps", uri: chunk.maps.uri });
        }
      });
    }

    // Heuristic for "Specific Area" - first line or extracted from grounding
    const lines = summary.split('\n');
    const specificArea = lines[0] || "Unknown Vicinity";

    return {
      summary,
      specificArea,
      sources
    };
  }).catch(e => {
    console.error("Traffic Grounding Error:", e);
    return {
      summary: "Satellite sync error. Using offline data.",
      specificArea: "Vicinity Sync Pending",
      sources: []
    };
  });
};

