export const signUpUser = async (userData: Partial<User & { password?: string }>): Promise<User> => {
  // Supabase Auth requires email. Use generic domain if only username is provided.
  const email = userData.email?.includes('@') ? userData.email : `${userData.name?.toLowerCase().replace(/\s/g, '')}@mtraffic.local`;

  const { data, error } = await supabase.auth.signUp({
    email,
    password: userData.password || 'TemporaryPassword123!',
    options: {
      data: {
        name: userData.name,
        role: userData.role,
        unit: userData.role === UserRole.POLICE ? 'Traffic Unit' : 'General Public',
        dob: userData.dob,
        aadhaar: userData.aadhaar,
        deviceIds: [],
      }
    }
  });

  if (error) throw error;
  if (!data.user) throw new Error("Registration failed to create user.");

  return mapSupabaseUser(data.user);
};

