    id: sbUser.id,
    role: (sbUser.user_metadata?.role as UserRole) || UserRole.PUBLIC,
    name: sbUser.user_metadata?.name || 'Authorized User',
    unit: sbUser.user_metadata?.unit || 'Field Unit',
    email: sbUser.email || '',
    phone: sbUser.user_metadata?.phone || '',
    dob: sbUser.user_metadata?.dob,
    aadhaar: sbUser.user_metadata?.aadhaar,
    deviceIds: sbUser.user_metadata?.deviceIds || [],
  };
};

