/**
 * SIGN UP: Real Supabase Auth Integration
 */
export const signUpUser = async (userData: Partial<User & { password?: string }>): Promise<User> => {
  // Use email if provided, otherwise derive from name or custom logic
  const email = userData.email || `${userData.name?.toLowerCase().replace(/\s/g, '')}@mtraffic.local`;

  const { data, error } = await supabase.auth.signUp({
    email,
    password: userData.password || 'TemporaryPassword123!',
    options: {
      data: {
        name: userData.name,
        role: userData.role,
        unit: userData.role === UserRole.POLICE ? 'Traffic Unit' : (userData.role === UserRole.ADMIN ? 'HQ Command' : 'General Public'),
        dob: userData.dob,
        aadhaar: userData.aadhaar,
        deviceIds: [],
      }
    }
  });

  if (error) throw error;
  if (!data.user) throw new Error("Registration failed to create user.");

  return mapSupabaseUser(data.user);
};

/**
