  ];

  const results = [];
  for (const user of demoUsers) {
    try {
      // Supabase often requires 6 chars. If 123 fails, we use 123123 for seeding.
      const pass = '123123'; 
      const email = `${user.identifier}@mtraffic.local`;

      const { data, error } = await supabase.auth.signUp({
        email,
        password: pass,
        options: {
