export const detectViolationWithGemini = async (imageBase64: string) => {
  return callGeminiWithRetry(async (ai) => {
    const data = imageBase64.includes(',') ? imageBase64.split(',')[1] : imageBase64;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { 
        parts: [
          { text: "Enforcement Task: Analyze frame for traffic violations (helmet, red light, phone). If found, return JSON with violationDetected: true, violationType, and plateText." }, 
          { inlineData: { mimeType: 'image/jpeg', data } }
        ] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            violationDetected: { type: Type.BOOLEAN },
            violationType: { type: Type.STRING, enum: Object.values(ViolationType) },
            confidence: { type: Type.NUMBER },
            plateText: { type: Type.STRING },
            detectionArea: { type: Type.OBJECT, properties: { x: { type: Type.NUMBER }, y: { type: Type.NUMBER }, width: { type: Type.NUMBER }, height: { type: Type.NUMBER } } }
          }
        }
      },
    });
    return JSON.parse(response.text || '{"violationDetected": false}');
  }).catch(e => {
    console.error("Gemini Detection Error:", e);
    return { violationDetected: false };
  });
};

export const ingestCase = async (c: Case) => { 
  MOCK_CASES.unshift(c); 
  return c; 
};

export const searchUsers = async (term: string) => {
  return SESSION_USERS.filter(u => u.name.toLowerCase().includes(term.toLowerCase()));
};

export const ingestManualReport = async (r: ManualReport) => {
  const c: Case = {
    id: `m-${Date.now()}`, 
    createdAt: r.timestamp, 
    status: CaseStatus.PENDING_REVIEW, 
    violationTypes: r.violationType, 
    confidence: 1, 
    plateText: 'N/A', 
    plateConfidence: 0,
    location: r.location ? { ...r.location, geoHash: 'm', placeName: 'Field Report' } : { latitude: 0, longitude: 0, geoHash: 'm', placeName: 'Manual' },
    deviceId: 'M-PATROL-1', 
    recorderId: r.reporterId, 
    mediaUrls: [r.imageBase64], 
    rulesMatched: [], 
    duplicateOf: null
  };
  MOCK_CASES.unshift(c);
  return c;
};

export const fetchAuditLogsForCase = async (caseId: string) => MOCK_AUDIT_LOGS.filter(l => l.caseId === caseId);

export const fetchUserById = async (id: string): Promise<User | undefined> => {
  return SESSION_USERS.find(u => u.id === id);
};

export const fetchAllPotentialAssignees = async (): Promise<User[]> => SESSION_USERS.filter(u => u.role !== UserRole.ADMIN);

export const assignCase = async (id: string, userId: string) => {
  const c = MOCK_CASES.find(x => x.id === id);
  if (c) {
    c.status = CaseStatus.ASSIGNED;
    c.assigneeId = userId;
  }
  return { success: true, case: c, message: "Assigned successfully." };
};

export const analyzeContentWithGemini = async (p: string, i?: string) => {
  const ai = getAI();
  const parts: any[] = [{ text: p }];
  if (i) parts.push({ inlineData: { mimeType: 'image/jpeg', data: i.split(',')[1] || i } });
  const r = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: { parts } });
  return r.text || "No analysis.";
};

export const fetchOfficerDuties = async (): Promise<OfficerDuty[]> => {
  await delay(400);
  return MOCK_OFFICER_DUTIES;
};

export const fetchUsersByRole = async (role: UserRole): Promise<User[]> => SESSION_USERS.filter(u => u.role === role);

export const acceptAllPendingCases = async () => {
  const pending = MOCK_CASES.filter(c => c.status === CaseStatus.PENDING_REVIEW);
  pending.forEach(c => c.status = CaseStatus.ACCEPTED);
  return { success: pending.length, failed: 0 };
};

export const fetchTrafficGrounding = async (location: LatLng): Promise<TrafficInfo> => {
  return callGeminiWithRetry(async (ai) => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", 
      contents: `Provide a 1-sentence traffic status report for the coordinates: latitude ${location.latitude}, longitude ${location.longitude}. Do not mention specific street names or location IDs.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.latitude,
              longitude: location.longitude
            }
          }
        }
      },
    });

    const summary = response.text || "Traffic status unavailable.";
    const sources: { title: string; uri: string }[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "View Map Source", uri: chunk.maps.uri });
        }
      });
    }

    return {
      summary,
      specificArea: "Active Corridor",
      sources
    };
  }).catch(e => {
    console.error("Traffic Grounding Error:", e);
    return {
      summary: "Satellite sync error. Scanning offline bio-signatures.",
      specificArea: "Vicinity Standby",
      sources: []
    };
  });
};

import React, { useState } from 'react';
