import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, Blob, FunctionDeclaration } from '@google/genai';
import { useNavigate } from 'react-router-dom';

interface JarvisAssistantProps {
  userRole: string;
  userName: string;
  onLogout: () => void;
}

const JarvisAssistant: React.FC<JarvisAssistantProps> = ({ userRole, userName, onLogout }) => {
  const navigate = useNavigate();
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  const sessionRef = useRef<any>(null);
  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);

  // Manual Base64 Helpers
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const createBlob = (data: Float32Array): Blob => {
    const int16 = new Int16Array(data.length);
    for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const stopAllAudio = () => {
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  };

  const handleFunctionCall = useCallback(async (fc: any) => {
    console.log("Jarvis Tool Call:", fc);
    let result = "Action completed";

    if (fc.name === 'navigateTo') {
      const path = fc.args.path;
      navigate(path);
      result = `Navigated to ${path}`;
    } else if (fc.name === 'logout') {
      onLogout();
      result = "Logging out user";
    }

    if (sessionRef.current) {
      sessionRef.current.sendToolResponse({
        functionResponses: { id: fc.id, name: fc.name, response: { result } }
      });
    }
  }, [navigate, onLogout]);

  const toggleAssistant = async () => {
    if (isActive) {
      if (sessionRef.current) sessionRef.current.close();
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      setIsActive(false);
      stopAllAudio();
      return;
    }

    setIsConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const navTool: FunctionDeclaration = {
        name: 'navigateTo',
        parameters: {
          type: Type.OBJECT,
          description: 'Navigate the user to a specific page in the traffic enforcement app.',
          properties: {
            path: { type: Type.STRING, description: 'The route path (e.g., "/", "/traffic", "/report", "/cases", "/analytics", "/officers")' }
          },
          required: ['path']
        }
      };

      const logoutTool: FunctionDeclaration = {
        name: 'logout',
        parameters: { type: Type.OBJECT, description: 'Log the current user out of the system.', properties: {} }
      };

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);

            const source = audioContextInRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.toolCall) {
              msg.toolCall.functionCalls.forEach(handleFunctionCall);
            }

            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              setIsSpeaking(true);
              const ctx = audioContextOutRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (msg.serverContent?.interrupted) {
              stopAllAudio();
              setIsSpeaking(false);
            }
          },
          onclose: () => setIsActive(false),
          onerror: (e) => console.error("Jarvis Error:", e)
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          tools: [{ functionDeclarations: [navTool, logoutTool] }],
          systemInstruction: `You are Jarvis, a high-tech traffic enforcement AI assistant. 
          The current user is ${userName} with the role of ${userRole}.
          You can navigate the app using tools. 
          Available paths: "/" (Scanner), "/traffic" (Radar), "/report" (Manual Report), "/cases" (History), "/analytics" (Stats/Dashboard), "/officers" (Police Personnel).
          Be professional, concise, and helpful. Always confirm actions with voice.`
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Jarvis Init Failed:", err);
      setIsConnecting(false);
    }
  };

  return (
    <div className="fixed bottom-20 right-4 z-[60] flex flex-col items-center">
      <button
        onClick={toggleAssistant}
        disabled={isConnecting}
        className={`relative group w-14 h-14 rounded-full flex items-center justify-center transition-all duration-500 shadow-2xl ${
          isActive 
            ? 'bg-indigo-600 scale-110 border-2 border-white/20' 
            : 'bg-gray-800 hover:bg-gray-700 border border-white/5'
        }`}
      >
        {/* Glow Rings */}
        {isActive && (
          <>
            <div className={`absolute inset-0 rounded-full bg-indigo-500/30 animate-ping`} />
            <div className={`absolute inset-0 rounded-full border-2 border-indigo-400/50 animate-pulse scale-125`} />
            {isSpeaking && <div className="absolute -inset-2 rounded-full border border-indigo-400/30 animate-spin" style={{ animationDuration: '3s' }} />}
          </>
        )}

        {/* Inner Icon */}
        <div className={`relative z-10 w-8 h-8 flex items-center justify-center`}>
          {isConnecting ? (
            <div className="w-5 h-5 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin" />
          ) : isActive ? (
            <div className="relative">
              <div className={`w-3 h-3 bg-white rounded-full ${isSpeaking ? 'scale-125' : 'scale-100'} transition-transform duration-150 shadow-[0_0_10px_white]`} />
              <div className="absolute inset-0 w-3 h-3 bg-white rounded-full animate-ping opacity-50" />
            </div>
          ) : (
            <svg className="w-6 h-6 text-indigo-400 group-hover:text-indigo-300 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.114 5.636a9 9 0 010 12.728M16.463 8.288a5.25 5.25 0 010 7.424M6.75 8.25l4.72-4.72a.75.75 0 011.28.53v15.88a.75.75 0 01-1.28.53l-4.72-4.72H4.51c-.88 0-1.704-.507-1.938-1.354A9.01 9.01 0 012.25 12c0-.83.112-1.633.322-2.396C2.806 8.756 3.63 8.25 4.51 8.25H6.75z" />
            </svg>
          )}
        </div>
      </button>

      {/* Label */}
      <span className={`mt-2 text-[8px] font-black uppercase tracking-[0.3em] transition-all duration-300 ${isActive ? 'text-indigo-400 opacity-100 translate-y-0' : 'text-gray-600 opacity-50 -translate-y-1'}`}>
        {isActive ? 'Jarvis Active' : 'Summon Jarvis'}
      </span>
    </div>
  );
};

export default JarvisAssistant;

