            if (audioData) {
              setIsSpeaking(true);
              const ctx = audioContextOutRef.current!;
              if (ctx.state === 'suspended') await ctx.resume();

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (msg.serverContent?.interrupted) {
              stopAllAudio();
              setIsSpeaking(false);
            }
          },
          onclose: () => {
            setIsActive(false);
            setIsConnecting(false);
          },
          onerror: (e) => {
            console.error("Jarvis Logic Error:", e);
            setIsConnecting(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          tools: [{ functionDeclarations: [navTool, logoutTool] }],
          systemInstruction: `SYSTEM: Persona is JARVIS. Current User: ${userName} (${userRole}).
          Role: Advanced Traffic Enforcement AI. 
          Instructions: Be extremely brief. Use tool "navigateTo" to switch views. 
          Paths: "/" (Scanner), "/traffic" (Radar), "/report" (Manual), "/cases" (History), "/analytics" (Dashboard), "/officers" (Personnel).
          Always confirm your action with a polite verbal response.`
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Jarvis Initialization Failed:", err);
      setIsConnecting(false);
    }
  };

  return (
    <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-center">
      <button
        onClick={toggleAssistant}
        disabled={isConnecting}
        className={`relative group w-16 h-16 rounded-full flex items-center justify-center transition-all duration-700 shadow-[0_0_30px_rgba(0,0,0,0.5)] ${
          isActive 
            ? 'bg-indigo-600 border-2 border-white/30 scale-110' 
            : 'bg-gray-800 border border-white/10 hover:border-indigo-500/50'
        }`}
      >
        {/* Holographic Effects */}
        {isActive && (
          <>
            {/* Dynamic Wave Aura */}
            <div 
              className="absolute inset-0 rounded-full bg-indigo-400/20 animate-ping" 
              style={{ animationDuration: '2s' }} 
            />
            {/* VU Meter Pulse */}
            <div 
              className="absolute inset-0 rounded-full border-2 border-indigo-300/40 transition-transform duration-75" 
              style={{ transform: `scale(${1 + (inputLevel / 100) * 1.5})` }} 
            />
            {/* Speaking Spinner */}
            {isSpeaking && (
              <div className="absolute -inset-3 rounded-full border border-indigo-400/20 border-t-indigo-400 animate-spin" />
            )}
          </>
        )}

        {/* The Nexus Orb */}
        <div className={`relative z-10 w-10 h-10 flex items-center justify-center`}>
          {isConnecting ? (
            <div className="w-6 h-6 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin" />
          ) : (
            <div className="relative flex items-center justify-center">
              {/* Core */}
              <div className={`w-4 h-4 rounded-full transition-all duration-300 ${
                isActive ? 'bg-white shadow-[0_0_20px_white]' : 'bg-indigo-500/40'
              } ${isSpeaking ? 'scale-125' : 'scale-100'}`} />

              {/* Orbiting Ring */}
              <div className={`absolute w-8 h-8 rounded-full border border-indigo-400/30 ${isActive ? 'animate-spin' : ''}`} 
                   style={{ animationDuration: '5s' }} />

              {/* Mic Icon Overlay when inactive */}
              {!isActive && (
                <svg className="absolute w-5 h-5 text-indigo-400/60" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v8a3 3 0 01-6 0V5a3 3 0 013-3z" />
                </svg>
