      };

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            updateMeter();
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
            };
            sourceMic.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.toolCall) msg.toolCall.functionCalls.forEach(handleFunctionCall);
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              setIsSpeaking(true);
              const ctx = audioContextOutRef.current!;
              if (ctx.state === 'suspended') await ctx.resume();
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
            if (msg.serverContent?.interrupted) { stopAllAudio(); setIsSpeaking(false); }
          },
          onclose: () => { setIsActive(false); setIsConnecting(false); },
          onerror: () => setIsConnecting(false)
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          tools: [{ functionDeclarations: [navTool, logoutTool] }],
          systemInstruction: `Persona: JARVIS. Action: Mobile traffic enforcement assistant. Be concise. Navigate using tools.`
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      setIsConnecting(false);
    }
  };

  if (!isJarvisSystemEnabled) return null;

  return (
    <div className="fixed bottom-[68px] right-4 z-[100] flex flex-col items-center">
      <button
        onClick={toggleAssistant}
        disabled={isConnecting}
        className={`relative w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 shadow-xl ${
          isActive 
            ? 'bg-indigo-600 border border-white/40 ring-2 ring-indigo-500/20' 
            : 'bg-gray-800 border border-white/5 hover:bg-gray-700'
        }`}
      >
        {isActive && (
          <div className="absolute inset-0 rounded-full bg-indigo-500/30 animate-ping" />
        )}

        <div className="relative z-10 flex items-center justify-center">
          {isConnecting ? (
            <div className="w-3 h-3 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin" />
          ) : (
            <div className="flex items-center justify-center">
              {isActive ? (
                <div className={`w-1.5 h-1.5 rounded-full bg-white shadow-[0_0_8px_white] ${isSpeaking ? 'scale-125' : 'scale-100'} transition-transform`} />
              ) : (
                <svg className="w-4 h-4 text-indigo-400/80" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v8a3 3 0 01-6 0V5a3 3 0 013-3z" />
                </svg>
              )}
            </div>
          )}
        </div>
      </button>
      <span className="mt-0.5 text-[6px] font-black uppercase tracking-widest text-indigo-400/50 opacity-0 group-hover:opacity-100 transition-opacity">Jarvis</span>
    </div>
  );
};

