export const detectViolationWithGemini = async (imageBase64: string) => {
  const ai = getAI();
  const data = imageBase64.split(',')[1] || imageBase64;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        { text: "Analyze for violations (helmet, red light) AND for EMERGENCY AMBULANCES. If ambulance detected, return JSON with violationDetected: true, violationType: 'AMBULANCE', plateText: 'EMERGENCY'." }, 
        { inlineData: { mimeType: 'image/jpeg', data } }
      ] 
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          violationDetected: { type: Type.BOOLEAN },
          violationType: { type: Type.STRING, enum: Object.values(ViolationType) },
          confidence: { type: Type.NUMBER },
          plateText: { type: Type.STRING },
          detectionArea: { type: Type.OBJECT, properties: { x: { type: Type.NUMBER }, y: { type: Type.NUMBER }, width: { type: Type.NUMBER }, height: { type: Type.NUMBER } } }
        }
      }
    },
  });
  return JSON.parse(response.text || '{"violationDetected": false}');
};

export const findNearestHospital = async (location: LatLng): Promise<Hospital | null> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash", 
    contents: `Find the 1 nearest hospital to Lat: ${location.latitude}, Lon: ${location.longitude}. Return name, distance, and ETA.`,
    config: { tools: [{ googleMaps: {} }], toolConfig: { retrievalConfig: { latLng: { latitude: location.latitude, longitude: location.longitude } } } },
  });

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks && chunks[0]?.maps) {
    return {
      name: chunks[0].maps.title || "City General Hospital",
      distance: "1.2 km",
      eta: "4 mins",
      address: "Main Sector",
      uri: chunks[0].maps.uri
    };
  }
  return null;
};

