const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);

  const [flaggedCase, setFlaggedCase] = useState<(Case & { detectionArea?: { x: number; y: number; width: number; height: number; }; }) | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isRelaying, setIsRelaying] = useState(false); // Sensor Relay Node (1km -> 100m)

  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 6000; 

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d');
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (flaggedCase && flaggedCase.detectionArea) {
          const { x, y, width, height } = flaggedCase.detectionArea;
          context.strokeStyle = flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? '#3b82f6' : '#ef4444';
          context.lineWidth = 6;
          context.strokeRect((x / 100) * canvas.width, (y / 100) * canvas.height, (width / 100) * canvas.width, (height / 100) * canvas.height);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [flaggedCase]);

  const setupCamera = useCallback(async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      mediaStreamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().then(() => { setIsCameraActive(true); setIsMediaReady(true); startDrawingLoop(); });
        };
      }
    } catch (err: any) { setCameraError("Camera block detected."); }
  }, [startDrawingLoop]);

  useEffect(() => { setupCamera(); return () => { if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(t => t.stop()); }; }, [setupCamera]);

  const performDetection = useCallback(async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing || flaggedCase) return;

    setIsAnalyzing(true);
    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.6);
      const result = await detectViolationWithGemini(imageData);

      if (result && result.violationDetected) {
        let hospital: Hospital | undefined;
        if (result.violationType === ViolationType.AMBULANCE) {
          hospital = (await findNearestHospital({ latitude: 13.0, longitude: 80.0 })) || undefined;
          setIsRelaying(true); // Simulate relaying message from 1km node
          setTimeout(() => setIsRelaying(false), 3000);
        }

        setFlaggedCase({
          id: `case-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: result.violationType === ViolationType.AMBULANCE ? CaseStatus.EMERGENCY : CaseStatus.DRAFT,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.9,
          plateText: result.plateText || 'EMERGENCY',
          plateConfidence: 0.9,
          location: { latitude: 0, longitude: 0, geoHash: 'mob', placeName: 'Intersection-A4' },
          deviceId: 'NODE-SENSOR-100M',
          recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['Distributed-AI-Net'],
          duplicateOf: null,
          detectionArea: result.detectionArea,
          hospitalRoute: hospital
        });
      }
    } catch (e) { console.error(e); } finally { setIsAnalyzing(false); lastDetectionTimeRef.current = Date.now(); }
  }, [isAnalyzing, flaggedCase, recorderId]);

  useEffect(() => {
    if (!isMediaReady || flaggedCase) return;
    const interval = setInterval(() => { if (Date.now() - lastDetectionTimeRef.current >= detectionIntervalMs) performDetection(); }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, flaggedCase, performDetection]);

  const handleApprove = async () => {
    if (flaggedCase) {
      setIsAnalyzing(true);
      await ingestCase({ ...flaggedCase, status: flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? CaseStatus.EMERGENCY : CaseStatus.PENDING_REVIEW });
      setFlaggedCase(null);
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="relative h-full w-full bg-black flex flex-col">
      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover grayscale opacity-30"></video>
        <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

        <div className="absolute top-4 left-4 z-10 flex flex-col space-y-2">
          <div className="bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10 flex items-center space-x-2">
            <div className={`w-2 h-2 rounded-full ${isAnalyzing ? 'bg-yellow-500 animate-pulse' : 'bg-green-500'}`}></div>
            <span className="text-[10px] font-black text-white uppercase tracking-widest">
              {isAnalyzing ? 'Analyzing Bio-Stream' : 'Local Sensor: 100m Active'}
            </span>
          </div>
          {isRelaying && (
            <div className="bg-blue-600/40 backdrop-blur-md px-3 py-1.5 rounded-full border border-blue-400/50 flex items-center space-x-2 animate-pulse">
              <span className="text-[10px] font-black text-white uppercase tracking-widest">Relay: 1KM Node Handshake</span>
            </div>
          )}
        </div>
      </div>

      {flaggedCase && (
        <div className="absolute bottom-0 left-0 right-0 z-40 p-4 pb-4 animate-in slide-in-from-bottom-5 duration-300">
          <div className={`backdrop-blur-3xl border rounded-2xl p-4 shadow-2xl ${flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'bg-blue-950/90 border-blue-400/50' : 'bg-gray-950/95 border-white/10'}`}>
            <div className="flex justify-between items-center mb-3">
              <div>
                <p className={`text-[9px] font-black uppercase tracking-widest mb-0.5 ${flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'text-blue-400' : 'text-red-500'}`}>
                  {flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'Emergency Detected' : 'Infraction Logged'}
                </p>
                <h3 className="text-lg font-black text-white uppercase tracking-tight">
                  {flaggedCase.violationTypes[0].replace(/_/g, ' ')}
                </h3>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-mono text-white bg-black/40 px-2 py-1 rounded-md border border-white/5">{flaggedCase.plateText}</span>
              </div>
            </div>

            {flaggedCase.hospitalRoute && (
              <div className="mb-4 p-3 bg-white/5 rounded-xl border border-white/10">
                <p className="text-[8px] font-black text-blue-400 uppercase mb-1">Priority Route Dispatched</p>
                <p className="text-xs font-bold text-white">{flaggedCase.hospitalRoute.name}</p>
                <div className="flex space-x-3 mt-1">
                  <p className="text-[10px] text-gray-400">ETA: <span className="text-white font-black">{flaggedCase.hospitalRoute.eta}</span></p>
                  <p className="text-[10px] text-gray-400">Dist: <span className="text-white font-black">{flaggedCase.hospitalRoute.distance}</span></p>
                </div>
              </div>
            )}

            <div className="flex space-x-2">
              <button onClick={() => setFlaggedCase(null)} className="flex-1 py-3 bg-gray-900 text-gray-400 font-black text-[10px] uppercase rounded-xl">Dismiss</button>
              <button onClick={handleApprove} className={`flex-1 py-3 text-white font-black text-[10px] uppercase rounded-xl shadow-lg ${flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'bg-blue-600 shadow-blue-600/20' : 'bg-indigo-600 shadow-indigo-600/20'}`}>
                {flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'Notify Command' : 'File Case'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

