      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [flaggedCase, sensorSource]);

  const setupCamera = useCallback(async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      mediaStreamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().then(() => { setIsCameraActive(true); setIsMediaReady(true); startDrawingLoop(); });
        };
      }
    } catch (err: any) { setCameraError("Visual sensor denied."); }
  }, [startDrawingLoop]);

  useEffect(() => { setupCamera(); return () => { if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(t => t.stop()); }; }, [setupCamera]);

  const performDetection = useCallback(async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing || flaggedCase) return;

    setIsAnalyzing(true);
    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.6);
      const result = await detectViolationWithGemini(imageData);

      if (result && result.violationDetected) {
        let hospital: Hospital | undefined;
        if (result.violationType === ViolationType.AMBULANCE) {
          hospital = (await findNearestHospital({ latitude: 12.9716, longitude: 77.5946 })) || undefined;
        }

        setFlaggedCase({
          id: `node-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: CaseStatus.EMERGENCY,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.9,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: 0.9,
          location: { latitude: 0, longitude: 0, geoHash: 'cctv', placeName: 'Sensor Node Alpha' },
          deviceId: sensorSource,
          recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['AI-Vision-Broadcaster'],
          duplicateOf: null,
          detectionArea: result.detectionArea,
          hospitalRoute: hospital,
          sensorSource: sensorSource
        });
      }
    } catch (e) { console.error(e); } finally { setIsAnalyzing(false); lastDetectionTimeRef.current = Date.now(); }
  }, [isAnalyzing, flaggedCase, recorderId, sensorSource]);

  useEffect(() => {
    if (!isMediaReady || flaggedCase) return;
    const interval = setInterval(() => { if (Date.now() - lastDetectionTimeRef.current >= detectionIntervalMs) performDetection(); }, 2000);
    return () => clearInterval(interval);
  }, [isMediaReady, flaggedCase, performDetection]);

  const switchSensor = (source: SensorSource) => {
    setIsSyncing(true);
    setSensorSource(source);
    setFlaggedCase(null);
    setTimeout(() => setIsSyncing(false), 800);
  };

  const handleNotifyPolice = async () => {
    if (flaggedCase) {
      setIsAnalyzing(true);
      await ingestCase({ ...flaggedCase, status: CaseStatus.EMERGENCY });
      setFlaggedCase(null);
      setIsAnalyzing(false);
      alert("Emergency Signal Relayed to Police HQ.");
    }
  };

  return (
    <div className="relative h-full w-full bg-black flex flex-col">
      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover opacity-80"></video>
        <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

        {/* Sensor Controls */}
        <div className="absolute top-4 left-4 right-4 z-20 flex flex-col space-y-2">
          <div className="flex space-x-2 overflow-x-auto pb-2 hide-scrollbar">
            {Object.values(SensorSource).map(source => (
              <button
                key={source}
                onClick={() => switchSensor(source)}
                className={`px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all whitespace-nowrap ${
                  sensorSource === source 
                  ? 'bg-indigo-600 border-indigo-400 text-white shadow-lg' 
                  : 'bg-black/60 border-white/10 text-gray-400 backdrop-blur-md'
                }`}
              >
                {source.replace('_', ' ')}
              </button>
            ))}
          </div>

          <div className="bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10 w-fit flex items-center space-x-2">
            <div className={`w-2 h-2 rounded-full ${isAnalyzing || isSyncing ? 'bg-yellow-500 animate-pulse' : 'bg-green-500'}`}></div>
            <span className="text-[9px] font-black text-white uppercase tracking-widest">
              {isSyncing ? 'Syncing Node...' : isAnalyzing ? 'Processing AI-Stream' : 'Node Active'}
            </span>
          </div>
        </div>

        {isSyncing && (
          <div className="absolute inset-0 bg-indigo-900/20 backdrop-blur-sm flex items-center justify-center z-30">
             <div className="text-center">
               <LoadingSpinner />
               <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em] mt-4">Establishing Secure Wi-Fi Link</p>
             </div>
          </div>
        )}
      </div>

      {flaggedCase && (
        <div className="absolute bottom-4 left-4 right-4 z-40 animate-in slide-in-from-bottom-10 duration-500">
          <div className={`backdrop-blur-3xl border rounded-3xl p-6 shadow-[0_0_50px_rgba(0,0,0,0.5)] ${flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'bg-blue-950/90 border-blue-400/50' : 'bg-gray-950/95 border-white/10'}`}>
            <div className="flex justify-between items-start mb-4">
              <div>
                <p className={`text-[10px] font-black uppercase tracking-widest mb-1 ${flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'text-blue-400' : 'text-red-500'}`}>
                  {flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'EMERGENCY OVERRIDE' : 'SENSORY DETECTION'}
                </p>
                <h3 className="text-xl font-black text-white uppercase leading-none">
                  {flaggedCase.violationTypes[0].replace(/_/g, ' ')}
                </h3>
              </div>
              <div className="bg-white/5 px-3 py-1.5 rounded-xl border border-white/10 text-right">
                <p className="text-[8px] text-gray-500 font-bold uppercase mb-0.5">Source Node</p>
                <span className="text-[10px] font-mono font-black text-indigo-400">{sensorSource}</span>
              </div>
            </div>

            {flaggedCase.hospitalRoute && (
              <div className="mb-6 p-4 bg-blue-500/10 rounded-2xl border border-blue-400/30 animate-pulse">
                <p className="text-[9px] font-black text-blue-400 uppercase tracking-widest mb-1.5">Broadcast Message Sent to Public:</p>
                <p className="text-sm font-bold text-white italic">"There is an ambulance coming back to you. Just give me a way."</p>
                <div className="mt-3 flex items-center justify-between border-t border-blue-400/20 pt-3">
                  <div>
                    <p className="text-[8px] text-gray-400 uppercase font-black">Target Hospital</p>
                    <p className="text-xs font-black text-white">{flaggedCase.hospitalRoute.name}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] text-gray-400 uppercase font-black">Time to Save</p>
                    <p className="text-xs font-black text-green-400">{flaggedCase.hospitalRoute.eta}</p>
                  </div>
                </div>
              </div>
            )}

            <div className="flex space-x-3">
              <button onClick={() => setFlaggedCase(null)} className="flex-1 py-4 bg-gray-900 border border-white/5 text-gray-400 font-black text-[10px] uppercase tracking-widest rounded-2xl active:scale-95 transition-all">Dismiss</button>
              <button onClick={handleNotifyPolice} className={`flex-1 py-4 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl shadow-xl active:scale-95 transition-all ${flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'bg-blue-600 shadow-blue-600/30' : 'bg-indigo-600 shadow-indigo-600/30'}`}>
                {flaggedCase.violationTypes.includes(ViolationType.AMBULANCE) ? 'VERIFY & BROADCAST' : 'LOG DETECTION'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

