import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Case, CaseStatus, AuditLog, User, UserRole, ViolationType } from '../types';
import { VIOLATION_TYPE_COLORS } from '../constants';
import { fetchCaseById, updateCaseStatus, fetchAuditLogsForCase, assignCase, fetchAllPotentialAssignees, analyzeContentWithGemini, fetchUserById, confirmEmergencyCase } from '../services/api';
import LoadingSpinner from './LoadingSpinner';
import MapComponent from './MapComponent';
import Button from './Button';
import Modal from './Modal';
import Dropdown from './Dropdown';

interface CaseDetailProps {
  onNotify?: (message: string, type?: 'info' | 'success' | 'error') => void;
}

const CaseDetail: React.FC<CaseDetailProps> = ({ onNotify }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [caseDetail, setCaseDetail] = useState<Case | null>(null);
  const [assigneeUser, setAssigneeUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);

  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [assignees, setAssignees] = useState<User[]>([]);
  const [selectedAssigneeId, setSelectedAssigneeId] = useState<string>('');

  const fetchCaseAndLogs = useCallback(async () => {
    setLoading(true);
    if (!id) return;
    try {
      const fetchedCase = await fetchCaseById(id);
      if (fetchedCase) {
        setCaseDetail(fetchedCase);
        if (fetchedCase.assigneeId) {
          const user = await fetchUserById(fetchedCase.assigneeId);
          if (user) setAssigneeUser(user);
        }
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
      }
    } catch (error) {
      console.error('Failed to fetch case details:', error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchCaseAndLogs();
  }, [fetchCaseAndLogs]);

  const handleConfirmEmergency = async () => {
    if (!id) return;
    setLoading(true);
    try {
      await confirmEmergencyCase(id);
      onNotify?.('Emergency Path Authorized. Broadcast live.', 'success');
      fetchCaseAndLogs();
    } catch (err) {
      onNotify?.('Broadcast failed.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const openAssignModal = async () => {
    try {
      const potential = await fetchAllPotentialAssignees();
      setAssignees(potential);
      if (potential.length > 0) setSelectedAssigneeId(potential[0].id);
      setIsAssignModalOpen(true);
    } catch (error) {
      onNotify?.('Failed to load users.', 'error');
    }
  };

  const handleAssignCase = async () => {
    if (!id || !selectedAssigneeId) return;
    setLoading(true);
    try {
      const result = await assignCase(id, selectedAssigneeId);
      if (result.success) {
        if (result.case) setCaseDetail(result.case);
        const user = await fetchUserById(selectedAssigneeId);
        if (user) setAssigneeUser(user);
        const logs = await fetchAuditLogsForCase(id);
        setAuditLogs(logs);
        onNotify?.(result.message, 'success');
      }
    } catch (error) {
      onNotify?.('Failed to assign case.', 'error');
    } finally {
      setLoading(false);
      setIsAssignModalOpen(false);
    }
  };

  if (loading) return <LoadingSpinner />;
  if (!caseDetail) return <div className="p-6 text-center text-red-500 font-bold uppercase tracking-widest">Case not found.</div>;

  const isEmergency = caseDetail.violationTypes.includes(ViolationType.AMBULANCE);

  return (
    <div className="flex-1 p-6 bg-gray-900 text-white pb-24">
      <div className="flex justify-between items-center mb-6">
        <div>
           <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Incident Registry</p>
           <h2 className="text-2xl font-black uppercase tracking-tight">ID: {caseDetail.id}</h2>
        </div>
        <div className="flex space-x-2">
           {isEmergency && caseDetail.status !== CaseStatus.EMERGENCY_CONFIRMED && (
             <Button 
               variant="primary" 
               className="!bg-blue-600 hover:!bg-blue-700 !rounded-xl px-6 animate-pulse" 
               onClick={handleConfirmEmergency}
             >
               Confirm & Clear Path
             </Button>
           )}
           <Button variant="secondary" onClick={openAssignModal} className="!rounded-xl">Assign Dispatch</Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className={`rounded-3xl p-8 border ${isEmergency ? 'bg-blue-950/40 border-blue-500/50' : 'bg-gray-800 border-gray-700'}`}>
            <h3 className="text-lg font-black mb-6 uppercase tracking-widest text-indigo-400">Tactical Briefing</h3>
            <div className="grid grid-cols-2 gap-8 text-sm">
              <div>
                <p className="text-gray-500 font-bold uppercase text-[10px] tracking-widest mb-2">Live Status</p>
                <span className={`inline-block px-4 py-1.5 rounded-full text-[11px] font-black uppercase tracking-widest ${isEmergency ? 'bg-blue-600 text-white' : 'bg-indigo-600 text-white'}`}>
                  {caseDetail.status.replace(/_/g, ' ')}
                </span>
              </div>
              {caseDetail.hospitalRoute && (
                <div>
                  <p className="text-gray-500 font-bold uppercase text-[10px] tracking-widest mb-2">Destination Hospital</p>
                  <p className="font-black text-white text-base">{caseDetail.hospitalRoute.name}</p>
                  <p className="text-[10px] text-blue-400 font-bold">{caseDetail.hospitalRoute.eta} ETA / {caseDetail.hospitalRoute.distance}</p>
                </div>
              )}
            </div>

            <div className="mt-8">
               <p className="text-gray-500 font-bold uppercase text-[10px] tracking-widest mb-4">Detected Entities</p>
               <div className="flex flex-wrap gap-3">
                 {caseDetail.violationTypes.map(type => (
                   <span key={type} className={`px-5 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-white/10 ${VIOLATION_TYPE_COLORS[type]} text-white shadow-xl`}>
                     {type.replace(/_/g, ' ')}
                   </span>
                 ))}
               </div>
            </div>

            {isEmergency && (
              <div className="mt-8 p-6 bg-white/5 rounded-3xl border border-white/10 italic text-gray-300 text-sm leading-relaxed">
                "System broadcast enabled. All users on path notified to yield. Emergency priority level: Omega."
              </div>
            )}
          </div>
        </div>

        <div className="lg:col-span-1 space-y-6">
          <div className="bg-gray-800 rounded-3xl p-5 border border-gray-700 shadow-xl">
            <h3 className="text-xs font-black text-indigo-400 mb-4 uppercase tracking-widest">Visual Telemetry</h3>
            <div className="aspect-video bg-black rounded-2xl overflow-hidden border border-white/5">
              <img src={caseDetail.mediaUrls[0]} className="w-full h-full object-cover" alt="Evidence" />
            </div>
          </div>
          <div className="bg-gray-800 rounded-3xl p-5 border border-gray-700 shadow-xl">
            <h3 className="text-xs font-black text-indigo-400 mb-4 uppercase tracking-widest">Global Coordinates</h3>
            <div className="rounded-2xl overflow-hidden grayscale contrast-125 opacity-80">
              <MapComponent location={caseDetail.location} placeName={caseDetail.location.placeName} />
            </div>
          </div>
        </div>
      </div>

      <Modal
        isOpen={isAssignModalOpen}
        onClose={() => setIsAssignModalOpen(false)}
        title="Personnel Deployment"
        size="xs"
        footer={<Button className="w-full !rounded-xl py-3" onClick={handleAssignCase} disabled={!selectedAssigneeId}>Authorize Mission</Button>}
      >
        <p className="mb-4 text-[10px] text-gray-500 font-bold uppercase tracking-[0.2em]">Select Unit or Officer</p>
        <Dropdown
