import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, Blob, FunctionDeclaration } from '@google/genai';
import { useNavigate } from 'react-router-dom';

interface JarvisAssistantProps {
  userRole: string;
  userName: string;
  onLogout: () => void;
}

const JarvisAssistant: React.FC<JarvisAssistantProps> = ({ userRole, userName, onLogout }) => {
  const navigate = useNavigate();
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [inputLevel, setInputLevel] = useState(0);

  const sessionRef = useRef<any>(null);
  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);
  const analyzerRef = useRef<AnalyserNode | null>(null);

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
    return buffer;
  };

  const createBlob = (data: Float32Array): Blob => ({
    data: encode(new Uint8Array(new Int16Array(data.map(v => v * 32768)).buffer)),
    mimeType: 'audio/pcm;rate=16000',
  });

  const stopAllAudio = () => {
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
  };

  const handleFunctionCall = useCallback(async (fc: any) => {
    let result = "Action Logged.";
    if (fc.name === 'dispatchEmergency') {
      result = `Alert sent to all officers: ${fc.args.type} incoming. Hospital: ${fc.args.hospital}.`;
    } else if (fc.name === 'navigateTo') {
      navigate(fc.args.path);
      result = `Switched view to ${fc.args.path}`;
    }
    if (sessionRef.current) {
      sessionRef.current.sendToolResponse({
        functionResponses: { id: fc.id, name: fc.name, response: { result } }
      });
    }
  }, [navigate]);

  const toggleAssistant = async () => {
    if (isActive) {
      if (sessionRef.current) sessionRef.current.close();
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      setIsActive(false);
      stopAllAudio();
      return;
    }

    const apiKey = process.env.API_KEY;
    if (!apiKey) return;

    setIsConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      analyzerRef.current = audioContextInRef.current.createAnalyser();
      const sourceMic = audioContextInRef.current.createMediaStreamSource(stream);
      sourceMic.connect(analyzerRef.current);
      analyzerRef.current.fftSize = 256;
      const dataArray = new Uint8Array(analyzerRef.current.frequencyBinCount);

      const updateMeter = () => {
        if (!analyzerRef.current || !isActive) return;
        analyzerRef.current.getByteFrequencyData(dataArray);
        setInputLevel(dataArray.reduce((a, b) => a + b, 0) / dataArray.length);
        requestAnimationFrame(updateMeter);
      };

      const dispatchTool: FunctionDeclaration = {
        name: 'dispatchEmergency',
        parameters: {
          type: Type.OBJECT,
          description: 'Notify police about an ambulance or emergency.',
          properties: {
            type: { type: Type.STRING },
            hospital: { type: Type.STRING },
            eta: { type: Type.STRING }
          },
          required: ['type', 'hospital']
        }
      };

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);
            updateMeter();
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
            };
            sourceMic.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.toolCall) msg.toolCall.functionCalls.forEach(handleFunctionCall);
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              setIsSpeaking(true);
              const ctx = audioContextOutRef.current!;
              if (ctx.state === 'suspended') await ctx.resume();
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onclose: () => setIsActive(false),
          onerror: (e: any) => {
            setIsConnecting(false);
            const errorMessage = e?.message || String(e);
            if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
              if (window.aistudio?.openSelectKey) {
                window.aistudio.openSelectKey();
              }
            }
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [dispatchTool, { name: 'navigateTo', parameters: { type: Type.OBJECT, properties: { path: { type: Type.STRING } } } }] }],
          systemInstruction: `Persona: JARVIS. You are a bridge between Public Users and Police Dispatch.
          User Role: ${userRole}. Name: ${userName}.
          Primary task: Handle emergency ambulance routing and police dispatch notifications.
          If an ambulance is detected, find a hospital and notify the police. Be extremely brief.`
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setIsConnecting(false);
      const errorMessage = err?.message || String(err);
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
        if (window.aistudio?.openSelectKey) {
          window.aistudio.openSelectKey();
        }
      }
    }
  };

  return (
    <div className="fixed bottom-[74px] right-4 z-[100] flex flex-col items-center">
      <button
        onClick={toggleAssistant}
        className={`relative w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 shadow-xl ${
          isActive ? 'bg-indigo-600 border border-white/40 ring-2 ring-indigo-500/20' : 'bg-gray-800 border border-white/5'
        }`}
      >
        {isActive && <div className="absolute inset-0 rounded-full bg-indigo-500/30 animate-ping" />}
        <div className="relative z-10 flex items-center justify-center">
          {isConnecting ? (
            <div className="w-3 h-3 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin" />
          ) : (
            <div className={`w-1.5 h-1.5 rounded-full bg-white transition-all ${isActive ? 'shadow-[0_0_8px_white] scale-125' : 'bg-indigo-400/80 scale-100'}`} />
          )}
        </div>
      </button>
    </div>
  );
};

export default JarvisAssistant;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat } from "@google/genai";
import Button from '../components/Button';
import LoadingSpinner from '../components/LoadingSpinner';

interface Message {
  text: string;
  sender: 'user' | 'gemini';
}

const ChatbotPage: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isJarvisEnabled, setIsJarvisEnabled] = useState(true);

  const chatRef = useRef<Chat | null>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Load and sync Jarvis state
  useEffect(() => {
    const enabled = localStorage.getItem('jarvis_system_enabled') !== 'false';
    setIsJarvisEnabled(enabled);
  }, []);

  const toggleJarvisSystem = () => {
    const newState = !isJarvisEnabled;
    setIsJarvisEnabled(newState);
    localStorage.setItem('jarvis_system_enabled', String(newState));
    window.dispatchEvent(new Event('storage'));
  };

  const initializeChat = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      chatRef.current = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: 'You are a concise traffic enforcement AI assistant. Answer support questions briefly.',
        },
      });
      if (messages.length === 0) {
        setMessages([{ text: "System ready. How can I help?", sender: 'gemini' }]);
      }
    } catch (error: any) {
      console.error('Gemini init failed', error);
      const errorMessage = error?.message || String(error);
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
        if (window.aistudio?.openSelectKey) {
          window.aistudio.openSelectKey();
        }
      }
    }
  };

  useEffect(() => {
    initializeChat();
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const sendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { text: input, sender: 'user' as const };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      if (!chatRef.current) await initializeChat();
      if (!chatRef.current) throw new Error("No session");

      const responseStream = await chatRef.current.sendMessageStream({ message: userMessage.text });
      let geminiResponseText = '';
      setMessages(prev => [...prev, { text: '', sender: 'gemini' as const }]);

      for await (const chunk of responseStream) {
        const currentChunkText = chunk.text;
        if (currentChunkText) {
          geminiResponseText += currentChunkText;
          setMessages(prev => {
            const newMessages = [...prev];
            if (newMessages.length > 0 && newMessages[newMessages.length - 1].sender === 'gemini') {
              newMessages[newMessages.length - 1].text = geminiResponseText;
            }
            return newMessages;
          });
        }
      }
    } catch (error: any) {
      console.error('Chat error:', error);
      const errorMessage = error?.message || String(error);
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
        if (window.aistudio?.openSelectKey) {
          window.aistudio.openSelectKey();
        }
      }
      setMessages(prev => [...prev, { text: `Error: Connection lost. Please verify your API settings.`, sender: 'gemini' as const }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-950 text-white">
      <div className="p-4 bg-gray-900 border-b border-indigo-500/20">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-sm font-black text-indigo-400 uppercase tracking-widest">Voice Assistance</h3>
            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest mt-0.5">Global System Control</p>
          </div>
          <button 
            onClick={toggleJarvisSystem}
            className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-xl active:scale-95 ${
              isJarvisEnabled 
              ? 'bg-indigo-600 text-white shadow-indigo-600/30' 
              : 'bg-gray-800 text-gray-500 border border-white/5'
            }`}
          >
            {isJarvisEnabled ? 'SYSTEM: ACTIVE' : 'SYSTEM: STANDBY'}
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 hide-scrollbar" ref={chatContainerRef}>
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-snug ${
                msg.sender === 'user' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-gray-900 text-white border border-white/5'
              }`}
            >
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="p-3 bg-gray-900 rounded-2xl border border-white/5">
              <LoadingSpinner />
            </div>
          </div>
        )}
      </div>

      <form onSubmit={sendMessage} className="flex p-4 bg-gray-950 border-t border-white/5">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Query AI Copilot..."
          className="flex-1 p-4 rounded-xl bg-gray-900 border border-white/10 text-sm text-white focus:outline-none focus:ring-1 focus:ring-indigo-500 transition-all"
          disabled={isLoading}
        />
        <button
          type="submit"
