import { GoogleGenAI, Type } from '@google/genai';
import { supabase } from '../lib/supabase';
import { MOCK_CASES, MOCK_USERS } from '../constants';
import { 
  Case, 
  CaseStatus, 
  FilterOptions, 
  PaginationInfo, 
  User, 
