  UserRole, 
  ViolationType, 
  ManualReport, 
  OfficerDuty, 
  DutyStatus, 
  TrafficInfo,
  Hospital
} from '../types';

export interface PaginatedCases {
  cases: Case[];
  pagination: PaginationInfo;
}

export const mapSupabaseUser = (sbUser: any): User => {
  return {
    id: sbUser.id,
    role: (sbUser.user_metadata?.role as UserRole) || UserRole.PUBLIC,
    name: sbUser.user_metadata?.name || 'Authorized User',
    unit: sbUser.user_metadata?.unit || 'Field Unit',
    email: sbUser.email || '',
    phone: sbUser.user_metadata?.phone || '',
    dob: sbUser.user_metadata?.dob,
    aadhaar: sbUser.user_metadata?.aadhaar,
    deviceIds: sbUser.user_metadata?.deviceIds || [],
  };
};

const getApiKey = () => process.env.API_KEY || '';
const getAI = () => new GoogleGenAI({ apiKey: getApiKey() });
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

// Helper to handle 404 errors as per guidelines
const handleApiError = async (error: any) => {
  console.error("API Error details:", error);
  const errorMessage = error?.message || String(error);
  if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
    if (window.aistudio?.openSelectKey) {
      console.warn("Model not found or 404 error. Prompting for new API key...");
      await window.aistudio.openSelectKey();
    }
  }
  throw error;
};

let SESSION_USERS = [...MOCK_USERS];

export const signInUser = async (identifier: string, password: string): Promise<User> => {
  const email = identifier.includes('@') ? identifier : `${identifier}@mtraffic.local`;
  const { data, error } = await supabase.auth.signInWithPassword({ email, password: password === '123' ? '123123' : password });
  if (error) throw error;
  return mapSupabaseUser(data.user);
};

export const signUpUser = async (userData: any): Promise<User> => {
  const { data, error } = await supabase.auth.signUp({
    email: userData.email,
    password: userData.password,
    options: {
      data: {
        name: userData.name,
        dob: userData.dob,
        aadhaar: userData.aadhaar,
        role: userData.role,
        unit: userData.role === UserRole.PUBLIC ? 'Public' : 'Police Unit',
        deviceIds: [],
      }
    }
  });
  if (error) throw error;
  if (!data.user) throw new Error("Sign up failed");
  return mapSupabaseUser(data.user);
};

