export const fetchTrafficGrounding = async (location: LatLng): Promise<TrafficInfo> => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", // Maps grounding is only supported in Gemini 2.5 series models
      contents: `Detailed traffic report for Lat: ${location.latitude}, Lon: ${location.longitude}.`,
      config: { 
        tools: [{ googleMaps: {} }], 
        toolConfig: { retrievalConfig: { latLng: { latitude: location.latitude, longitude: location.longitude } } } 
      },
    });
    const summary = response.text || "Status green.";
    const sources: { title: string; uri: string }[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) chunks.forEach((c: any) => { if (c.maps) sources.push({ title: c.maps.title, uri: c.maps.uri }); });
    return { summary, specificArea: "Main Junction", sources };
  } catch (err) {
    return handleApiError(err);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat } from "@google/genai";
import Button from '../components/Button';
import LoadingSpinner from '../components/LoadingSpinner';

interface Message {
  text: string;
  sender: 'user' | 'gemini';
}

const ChatbotPage: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isJarvisEnabled, setIsJarvisEnabled] = useState(true);

  const chatRef = useRef<Chat | null>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Load and sync Jarvis state
  useEffect(() => {
    const enabled = localStorage.getItem('jarvis_system_enabled') !== 'false';
    setIsJarvisEnabled(enabled);
  }, []);

  const toggleJarvisSystem = () => {
    const newState = !isJarvisEnabled;
    setIsJarvisEnabled(newState);
    localStorage.setItem('jarvis_system_enabled', String(newState));
    window.dispatchEvent(new Event('storage'));
  };

  const initializeChat = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      chatRef.current = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: 'You are a concise traffic enforcement AI assistant. Answer support questions briefly.',
        },
      });
      if (messages.length === 0) {
        setMessages([{ text: "System ready. How can I help?", sender: 'gemini' }]);
      }
    } catch (error: any) {
      console.error('Gemini init failed', error);
      const errorMessage = error?.message || String(error);
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
        if (window.aistudio?.openSelectKey) {
          window.aistudio.openSelectKey();
        }
      }
    }
  };

  useEffect(() => {
    initializeChat();
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const sendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { text: input, sender: 'user' as const };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      if (!chatRef.current) await initializeChat();
      if (!chatRef.current) throw new Error("No session");

      const responseStream = await chatRef.current.sendMessageStream({ message: userMessage.text });
      let geminiResponseText = '';
      setMessages(prev => [...prev, { text: '', sender: 'gemini' as const }]);

      for await (const chunk of responseStream) {
        const currentChunkText = chunk.text;
        if (currentChunkText) {
          geminiResponseText += currentChunkText;
          setMessages(prev => {
            const newMessages = [...prev];
            if (newMessages.length > 0 && newMessages[newMessages.length - 1].sender === 'gemini') {
              newMessages[newMessages.length - 1].text = geminiResponseText;
            }
            return newMessages;
          });
        }
      }
    } catch (error: any) {
      console.error('Chat error:', error);
      const errorMessage = error?.message || String(error);
      if (errorMessage.includes("Requested entity was not found") || errorMessage.includes("404")) {
        if (window.aistudio?.openSelectKey) {
          window.aistudio.openSelectKey();
        }
      }
      setMessages(prev => [...prev, { text: `Error: Connection lost. Please verify your API settings.`, sender: 'gemini' as const }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-gray-950 text-white">
      <div className="p-4 bg-gray-900 border-b border-indigo-500/20">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-sm font-black text-indigo-400 uppercase tracking-widest">Voice Assistance</h3>
            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest mt-0.5">Global System Control</p>
          </div>
          <button 
            onClick={toggleJarvisSystem}
            className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-xl active:scale-95 ${
              isJarvisEnabled 
              ? 'bg-indigo-600 text-white shadow-indigo-600/30' 
              : 'bg-gray-800 text-gray-500 border border-white/5'
            }`}
          >
            {isJarvisEnabled ? 'SYSTEM: ACTIVE' : 'SYSTEM: STANDBY'}
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 hide-scrollbar" ref={chatContainerRef}>
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-snug ${
                msg.sender === 'user' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-gray-900 text-white border border-white/5'
              }`}
            >
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="p-3 bg-gray-900 rounded-2xl border border-white/5">
              <LoadingSpinner />
            </div>
          </div>
        )}
      </div>

      <form onSubmit={sendMessage} className="flex p-4 bg-gray-950 border-t border-white/5">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Query AI Copilot..."
          className="flex-1 p-4 rounded-xl bg-gray-900 border border-white/10 text-sm text-white focus:outline-none focus:ring-1 focus:ring-indigo-500 transition-all"
          disabled={isLoading}
        />
        <button
          type="submit"
          className="ml-2 bg-white text-black p-4 rounded-xl disabled:opacity-30 active:scale-95 transition-all shadow-lg"
          disabled={!input.trim() || isLoading}
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M14 5l7 7m0 0l-7 7m7-7H3" />
          </svg>
        </button>
      </form>
    </div>
  );
};

export default ChatbotPage;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Case, CaseStatus, ViolationType, Hospital, SensorSource } from '../types';
import { ingestCase, detectViolationWithGemini, findNearestHospital } from '../services/api';
import LoadingSpinner from '../components/LoadingSpinner';

interface CameraViewProps {
  recorderId: string;
}

const CameraView: React.FC<CameraViewProps> = ({ recorderId }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const [isMediaReady, setIsMediaReady] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [sensorSource, setSensorSource] = useState<SensorSource>(SensorSource.LOCAL);

  const [detectionOverlay, setDetectionOverlay] = useState<{ x: number; y: number; width: number; height: number; type: ViolationType; } | null>(null);
  const [lastFiledCaseId, setLastFiledCaseId] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const lastDetectionTimeRef = useRef<number>(0);
  const detectionIntervalMs = 4000; // Slightly faster for real-time feel

  const startDrawingLoop = useCallback(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (video && canvas) {
      const context = canvas.getContext('2d');
      if (!context) return;

      const drawFrame = () => {
        if (!video.videoWidth || !video.videoHeight) {
          animationFrameId.current = requestAnimationFrame(drawFrame);
          return;
        }
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;

        if (sensorSource !== SensorSource.LOCAL) {
          context.filter = 'contrast(1.1) brightness(1.1) sepia(0.1)';
        } else {
          context.filter = 'none';
        }

        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        if (detectionOverlay) {
          const { x, y, width, height, type } = detectionOverlay;
          const isAmbulance = type === ViolationType.AMBULANCE;
          context.strokeStyle = isAmbulance ? '#3b82f6' : '#ef4444';
          context.setLineDash(isAmbulance ? [10, 5] : []);
          context.lineWidth = 4;
          context.strokeRect((x / 100) * canvas.width, (y / 100) * canvas.height, (width / 100) * canvas.width, (height / 100) * canvas.height);

          context.fillStyle = isAmbulance ? '#3b82f6' : '#ef4444';
          context.font = 'bold 16px Arial';
          context.fillText(isAmbulance ? 'EMERGENCY DETECTED' : 'VIOLATION DETECTED', (x / 100) * canvas.width, (y / 100) * canvas.height - 10);
        }

        animationFrameId.current = requestAnimationFrame(drawFrame);
      };
      animationFrameId.current = requestAnimationFrame(drawFrame);
    }
  }, [detectionOverlay, sensorSource]);

  const setupCamera = useCallback(async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      mediaStreamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().then(() => { setIsCameraActive(true); setIsMediaReady(true); startDrawingLoop(); });
        };
      }
    } catch (err: any) { setCameraError("Visual sensor denied."); }
  }, [startDrawingLoop]);

  useEffect(() => { setupCamera(); return () => { if (mediaStreamRef.current) mediaStreamRef.current.getTracks().forEach(t => t.stop()); }; }, [setupCamera]);

  const performDetection = useCallback(async () => {
    const canvas = canvasRef.current;
    if (!canvas || isAnalyzing) return;

    setIsAnalyzing(true);
    try {
      const imageData = canvas.toDataURL('image/jpeg', 0.6);
      const result = await detectViolationWithGemini(imageData);

      if (result && result.violationDetected) {
        let hospital: Hospital | undefined;
        const isAmbulance = result.violationType === ViolationType.AMBULANCE;

        if (isAmbulance) {
          // Automatic hospital routing for ambulances
          hospital = (await findNearestHospital({ latitude: 12.9716, longitude: 77.5946 })) || undefined;
        }

        const newCase: Case = {
          id: `auto-${Date.now()}`,
          createdAt: new Date().toISOString(),
          status: isAmbulance ? CaseStatus.EMERGENCY : CaseStatus.PENDING_REVIEW,
          violationTypes: [result.violationType],
          confidence: result.confidence || 0.9,
          plateText: result.plateText || 'UNKNOWN',
          plateConfidence: 0.9,
          location: { latitude: 12.9716, longitude: 77.5946, geoHash: 'cctv', placeName: 'Autonomous Node' },
          deviceId: sensorSource,
          recorderId,
          mediaUrls: [imageData],
          rulesMatched: ['Autonomous-AI-Filing'],
          duplicateOf: null,
          hospitalRoute: hospital,
          sensorSource: sensorSource
        };

        // AUTOMATIC FILING
        await ingestCase(newCase);

        // Visual Feedback
        setDetectionOverlay({ 
          ...result.detectionArea, 
          type: result.violationType 
        });
        setLastFiledCaseId(newCase.id);

        // Clear overlay after 3 seconds
        setTimeout(() => {
          setDetectionOverlay(null);
          setLastFiledCaseId(null);
        }, 3000);
      }
    } catch (e) { 
      console.error("Auto-detection failed:", e); 
    } finally { 
      setIsAnalyzing(false); 
      lastDetectionTimeRef.current = Date.now(); 
    }
  }, [isAnalyzing, recorderId, sensorSource]);

  useEffect(() => {
    if (!isMediaReady) return;
    const interval = setInterval(() => { 
      if (Date.now() - lastDetectionTimeRef.current >= detectionIntervalMs) performDetection(); 
    }, 1000);
    return () => clearInterval(interval);
  }, [isMediaReady, performDetection]);

  const switchSensor = (source: SensorSource) => {
    setIsSyncing(true);
    setSensorSource(source);
    setDetectionOverlay(null);
    setTimeout(() => setIsSyncing(false), 800);
  };

  return (
    <div className="relative h-full w-full bg-black flex flex-col">
      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover opacity-60"></video>
        <canvas ref={canvasRef} className="absolute inset-0 w-full h-full object-cover"></canvas>

        {/* Top Controls */}
        <div className="absolute top-4 left-4 right-4 z-20 flex flex-col space-y-3">
          <div className="flex space-x-2 overflow-x-auto pb-2 hide-scrollbar">
            {Object.values(SensorSource).map(source => (
              <button
                key={source}
                onClick={() => switchSensor(source)}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all whitespace-nowrap ${
                  sensorSource === source 
                  ? 'bg-indigo-600 border-indigo-400 text-white shadow-lg' 
                  : 'bg-black/60 border-white/10 text-gray-400 backdrop-blur-md'
                }`}
              >
                {source.replace('_', ' ')}
              </button>
            ))}
          </div>

          <div className="flex items-center space-x-2">
            <div className="bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/10 w-fit flex items-center space-x-2">
              <div className={`w-2 h-2 rounded-full ${isAnalyzing || isSyncing ? 'bg-indigo-500 animate-pulse' : 'bg-green-500'}`}></div>
              <span className="text-[9px] font-black text-white uppercase tracking-widest">
                {isSyncing ? 'Linking Node' : isAnalyzing ? 'AI ANALYZING' : 'SCANNING ACTIVE'}
              </span>
            </div>
            <div className="bg-indigo-600/20 backdrop-blur-md px-3 py-1.5 rounded-full border border-indigo-500/30 w-fit flex items-center space-x-2">
               <span className="text-[9px] font-black text-indigo-400 uppercase tracking-widest">AUTO-FILING: ON</span>
            </div>
          </div>
        </div>

        {/* Filing Notification */}
        {lastFiledCaseId && (
          <div className="absolute top-1/4 left-1/2 -translate-x-1/2 z-50 animate-bounce">
            <div className="bg-green-600 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-green-400">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
               <span className="text-xs font-black uppercase tracking-widest">CASE FILED AUTOMATICALLY</span>
            </div>
          </div>
        )}

        {isSyncing && (
          <div className="absolute inset-0 bg-indigo-900/30 backdrop-blur-md flex items-center justify-center z-30 transition-opacity">
             <div className="text-center">
               <LoadingSpinner />
               <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.4em] mt-4">Establishing Wi-Fi Data Stream</p>
             </div>
          </div>
        )}
      </div>

      {/* Bottom Status Panel */}
      <div className="bg-gray-950 border-t border-white/5 p-4 pb-8">
        <div className="flex items-center justify-between mb-2">
           <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Sensor Telemetry</h3>
           <div className="flex items-center space-x-2">
             <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span>
             <span className="text-[9px] font-bold text-green-500 uppercase">Secure Link</span>
           </div>
        </div>
        <div className="grid grid-cols-2 gap-4">
           <div className="bg-white/5 p-3 rounded-xl border border-white/5">
              <p className="text-[8px] text-gray-600 font-bold uppercase mb-1">Current Node</p>
              <p className="text-xs font-black text-white truncate">{sensorSource.replace(/_/g, ' ')}</p>
           </div>
           <div className="bg-white/5 p-3 rounded-xl border border-white/5">
              <p className="text-[8px] text-gray-600 font-bold uppercase mb-1">AI Version</p>
              <p className="text-xs font-black text-indigo-400">Gemini-3.0-Edge</p>
           </div>
        </div>
      </div>
    </div>
  );
};

export default CameraView;
